using System;
using System.Collections.Generic;
using System.Diagnostics.CodeAnalysis;
using System.Linq;
using System.Linq.Expressions;
using ConstExpr.Core.Enumerators;
using ConstExpr.SourceGenerator.Extensions;
using ConstExpr.SourceGenerator.Models;
using ConstExpr.SourceGenerator.Optimizers;
using ConstExpr.SourceGenerator.Optimizers.FunctionOptimizers.LinqOptimizers;
using ConstExpr.SourceGenerator.Optimizers.FunctionOptimizers.MathOptimizers;
using ConstExpr.SourceGenerator.Optimizers.FunctionOptimizers.StringOptimizers;
using ConstExpr.SourceGenerator.Visitors;
using Microsoft.CodeAnalysis;
using Microsoft.CodeAnalysis.CSharp;
using Microsoft.CodeAnalysis.CSharp.Syntax;
using Microsoft.CodeAnalysis.Operations;
using SourceGen.Utilities.Extensions;
using ExpressionVisitor = ConstExpr.SourceGenerator.Visitors.ExpressionVisitor;

namespace ConstExpr.SourceGenerator.Rewriters;

/// <summary>
/// Invocation and member access visitor methods for the ConstExprPartialRewriter.
/// Handles method invocations, element access, and member access expressions.
/// </summary>
public partial class ConstExprPartialRewriter
{
	public override SyntaxNode? VisitInvocationExpression(InvocationExpressionSyntax node)
	{
		// Handle nameof(...) directly
		if (TryHandleNameof(node, out var nameofResult))
		{
			return nameofResult;
		}

		if (!semanticModel.TryGetSymbol(node, out IMethodSymbol? targetMethod))
		{
			return VisitInvocationExpressionFallback(node);
		}

		var arguments = node.ArgumentList.Arguments
			.Select(arg => Visit(arg.Expression))
			.ToList();

		var constantArguments = ExtractConstantArguments(arguments, node.ArgumentList.Arguments);

		// Try to execute with all constant arguments
		if (constantArguments.Count == targetMethod.Parameters.Length)
		{
			var result = TryExecuteWithConstantArguments(node, targetMethod, constantArguments);

			if (result is not null)
			{
				return result;
			}
		}

		// Try string optimizers
		if (targetMethod.ContainingType.SpecialType == SpecialType.System_String
		    && node.Expression is MemberAccessExpressionSyntax memberAccess)
		{
			var tempNode = node.WithExpression(Visit(node.Expression) as ExpressionSyntax ?? node.Expression);
			var optimized = TryOptimizeStringMethod(semanticModel, targetMethod, tempNode, memberAccess, arguments, node.ArgumentList.Arguments.Select(s => s.Expression));

			if (optimized is not null)
			{
				return Visit(optimized);
			}
		}
		// Try math optimizers
		else if (attribute.FloatingPointMode == FloatingPointEvaluationMode.FastMath)
		{
			var tempNode = node.WithExpression(Visit(node.Expression) as ExpressionSyntax ?? node.Expression);
			var optimized = TryOptimizeMathMethod(semanticModel, targetMethod, tempNode, arguments, node.ArgumentList.Arguments.Select(s => s.Expression));

			if (optimized is not null)
			{
				return Visit(optimized);
			}
		}

		// Try LINQ optimizers (for inner calls, or when unrolling was skipped).
		// The optimized result is annotated with symbol info so it can be unrolled
		// when it re-enters the rewriter through Visit.
		if (attribute.LinqOptimisationMode != LinqOptimisationMode.None
		    && TryOptimizeLinqMethod(semanticModel, targetMethod, node, arguments, node.ArgumentList.Arguments.Select(s => s.Expression)) is { } optimizedLinq)
		{
			if (attribute.LinqOptimisationMode == LinqOptimisationMode.Unroll)
			{
				return LinqUnroller.TryUnrollLinqChain(optimizedLinq, Visit, semanticModel, additionalMethods);
			}

			return optimizedLinq;
		}

		node = node.WithExpression(Visit(node.Expression) as ExpressionSyntax ?? node.Expression);

		// Handle char overload conversion
		if (ConvertToCharOverloadIfNeeded(targetMethod, arguments, out var newArguments, out var charMethod))
		{
			targetMethod = charMethod;
			arguments = newArguments;
		}

		// Handle static methods and local functions
		return targetMethod.IsStatic || targetMethod.MethodKind == MethodKind.LocalFunction
			? HandleStaticMethodInvocation(node, targetMethod, arguments)
			: HandleInstanceMethodInvocation(node, targetMethod, arguments);

	}

	/// <summary>
	/// Tries to handle nameof(...) expressions.
	/// </summary>
	private bool TryHandleNameof(InvocationExpressionSyntax node, out SyntaxNode? result)
	{
		result = null;

		if (node is not { Expression: IdentifierNameSyntax { Identifier.Text: "nameof" }, ArgumentList.Arguments.Count: 1 })
		{
			return false;
		}

		var arg = node.ArgumentList.Arguments[0].Expression;
		string? name = null;

		if (semanticModel.TryGetSymbol(arg, out ISymbol? sym))
		{
			name = sym.Name;
		}
		else
		{
			name = arg switch
			{
				IdentifierNameSyntax id => id.Identifier.Text,
				MemberAccessExpressionSyntax { Name: IdentifierNameSyntax last } => last.Identifier.Text,
				QualifiedNameSyntax qn => qn.Right.Identifier.Text,
				GenericNameSyntax gen => gen.Identifier.Text,
				_ => name
			};
		}

		if (name is not null)
		{
			result = LiteralExpression(SyntaxKind.StringLiteralExpression, Literal(name));
			return true;
		}

		result = base.VisitInvocationExpression(node);
		return true;
	}

	/// <summary>
	/// Extracts constant arguments from visited arguments.
	/// </summary>
	private List<object> ExtractConstantArguments(List<SyntaxNode> arguments, SeparatedSyntaxList<ArgumentSyntax> originalArguments)
	{
		var constantArguments = new List<object>(arguments.Count);

		try
		{
			for (var i = 0; i < arguments.Count; i++)
			{
				if (TryGetLiteralValue(arguments[i], out var value) || TryGetLiteralValue(originalArguments[i], out value))
				{
					constantArguments.Add(value);
				}
			}
		}
		catch (Exception e)
		{
			exceptionHandler(arguments[0], e);
		}

		return constantArguments;
	}

	/// <summary>
	/// Tries to execute a method with constant arguments.
	/// </summary>
	private SyntaxNode? TryExecuteWithConstantArguments(InvocationExpressionSyntax node, IMethodSymbol targetMethod, List<object> constantArguments)
	{
		try
		{
			if (node.Expression is MemberAccessExpressionSyntax { Expression: var instanceName }
			    && !targetMethod.ContainingType.EqualsType(semanticModel.Compilation.GetTypeByMetadataName("System.Random")))
			{
				return TryExecuteInstanceMethod(targetMethod, instanceName, constantArguments);
			}

			return TryExecuteViaOperationVisitor(targetMethod, constantArguments);
		}
		catch (Exception)
		{
			return null;
		}
	}

	/// <summary>
	/// Tries to execute an instance method.
	/// </summary>
	private SyntaxNode? TryExecuteInstanceMethod(IMethodSymbol targetMethod, ExpressionSyntax instanceName, List<object> constantArguments)
	{
		var hasLiteral = TryGetLiteralValue(instanceName, out var instance)
		                 || TryGetLiteralValue(Visit(instanceName), out instance);

		if (hasLiteral && loader.TryGetType(targetMethod.ContainingType, out var type))
		{
			try
			{
				instance = Convert.ChangeType(instance, type);
			}
			catch (InvalidCastException) { }
		}

		if ((targetMethod.IsStatic || hasLiteral
			    && (instanceName is not IdentifierNameSyntax identifier || CanBePruned(identifier.Identifier.Text)))
		    && loader.TryExecuteMethod(targetMethod, instance, new VariableItemDictionary(variables), constantArguments, out var value)
		    && TryGetLiteral(value, out var literal))
		{
			if (targetMethod.ReturnsVoid)
			{
				return null;
			}

			return literal;
		}

		return null;
	}

	/// <summary>
	/// Tries to execute a method via the operation visitor.
	/// </summary>
	private SyntaxNode? TryExecuteViaOperationVisitor(IMethodSymbol targetMethod, List<object> constantArguments)
	{
		if (!TryGetOperation<IOperation>(semanticModel, targetMethod, out var methodOperation))
		{
			return null;
		}

		var parameters = methodOperation.Syntax switch
		{
			LocalFunctionStatementSyntax localFunc => localFunc.ParameterList,
			MethodDeclarationSyntax methodDecl => methodDecl.ParameterList,
			_ => null
		};

		var vars = new Dictionary<string, object?>();

		for (var i = 0; i < (parameters?.Parameters.Count ?? 0); i++)
		{
			var parameterName = parameters!.Parameters[i].Identifier.Text;
			vars.Add(parameterName, constantArguments[i]);
		}

		var visitor = new ConstExprOperationVisitor(semanticModel, loader, (_, _) => { }, token);

		switch (methodOperation)
		{
			case ILocalFunctionOperation { Body: not null } localFunction:
				visitor.VisitBlock(localFunction.Body, vars);
				break;
			case IMethodBodyOperation { BlockBody: not null } methodBody:
				visitor.VisitBlock(methodBody.BlockBody, vars);
				break;
		}

		if (TryGetLiteral(vars[ConstExprOperationVisitor.RETURNVARIABLENAME], out var result))
		{
			return result;
		}

		return null;
	}

	/// <summary>
	/// Tries to optimize a string method.
	/// </summary>
	private SyntaxNode? TryOptimizeStringMethod(SemanticModel model, IMethodSymbol targetMethod, InvocationExpressionSyntax node, MemberAccessExpressionSyntax memberAccess, IEnumerable<SyntaxNode> visitedArguments, IEnumerable<SyntaxNode> originalArguments)
	{
		var instance = Visit(memberAccess.Expression);

		var optimizers = _stringOptimizers.Value
			.Select(s => Activator.CreateInstance(s, instance) as BaseStringFunctionOptimizer)
			.Where(o => string.Equals(o?.Name, targetMethod.Name, StringComparison.Ordinal));

		var getLambda = new Func<LambdaExpressionSyntax, LambdaExpression?>(lambda =>
		{
			if (!semanticModel.TryGetOperation<IAnonymousFunctionOperation>(lambda, out var operation))
			{
				return null;
			}

			// Create parameters for the lambda
			var lambdaParams = operation.Symbol.Parameters
				.Select(p => Expression.Parameter(loader.GetType(p.Type), p.Name))
				.ToArray();

			// Create a new visitor with the lambda parameters included
			var allParams = variables.Select(s => Expression.Parameter(loader.GetType(s.Value.Type), s.Key)).Concat(lambdaParams);
			var lambdaVisitor = new ExpressionVisitor(semanticModel, loader, allParams);

			// Visit the body with the new visitor
			var body = lambdaVisitor.VisitBlock(operation.Body, new VariableItemDictionary(variables));

			// Create the lambda expression
			return Expression.Lambda(body, lambdaParams);
		});

		var optimizeBinaryExpression = new Func<BinaryExpressionSyntax, ITypeSymbol, ITypeSymbol, ITypeSymbol, ExpressionSyntax>((binary, leftType, rightType, type) =>
		{
			var expressions = GetBinaryExpressions(node).ToList();

			if (TryOptimizeNode(binary.Kind().ToBinaryOperatorKind(), expressions, type, binary.Left, leftType, binary.Right, rightType, node.Parent, out var optimizedNode)
			    && optimizedNode is ExpressionSyntax optimizedExpr)
			{
				return optimizedExpr;
			}

			return binary;
		});

		var context = new FunctionOptimizerContext(model, loader, targetMethod, node, visitedArguments.OfType<ExpressionSyntax>().ToArray(), originalArguments.OfType<ExpressionSyntax>().ToArray(), x => Visit(x) as ExpressionSyntax, getLambda, optimizeBinaryExpression, additionalMethods, variables);

		foreach (var stringOptimizer in optimizers)
		{
			if (stringOptimizer!.TryOptimize(context, out var optimized))
			{
				return optimized;
			}
		}

		if (targetMethod.IsStatic)
		{
			return node.WithExpression(memberAccess.WithExpression(ParseTypeName(targetMethod.ContainingType.Name)))
				.WithArgumentList(node.ArgumentList.WithArguments(SeparatedList(visitedArguments.OfType<ExpressionSyntax>().Select(Argument))));
		}

		return null;
	}

	/// <summary>
	/// Tries to optimize a math method.
	/// </summary>
	private SyntaxNode? TryOptimizeMathMethod(SemanticModel model, IMethodSymbol targetMethod, InvocationExpressionSyntax node, IEnumerable<SyntaxNode> visitedArguments, IEnumerable<SyntaxNode> originalArguments)
	{
		var getLambda = new Func<LambdaExpressionSyntax, LambdaExpression?>(lambda =>
		{
			if (!semanticModel.TryGetOperation<IAnonymousFunctionOperation>(lambda, out var operation))
			{
				return null;
			}

			// Create parameters for the lambda
			var lambdaParams = operation.Symbol.Parameters
				.Select(p => Expression.Parameter(loader.GetType(p.Type), p.Name))
				.ToArray();

			// Create a new visitor with the lambda parameters included
			var allParams = variables.Select(s => Expression.Parameter(loader.GetType(s.Value.Type), s.Key)).Concat(lambdaParams);
			var lambdaVisitor = new ExpressionVisitor(semanticModel, loader, allParams);

			// Visit the body with the new visitor
			var body = lambdaVisitor.VisitBlock(operation.Body, new VariableItemDictionary(variables));

			// Create the lambda expression
			return Expression.Lambda(body, lambdaParams);
		});

		var optimizeBinaryExpression = new Func<BinaryExpressionSyntax, ITypeSymbol, ITypeSymbol, ITypeSymbol, ExpressionSyntax>((binary, leftType, rightType, type) =>
		{
			var expressions = GetBinaryExpressions(node).ToList();

			if (TryOptimizeNode(binary.Kind().ToBinaryOperatorKind(), expressions, type, binary.Left, leftType, binary.Right, rightType, node.Parent, out var optimizedNode)
			    && optimizedNode is ExpressionSyntax optimizedExpr)
			{
				return optimizedExpr;
			}

			return binary;
		});

		var context = new FunctionOptimizerContext(model, loader, targetMethod, node, visitedArguments.OfType<ExpressionSyntax>().ToArray(), originalArguments.OfType<ExpressionSyntax>().ToArray(), x => Visit(x) as ExpressionSyntax, getLambda, optimizeBinaryExpression, additionalMethods, variables);

		return _mathOptimizers.Value
			.Where(o => String.Equals(o.Name, targetMethod.Name, StringComparison.Ordinal)
			            && o.ParameterCounts.Contains(targetMethod.Parameters.Length))
			.WhereSelect<BaseMathFunctionOptimizer, SyntaxNode>((optimizer, out optimized) => optimizer.TryOptimize(context, out optimized))
			.FirstOrDefault();
	}

	/// <summary>
	/// Tries to optimize a linq method.
	/// </summary>
	private SyntaxNode? TryOptimizeLinqMethod(SemanticModel model, IMethodSymbol targetMethod, InvocationExpressionSyntax node, IEnumerable<SyntaxNode> visitedArguments, IEnumerable<SyntaxNode> originalArguments)
	{
		var getLambda = new Func<LambdaExpressionSyntax, LambdaExpression?>(lambda =>
		{
			try
			{
				if (!semanticModel.TryGetOperation<IAnonymousFunctionOperation>(lambda, out var operation))
				{
					return null;
				}

				// Create parameters for the lambda
				var lambdaParams = operation.Symbol.Parameters
					.Select(p => Expression.Parameter(loader.GetType(p.Type), p.Name))
					.ToArray();

				// Create a new visitor with the lambda parameters included
				var allParams = variables.Select(s => Expression.Parameter(loader.GetType(s.Value.Type), s.Key)).Concat(lambdaParams);
				var lambdaVisitor = new ExpressionVisitor(semanticModel, loader, allParams);

				// Visit the body with the new visitor
				var body = lambdaVisitor.VisitBlock(operation.Body, new VariableItemDictionary(variables));

				// Create the lambda expression
				return Expression.Lambda(body, lambdaParams);
			}
			catch (Exception e)
			{
				return null;
			}
		});

		var optimizeBinaryExpression = new Func<BinaryExpressionSyntax, ITypeSymbol, ITypeSymbol, ITypeSymbol, ExpressionSyntax>((binary, leftType, rightType, type) =>
		{
			if (binary.Left is LiteralExpressionSyntax leftLiteral
			    && binary.Right is LiteralExpressionSyntax rightLiteral
			    && TryGetLiteral(ObjectExtensions.ExecuteBinaryOperation(binary.Kind(), leftLiteral.Token.Value, rightLiteral.Token.Value), out var leftValue))
			{
				return leftValue;
			}

			var expressions = GetBinaryExpressions(node).ToList();

			if (TryOptimizeNode(binary.Kind().ToBinaryOperatorKind(), expressions, type, binary.Left, leftType, binary.Right, rightType, node.Parent, out var optimizedNode)
			    && optimizedNode is ExpressionSyntax optimizedExpr)
			{
				return optimizedExpr;
			}

			return binary;
		});

		var context = new FunctionOptimizerContext(model, loader, targetMethod, node, visitedArguments.OfType<ExpressionSyntax>().ToArray(), originalArguments.OfType<ExpressionSyntax>().ToArray(), x => Visit(x) as ExpressionSyntax, getLambda, optimizeBinaryExpression, additionalMethods, variables);

		var result = _linqOptimizers.Value
			.Where(o => String.Equals(o.Name, targetMethod.Name, StringComparison.Ordinal)
			            && o.ParameterCounts.Contains(targetMethod.Parameters.Length))
			.WhereSelect<BaseLinqFunctionOptimizer, SyntaxNode>((optimizer, out optimized) => optimizer.TryOptimize(context, out optimized))
			.FirstOrDefault();

		return result;
	}

	/// <summary>
	/// Converts arguments to char if there's a char overload available.
	/// </summary>
	private bool ConvertToCharOverloadIfNeeded(IMethodSymbol targetMethod, List<SyntaxNode> arguments, [NotNullWhen(true)] out List<SyntaxNode>? newArguments, [NotNullWhen(true)] out IMethodSymbol? charMethod)
	{
		if (attribute.FloatingPointMode != FloatingPointEvaluationMode.FastMath
		    || !TryGetCharOverload(targetMethod, arguments, out charMethod))
		{
			charMethod = null;
			newArguments = null;
			return false;
		}

		newArguments = arguments
			.Select(s =>
			{
				if (TryGetLiteralValue(s, out var value) && value is string { Length: 1 } charValue)
				{
					return LiteralExpression(SyntaxKind.CharacterLiteralExpression, Literal(charValue[0]));
				}

				return s;
			})
			.ToList();

		return true;
	}

	/// <summary>
	/// Handles static method invocation.
	/// </summary>
	private SyntaxNode? HandleStaticMethodInvocation(InvocationExpressionSyntax node, IMethodSymbol targetMethod, List<SyntaxNode> arguments)
	{
		// Check if method is empty (applies to local functions too)
		if (IsEmptyMethod(targetMethod))
		{
			return null;
		}

		// Check if we're already visiting this method to prevent infinite recursion
		if (visitingMethods?.Contains(targetMethod) is true)
		{
			usings.Add(targetMethod.ContainingType.ContainingNamespace.ToString());

			return node
				.WithArgumentList(node.ArgumentList.WithArguments(SeparatedList(arguments.OfType<ExpressionSyntax>().Select(Argument))))
				.WithMethodSymbolAnnotation(targetMethod);
		}

		var syntax = GetInlinedMethodSyntax(targetMethod);

		if (syntax is not null && !additionalMethods.ContainsKey(syntax))
		{
			additionalMethods.Add(syntax, true);
		}
		else if (syntax is null)
		{
			usings.Add(targetMethod.ContainingType.ContainingNamespace.ToString());
		}

		return node
			.WithArgumentList(node.ArgumentList.WithArguments(SeparatedList(arguments.OfType<ExpressionSyntax>().Select(Argument))))
			.WithMethodSymbolAnnotation(targetMethod);
	}

	/// <summary>
	/// Gets the inlined syntax for a method.
	/// </summary>
	private SyntaxNode? GetInlinedMethodSyntax(IMethodSymbol targetMethod)
	{
		return targetMethod.DeclaringSyntaxReferences
			.Select(s => s.GetSyntax(token))
			.Select<SyntaxNode, SyntaxNode?>(s =>
			{
				var mods = TokenList(Token(SyntaxKind.PrivateKeyword), Token(SyntaxKind.StaticKeyword));

				switch (s)
				{
					case MethodDeclarationSyntax method:
					{
						var parameters = method.ParameterList.Parameters
							.ToDictionary(d => d.Identifier.Text, d => new VariableItem(semanticModel.GetTypeInfo(d.Type).Type ?? semanticModel.Compilation.ObjectType, false, null));

						visitingMethods?.Add(targetMethod);
						var visitor = new ConstExprPartialRewriter(semanticModel, loader, (_, _) => { }, parameters, additionalMethods, usings, attribute, token, visitingMethods);
						var body = visitor.Visit(method.Body) as BlockSyntax;
						visitingMethods?.Remove(targetMethod);

						return method.WithBody(body).WithModifiers(mods);
					}
					case LocalFunctionStatementSyntax localFunc:
					{
						var parameters = localFunc.ParameterList.Parameters
							.ToDictionary(d => d.Identifier.Text, d => new VariableItem(semanticModel.GetTypeInfo(d.Type).Type ?? semanticModel.Compilation.ObjectType, false, null));

						visitingMethods?.Add(targetMethod);
						var visitor = new ConstExprPartialRewriter(semanticModel, loader, (_, _) => { }, parameters, additionalMethods, usings, attribute, token, visitingMethods);
						var body = visitor.Visit(localFunc.Body) as BlockSyntax;
						visitingMethods?.Remove(targetMethod);

						return localFunc.WithBody(body).WithModifiers(mods);
					}
					default:
						return null;
				}
			})
			.FirstOrDefault(f => f is not null);
	}

	/// <summary>
	/// Handles instance method invocation.
	/// </summary>
	private SyntaxNode? HandleInstanceMethodInvocation(InvocationExpressionSyntax node, IMethodSymbol targetMethod, List<SyntaxNode> arguments)
	{
		// try check if method is empty
		if (IsEmptyMethod(targetMethod))
		{
			return null;
		}

		usings.Add(targetMethod.ContainingType.ContainingNamespace.ToString());

		// Mark variable as altered since instance method may mutate it
		if (node.Expression is MemberAccessExpressionSyntax { Expression: IdentifierNameSyntax identifierName }
		    && variables.TryGetValue(identifierName.Identifier.Text, out var variable))
		{
			variable.IsAltered = true;
		}

		var expression = Visit(node.Expression) as ExpressionSyntax ?? node.Expression;

		// Handle collection conversion methods
		if (expression is MemberAccessExpressionSyntax { Expression: CollectionExpressionSyntax collection }
		    && targetMethod.IsMethod(typeof(Enumerable), "ToArray", "ToList"))
		{
			return collection;
		}

		// Try to invoke delegate
		var delegateResult = TryInvokeDelegate(node, expression, arguments);

		if (delegateResult is not null)
		{
			return delegateResult;
		}

		return node
			.WithExpression(expression)
			.WithArgumentList(node.ArgumentList
				.WithArguments(SeparatedList(arguments.OfType<ExpressionSyntax>().Select(Argument))));
	}

	/// <summary>
	/// Tries to invoke a delegate.
	/// </summary>
	private SyntaxNode? TryInvokeDelegate(InvocationExpressionSyntax node, ExpressionSyntax expression, List<SyntaxNode?> arguments)
	{
		if (!TryGetLiteralValue(expression, out var action) || action is not Delegate @delegate)
		{
			return null;
		}

		var constantArguments = arguments
			.WhereSelect<SyntaxNode?, object?>(TryGetLiteralValue)
			.ToList();

		if (constantArguments.Count != arguments.Count)
		{
			return null;
		}

		var args = constantArguments.ToArray();
		var result = @delegate.DynamicInvoke(args);

		if (@delegate.Method.ReturnType == typeof(void))
		{
			return null;
		}

		if (TryGetLiteral(result, out var literal))
		{
			if (node.Expression is IdentifierNameSyntax id
			    && variables.TryGetValue(id.Identifier.Text, out var v))
			{
				v.IsAccessed = false;
			}

			return literal;
		}

		return null;
	}

	/// <summary>
	/// Fallback for invocation expressions when symbol is not found.
	/// </summary>
	private SyntaxNode? VisitInvocationExpressionFallback(InvocationExpressionSyntax node)
	{
		return node
			.WithExpression(Visit(node.Expression) as ExpressionSyntax ?? node.Expression)
			.WithArgumentList(VisitArgumentList(node.ArgumentList) as ArgumentListSyntax ?? node.ArgumentList);
	}

	public override SyntaxNode? VisitElementAccessExpression(ElementAccessExpressionSyntax node)
	{
		var instance = Visit(node.Expression);

		var arguments = node.ArgumentList.Arguments
			.Select(arg => Visit(arg.Expression))
			.ToList();

		var constantArguments = arguments
			.WhereSelect<SyntaxNode, object?>(TryGetLiteralValue)
			.ToArray();

		if (TryGetLiteralValue(node.Expression, out var instanceValue)
		    || TryGetLiteralValue(instance, out instanceValue))
		{
			var result = TryEvaluateElementAccess(node, instanceValue, constantArguments);

			if (result is not null)
			{
				return result;
			}

			if (semanticModel.TryGetSymbol(node, out IPropertySymbol? propertySymbol)
			    && constantArguments.Length == propertySymbol.Parameters.Length)
			{
				if (loader.TryExecuteMethod(propertySymbol.GetMethod, instanceValue, new VariableItemDictionary(variables), constantArguments, out var value)
				    && TryGetLiteral(value, out var literal))
				{
					return literal;
				}

				return node
					.WithExpression(instance as ExpressionSyntax ?? node.Expression)
					.WithArgumentList(node.ArgumentList
						.WithArguments(SeparatedList(arguments.OfType<ExpressionSyntax>().Select(Argument))));
			}
		}

		return base.VisitElementAccessExpression(node);
	}

	/// <summary>
	/// Tries to evaluate element access at compile time.
	/// </summary>
	private SyntaxNode? TryEvaluateElementAccess(ElementAccessExpressionSyntax node, object? instanceValue, object?[] constantArguments)
	{
		if (!TryGetOperation(semanticModel, node, out IOperation? operation))
		{
			return null;
		}

		var type = instanceValue?.GetType();

		return operation switch
		{
			IArrayElementReferenceOperation arrayOp => TryEvaluateArrayAccess(instanceValue as Array, constantArguments, arrayOp.Indices.Length, type),
			IPropertyReferenceOperation { Property.IsIndexer: true } propOp when instanceValue is not null
			                                                                     && constantArguments.Length == propOp.Arguments.Length
			                                                                     && loader.TryExecuteMethod(propOp.Property.GetMethod, instanceValue, new VariableItemDictionary(variables), constantArguments, out var value)
			                                                                     && TryGetLiteral(value, out var literal) => literal,
			_ => null
		};

	}

	/// <summary>
	/// Tries to evaluate array access at compile time.
	/// </summary>
	private SyntaxNode? TryEvaluateArrayAccess(Array? arr, object?[] constantArguments, int indicesLength, Type? type)
	{
		if (arr is null || constantArguments.Length != indicesLength)
		{
			return null;
		}

		try
		{
			if (constantArguments.Length == 1)
			{
				var arg = constantArguments[0];

				// Handle System.Range
				if (arg is not null && (arg.GetType().FullName == "System.Range" || arg.GetType().Name == "Range"))
				{
					return TryEvaluateRangeAccess(arr, arg, type);
				}

				// Handle System.Index
				if (arg is not null && (arg.GetType().FullName == "System.Index" || arg.GetType().Name == "Index"))
				{
					return TryEvaluateIndexAccess(arr, arg);
				}
			}

			// Handle integer indices
			if (constantArguments.All(a => a is int))
			{
				var value = arr.GetValue(constantArguments.OfType<int>().ToArray());

				if (TryGetLiteral(value, out var literal))
				{
					return literal;
				}
			}
			else if (constantArguments.All(a => a is long))
			{
				var value = arr.GetValue(constantArguments.OfType<long>().ToArray());

				if (TryGetLiteral(value, out var literal))
				{
					return literal;
				}
			}
		}
		catch { }

		return null;
	}

	/// <summary>
	/// Tries to evaluate a Range access at compile time.
	/// </summary>
	private SyntaxNode? TryEvaluateRangeAccess(Array arr, object arg, Type? type)
	{
		var getOffsetAndLength = arg.GetType().GetMethod("GetOffsetAndLength", [ typeof(int) ]);
		var tuple = getOffsetAndLength?.Invoke(arg, [ arr.Length ]);

		if (tuple is null)
		{
			return null;
		}

		var tType = tuple.GetType();
		var item1 = tType.GetField("Item1")?.GetValue(tuple);
		var item2 = tType.GetField("Item2")?.GetValue(tuple);

		if (item1 is int offset && item2 is int length)
		{
			var slice = Array.CreateInstance(type?.GetElementType() ?? typeof(object), length);
			Array.Copy(arr, offset, slice, 0, length);

			if (TryGetLiteral(slice, out var result))
			{
				return result;
			}
		}

		return null;
	}

	/// <summary>
	/// Tries to evaluate an Index access at compile time.
	/// </summary>
	private SyntaxNode? TryEvaluateIndexAccess(Array arr, object arg)
	{
		var getOffset = arg.GetType().GetMethod("GetOffset", [ typeof(int) ]);
		var offset = getOffset?.Invoke(arg, [ arr.Length ]);

		if (offset is int idx)
		{
			var value = arr.GetValue(idx);

			if (TryGetLiteral(value, out var literal))
			{
				return literal;
			}
		}

		return null;
	}

	public override SyntaxNode? VisitMemberAccessExpression(MemberAccessExpressionSyntax node)
	{
		semanticModel.TryGetTypeSymbol(node, out var typeSymbol);

		var expression = Visit(node.Expression);
		var hasLiteral = TryGetLiteralValue(node.Expression, typeSymbol, out var instanceValue);

		if (!hasLiteral)
		{
			hasLiteral = TryGetLiteralValue(expression, typeSymbol, out instanceValue);
		}

		if (semanticModel.TryGetSymbol(node, out ISymbol? symbol))
		{
			var result = TryEvaluateMemberAccess(symbol, instanceValue);

			if (result is not null)
			{
				return result;
			}

			// check if symbol is IList.Count
			if (symbol is IPropertySymbol propertySymbol)
			{
				var isListCount = propertySymbol.Name == "Count"
				                  && propertySymbol.ContainingType.AllInterfaces.Any(i => i.OriginalDefinition.SpecialType is SpecialType.System_Collections_Generic_ICollection_T or SpecialType.System_Collections_Generic_IList_T);

				var isArrayLength = propertySymbol is { Name: "Length", ContainingType.SpecialType: SpecialType.System_Array };

				if ((isListCount || isArrayLength)
				    && expression is CollectionExpressionSyntax collectionExpression)
				{
					return CreateLiteral(collectionExpression.Elements.Count);
				}

				if (expression is InvocationExpressionSyntax { Expression: MemberAccessExpressionSyntax { Name: IdentifierNameSyntax { Identifier.Text: { } methodName }, Expression: { } resultExpression } })
				{
					if (isListCount)
					{
						switch (methodName)
						{
							// check if expression is Enumerable.ToList()
							case "ToList" when semanticModel.TryGetTypeSymbol(node.Expression, out var collectionType)
							                   && collectionType is INamedTypeSymbol namedTypeSymbol:
							{
								// return Enumerable.Count() instead
								var newInvocation = InvocationExpression(
										MemberAccessExpression(
											SyntaxKind.SimpleMemberAccessExpression,
											resultExpression,
											IdentifierName("Count")))
									.WithArgumentList(ArgumentList());

								var optimized = TryOptimizeLinqMethod(semanticModel, semanticModel.Compilation
									.GetTypeByMetadataName("System.Linq.Enumerable")!
									.GetMembers("Count")
									.OfType<IMethodSymbol>()
									.Select(s => s.Construct(namedTypeSymbol.TypeArguments[0]))
									.First(m => m.Parameters.Length == 1), newInvocation, [ ], [ ]);

								return optimized ?? newInvocation;
							}
							case "ToHashSet" when semanticModel.TryGetTypeSymbol(node.Expression, out var collectionType)
							                      && collectionType is INamedTypeSymbol namedTypeSymbol:
							{
								// return Enumerable.Distinct().Count() instead
								var distinctInvocation = InvocationExpression(
										MemberAccessExpression(
											SyntaxKind.SimpleMemberAccessExpression,
											resultExpression,
											IdentifierName("Distinct")))
									.WithArgumentList(ArgumentList());

								var optimizedDistinct = TryOptimizeLinqMethod(semanticModel, semanticModel.Compilation
									.GetTypeByMetadataName("System.Linq.Enumerable")!
									.GetMembers("Count")
									.OfType<IMethodSymbol>()
									.Select(s => s.Construct(namedTypeSymbol.TypeArguments[0]))
									.First(m => m.Parameters.Length == 1), distinctInvocation, [ ], [ ]);

								var countInvocation = InvocationExpression(
										MemberAccessExpression(
											SyntaxKind.SimpleMemberAccessExpression,
											optimizedDistinct as ExpressionSyntax ?? distinctInvocation,
											IdentifierName("Count")))
									.WithArgumentList(ArgumentList());

								var optimized = TryOptimizeLinqMethod(semanticModel, semanticModel.Compilation
									.GetTypeByMetadataName("System.Linq.Enumerable")!
									.GetMembers("Count")
									.OfType<IMethodSymbol>()
									.Select(s => s.Construct(namedTypeSymbol.TypeArguments[0]))
									.First(m => m.Parameters.Length == 1), countInvocation, [ ], [ ]);

								return optimized ?? countInvocation;
							}
						}
					}

					if (isArrayLength
					    && methodName == nameof(Enumerable.ToArray)
					    && semanticModel.TryGetTypeSymbol(node.Expression, out typeSymbol)
					    && typeSymbol is IArrayTypeSymbol arrayType)
					{
						// return Enumerable.Count() instead
						var newInvocation = InvocationExpression(
								MemberAccessExpression(
									SyntaxKind.SimpleMemberAccessExpression,
									resultExpression,
									IdentifierName("Count")))
							.WithArgumentList(ArgumentList());

						var optimized = TryOptimizeLinqMethod(semanticModel, semanticModel.Compilation
							.GetTypeByMetadataName("System.Linq.Enumerable")!
							.GetMembers("Count")
							.OfType<IMethodSymbol>()
							.Select(s => s.Construct(arrayType.ElementType))
							.First(m => m.Parameters.Length == 1), newInvocation, [ ], [ ]);

						return optimized ?? newInvocation;
					}
				}
			}
		}

		return node.WithExpression(expression as ExpressionSyntax ?? node.Expression);
	}

	/// <summary>
	/// Tries to evaluate member access at compile time.
	/// </summary>
	private SyntaxNode? TryEvaluateMemberAccess(ISymbol symbol, object? instanceValue)
	{
		switch (symbol)
		{
			case IFieldSymbol fieldSymbol:
				if (fieldSymbol.ContainingType.EnumUnderlyingType is not null)
				{
					return null;
				}

				if (loader.TryGetFieldValue(fieldSymbol, instanceValue, out var value)
				    && TryGetLiteral(value, out var literal))
				{
					return literal;
				}
				break;

			case IPropertySymbol { Parameters.Length: 0 } propertySymbol:
				if (loader.TryExecuteMethod(propertySymbol.GetMethod, instanceValue, new VariableItemDictionary(variables), [ ], out value)
				    && TryGetLiteral(value, out literal))
				{
					return literal;
				}
				break;
		}

		return null;
	}

	public override SyntaxNode? VisitArgument(ArgumentSyntax node)
	{
		var expression = Visit(node.Expression);

		return node.WithExpression(expression as ExpressionSyntax ?? node.Expression);
	}

	public override SyntaxNode? VisitArgumentList(ArgumentListSyntax node)
	{
		return node.WithArguments(VisitList(node.Arguments));
	}

	public override SyntaxNode? VisitQualifiedName(QualifiedNameSyntax node)
	{
		usings.Add(node.Left.ToString());
		return node.Right;
	}
}

using System;
using System.Collections.Generic;
using System.Diagnostics.CodeAnalysis;
using System.Linq;
using System.Linq.Expressions;
using ConstExpr.Core.Enumerators;
using ConstExpr.SourceGenerator.Extensions;
using ConstExpr.SourceGenerator.Models;
using ConstExpr.SourceGenerator.Optimizers;
using ConstExpr.SourceGenerator.Optimizers.FunctionOptimizers.LinqOptimizers;
using ConstExpr.SourceGenerator.Optimizers.FunctionOptimizers.MathOptimizers;
using ConstExpr.SourceGenerator.Optimizers.FunctionOptimizers.StringOptimizers;
using ConstExpr.SourceGenerator.Visitors;
using Microsoft.CodeAnalysis;
using Microsoft.CodeAnalysis.CSharp;
using Microsoft.CodeAnalysis.CSharp.Syntax;
using Microsoft.CodeAnalysis.Operations;
using SourceGen.Utilities.Extensions;
using ExpressionVisitor = ConstExpr.SourceGenerator.Visitors.ExpressionVisitor;

namespace ConstExpr.SourceGenerator.Rewriters;

/// <summary>
/// Invocation and member access visitor methods for the ConstExprPartialRewriter.
/// Handles method invocations, element access, and member access expressions.
/// </summary>
public partial class ConstExprPartialRewriter
{
	/// <summary>
	/// Visits an invocation expression and attempts to evaluate it at compile time.
	/// </summary>
	/// <remarks>
	/// The evaluation pipeline proceeds as follows:
	/// <list type="number">
	///   <item><description>Handle <c>nameof(...)</c> expressions immediately.</description></item>
	///   <item><description>Resolve the target <see cref="IMethodSymbol"/> via the semantic model.</description></item>
	///   <item><description>When all arguments are constant, execute the method directly and inline its result.</description></item>
	///   <item><description>If not fully constant, delegate to the appropriate optimizer family:
	///     string optimizers, math optimizers (FastMath mode), or LINQ optimizers.</description></item>
	///   <item><description>Fall back to static or instance method handling for non-constant calls.</description></item>
	/// </list>
	/// </remarks>
	/// <param name="node">The invocation expression syntax node being visited.</param>
	/// <returns>
	/// A rewritten <see cref="SyntaxNode"/> with the call replaced by its compile-time value,
	/// or the (possibly partially rewritten) original node when evaluation is not possible.
	/// </returns>
	public override SyntaxNode? VisitInvocationExpression(InvocationExpressionSyntax node)
	{
		// Handle nameof(...) directly
		if (TryHandleNameof(node, out var nameofResult))
		{
			return nameofResult;
		}

		if (!semanticModel.TryGetSymbol(node, out IMethodSymbol? targetMethod))
		{
			return VisitInvocationExpressionFallback(node);
		}

		var arguments = node.ArgumentList.Arguments
			.Select(arg => Visit(arg.Expression))
			.ToList();

		var constantArguments = ExtractConstantArguments(arguments, node.ArgumentList.Arguments);

		// Try to execute with all constant arguments
		if (constantArguments.Count == targetMethod.Parameters.Length)
		{
			var result = TryExecuteWithConstantArguments(node, targetMethod, constantArguments);

			if (result is not null)
			{
				return result;
			}
		}

		// Try string optimizers
		if (targetMethod.ContainingType.SpecialType == SpecialType.System_String
		    && node.Expression is MemberAccessExpressionSyntax memberAccess)
		{
			var tempNode = node.WithExpression(Visit(node.Expression) as ExpressionSyntax ?? node.Expression);
			var optimized = TryOptimizeStringMethod(semanticModel, targetMethod, tempNode, memberAccess, arguments, node.ArgumentList.Arguments.Select(s => s.Expression));

			if (optimized is not null)
			{
				return Visit(optimized);
			}
		}
		// Try math optimizers
		else if (attribute.FloatingPointMode == FloatingPointEvaluationMode.FastMath)
		{
			var tempNode = node.WithExpression(Visit(node.Expression) as ExpressionSyntax ?? node.Expression);
			var optimized = TryOptimizeMathMethod(semanticModel, targetMethod, tempNode, arguments, node.ArgumentList.Arguments.Select(s => s.Expression));

			if (optimized is not null)
			{
				return Visit(optimized);
			}
		}

		// Try LINQ optimizers (for inner calls, or when unrolling was skipped).
		// The optimized result is annotated with symbol info so it can be unrolled
		// when it re-enters the rewriter through Visit.
		if (attribute.LinqOptimisationMode != LinqOptimisationMode.None
		    && TryOptimizeLinqMethod(semanticModel, targetMethod, node, arguments, node.ArgumentList.Arguments.Select(s => s.Expression)) is { } optimizedLinq)
		{
			if (attribute.LinqOptimisationMode == LinqOptimisationMode.Unroll)
			{
				return LinqUnroller.TryUnrollLinqChain(optimizedLinq, Visit, semanticModel, additionalMethods);
			}

			return optimizedLinq;
		}

		node = node.WithExpression(Visit(node.Expression) as ExpressionSyntax ?? node.Expression);

		// Handle char overload conversion
		if (ConvertToCharOverloadIfNeeded(targetMethod, arguments, out var newArguments, out var charMethod))
		{
			targetMethod = charMethod;
			arguments = newArguments;
		}

		// Handle static methods and local functions
		return targetMethod.IsStatic || targetMethod.MethodKind == MethodKind.LocalFunction
			? HandleStaticMethodInvocation(node, targetMethod, arguments)
			: HandleInstanceMethodInvocation(node, targetMethod, arguments);

	}

	/// <summary>
	/// Tries to handle nameof(...) expressions.
	/// </summary>
	private bool TryHandleNameof(InvocationExpressionSyntax node, out SyntaxNode? result)
	{
		result = null;

		if (node is not { Expression: IdentifierNameSyntax { Identifier.Text: "nameof" }, ArgumentList.Arguments.Count: 1 })
		{
			return false;
		}

		var arg = node.ArgumentList.Arguments[0].Expression;
		string? name = null;

		if (semanticModel.TryGetSymbol(arg, out ISymbol? sym))
		{
			name = sym.Name;
		}
		else
		{
			name = arg switch
			{
				IdentifierNameSyntax id => id.Identifier.Text,
				MemberAccessExpressionSyntax { Name: IdentifierNameSyntax last } => last.Identifier.Text,
				QualifiedNameSyntax qn => qn.Right.Identifier.Text,
				GenericNameSyntax gen => gen.Identifier.Text,
				_ => name
			};
		}

		if (name is not null)
		{
			result = LiteralExpression(SyntaxKind.StringLiteralExpression, Literal(name));
			return true;
		}

		result = base.VisitInvocationExpression(node);
		return true;
	}

	/// <summary>
	/// Extracts constant arguments from visited arguments.
	/// </summary>
	private List<object> ExtractConstantArguments(List<SyntaxNode> arguments, SeparatedSyntaxList<ArgumentSyntax> originalArguments)
	{
		var constantArguments = new List<object>(arguments.Count);

		try
		{
			for (var i = 0; i < arguments.Count; i++)
			{
				if (TryGetLiteralValue(arguments[i], out var value) || TryGetLiteralValue(originalArguments[i], out value))
				{
					constantArguments.Add(value);
				}
			}
		}
		catch (Exception e)
		{
			exceptionHandler(arguments[0], e);
		}

		return constantArguments;
	}

	/// <summary>
	/// Tries to execute a method with constant arguments.
	/// </summary>
	private SyntaxNode? TryExecuteWithConstantArguments(InvocationExpressionSyntax node, IMethodSymbol targetMethod, List<object> constantArguments)
	{
		try
		{
			if (node.Expression is MemberAccessExpressionSyntax { Expression: var instanceName }
			    && !targetMethod.ContainingType.EqualsType(semanticModel.Compilation.GetTypeByMetadataName("System.Random")))
			{
				return TryExecuteInstanceMethod(targetMethod, instanceName, constantArguments);
			}

			return TryExecuteViaOperationVisitor(targetMethod, constantArguments);
		}
		catch (Exception)
		{
			return null;
		}
	}

	/// <summary>
	/// Tries to execute an instance method.
	/// </summary>
	private SyntaxNode? TryExecuteInstanceMethod(IMethodSymbol targetMethod, ExpressionSyntax instanceName, List<object> constantArguments)
	{
		var hasLiteral = TryGetLiteralValue(instanceName, out var instance)
		                 || TryGetLiteralValue(Visit(instanceName), out instance);

		if (hasLiteral && loader.TryGetType(targetMethod.ContainingType, out var type))
		{
			try
			{
				instance = Convert.ChangeType(instance, type);
			}
			catch (InvalidCastException) { }
		}

		if ((targetMethod.IsStatic || hasLiteral
			    && (instanceName is not IdentifierNameSyntax identifier || CanBePruned(identifier.Identifier.Text)))
		    && loader.TryExecuteMethod(targetMethod, instance, new VariableItemDictionary(variables), constantArguments, out var value)
		    && TryGetLiteral(value, out var literal))
		{
			if (targetMethod.ReturnsVoid)
			{
				return null;
			}

			return literal;
		}

		return null;
	}

	/// <summary>
	/// Tries to execute a method via the operation visitor.
	/// </summary>
	private SyntaxNode? TryExecuteViaOperationVisitor(IMethodSymbol targetMethod, List<object> constantArguments)
	{
		if (!TryGetOperation<IOperation>(semanticModel, targetMethod, out var methodOperation))
		{
			return null;
		}

		var parameters = methodOperation.Syntax switch
		{
			LocalFunctionStatementSyntax localFunc => localFunc.ParameterList,
			MethodDeclarationSyntax methodDecl => methodDecl.ParameterList,
			_ => null
		};

		var vars = new Dictionary<string, object?>();

		for (var i = 0; i < (parameters?.Parameters.Count ?? 0); i++)
		{
			var parameterName = parameters!.Parameters[i].Identifier.Text;
			vars.Add(parameterName, constantArguments[i]);
		}

		var visitor = new ConstExprOperationVisitor(semanticModel, loader, (_, _) => { }, token);

		switch (methodOperation)
		{
			case ILocalFunctionOperation { Body: not null } localFunction:
				visitor.VisitBlock(localFunction.Body, vars);
				break;
			case IMethodBodyOperation { BlockBody: not null } methodBody:
				visitor.VisitBlock(methodBody.BlockBody, vars);
				break;
		}

		if (TryGetLiteral(vars[ConstExprOperationVisitor.RETURNVARIABLENAME], out var result))
		{
			return result;
		}

		return null;
	}

	/// <summary>
	/// Tries to optimize a string method.
	/// </summary>
	private SyntaxNode? TryOptimizeStringMethod(SemanticModel model, IMethodSymbol targetMethod, InvocationExpressionSyntax node, MemberAccessExpressionSyntax memberAccess, IEnumerable<SyntaxNode> visitedArguments, IEnumerable<SyntaxNode> originalArguments)
	{
		var instance = Visit(memberAccess.Expression);

		var optimizers = _stringOptimizers.Value
			.Select(s => Activator.CreateInstance(s, instance) as BaseStringFunctionOptimizer)
			.Where(o => string.Equals(o?.Name, targetMethod.Name, StringComparison.Ordinal));

		var getLambda = new Func<LambdaExpressionSyntax, LambdaExpression?>(lambda =>
		{
			if (!semanticModel.TryGetOperation<IAnonymousFunctionOperation>(lambda, out var operation))
			{
				return null;
			}

			// Create parameters for the lambda
			var lambdaParams = operation.Symbol.Parameters
				.Select(p => Expression.Parameter(loader.GetType(p.Type), p.Name))
				.ToArray();

			// Create a new visitor with the lambda parameters included
			var allParams = variables.Select(s => Expression.Parameter(loader.GetType(s.Value.Type), s.Key)).Concat(lambdaParams);
			var lambdaVisitor = new ExpressionVisitor(semanticModel, loader, allParams);

			// Visit the body with the new visitor
			var body = lambdaVisitor.VisitBlock(operation.Body, new VariableItemDictionary(variables));

			// Create the lambda expression
			return Expression.Lambda(body, lambdaParams);
		});

		var optimizeBinaryExpression = new Func<BinaryExpressionSyntax, ITypeSymbol, ITypeSymbol, ITypeSymbol, ExpressionSyntax>((binary, leftType, rightType, type) =>
		{
			var expressions = GetBinaryExpressions(node).ToList();

			if (TryOptimizeNode(binary.Kind().ToBinaryOperatorKind(), expressions, type, binary.Left, leftType, binary.Right, rightType, node.Parent, out var optimizedNode)
			    && optimizedNode is ExpressionSyntax optimizedExpr)
			{
				return optimizedExpr;
			}

			return binary;
		});

		var context = new FunctionOptimizerContext(model, loader, targetMethod, node, visitedArguments.OfType<ExpressionSyntax>().ToArray(), originalArguments.OfType<ExpressionSyntax>().ToArray(), x => Visit(x) as ExpressionSyntax, getLambda, optimizeBinaryExpression, additionalMethods, variables);

		foreach (var stringOptimizer in optimizers)
		{
			if (stringOptimizer!.TryOptimize(context, out var optimized))
			{
				return optimized;
			}
		}

		if (targetMethod.IsStatic)
		{
			return node.WithExpression(memberAccess.WithExpression(ParseTypeName(targetMethod.ContainingType.Name)))
				.WithArgumentList(node.ArgumentList.WithArguments(SeparatedList(visitedArguments.OfType<ExpressionSyntax>().Select(Argument))));
		}

		return null;
	}

	/// <summary>
	/// Tries to optimize a math method.
	/// </summary>
	private SyntaxNode? TryOptimizeMathMethod(SemanticModel model, IMethodSymbol targetMethod, InvocationExpressionSyntax node, IEnumerable<SyntaxNode> visitedArguments, IEnumerable<SyntaxNode> originalArguments)
	{
		var getLambda = new Func<LambdaExpressionSyntax, LambdaExpression?>(lambda =>
		{
			if (!semanticModel.TryGetOperation<IAnonymousFunctionOperation>(lambda, out var operation))
			{
				return null;
			}

			// Create parameters for the lambda
			var lambdaParams = operation.Symbol.Parameters
				.Select(p => Expression.Parameter(loader.GetType(p.Type), p.Name))
				.ToArray();

			// Create a new visitor with the lambda parameters included
			var allParams = variables.Select(s => Expression.Parameter(loader.GetType(s.Value.Type), s.Key)).Concat(lambdaParams);
			var lambdaVisitor = new ExpressionVisitor(semanticModel, loader, allParams);

			// Visit the body with the new visitor
			var body = lambdaVisitor.VisitBlock(operation.Body, new VariableItemDictionary(variables));

			// Create the lambda expression
			return Expression.Lambda(body, lambdaParams);
		});

		var optimizeBinaryExpression = new Func<BinaryExpressionSyntax, ITypeSymbol, ITypeSymbol, ITypeSymbol, ExpressionSyntax>((binary, leftType, rightType, type) =>
		{
			var expressions = GetBinaryExpressions(node).ToList();

			if (TryOptimizeNode(binary.Kind().ToBinaryOperatorKind(), expressions, type, binary.Left, leftType, binary.Right, rightType, node.Parent, out var optimizedNode)
			    && optimizedNode is ExpressionSyntax optimizedExpr)
			{
				return optimizedExpr;
			}

			return binary;
		});

		var context = new FunctionOptimizerContext(model, loader, targetMethod, node, visitedArguments.OfType<ExpressionSyntax>().ToArray(), originalArguments.OfType<ExpressionSyntax>().ToArray(), x => Visit(x) as ExpressionSyntax, getLambda, optimizeBinaryExpression, additionalMethods, variables);

		return _mathOptimizers.Value
			.Where(o => String.Equals(o.Name, targetMethod.Name, StringComparison.Ordinal)
			            && o.ParameterCounts.Contains(targetMethod.Parameters.Length))
			.WhereSelect<BaseMathFunctionOptimizer, SyntaxNode>((optimizer, out optimized) => optimizer.TryOptimize(context, out optimized))
			.FirstOrDefault();
	}

	/// <summary>
	/// Tries to optimize a linq method.
	/// </summary>
	private SyntaxNode? TryOptimizeLinqMethod(SemanticModel model, IMethodSymbol targetMethod, InvocationExpressionSyntax node, IEnumerable<SyntaxNode> visitedArguments, IEnumerable<SyntaxNode> originalArguments)
	{
		var getLambda = new Func<LambdaExpressionSyntax, LambdaExpression?>(lambda =>
		{
			try
			{
				if (!semanticModel.TryGetOperation<IAnonymousFunctionOperation>(lambda, out var operation))
				{
					return null;
				}

				// Create parameters for the lambda
				var lambdaParams = operation.Symbol.Parameters
					.Select(p => Expression.Parameter(loader.GetType(p.Type), p.Name))
					.ToArray();

				// Create a new visitor with the lambda parameters included
				var allParams = variables.Select(s => Expression.Parameter(loader.GetType(s.Value.Type), s.Key)).Concat(lambdaParams);
				var lambdaVisitor = new ExpressionVisitor(semanticModel, loader, allParams);

				// Visit the body with the new visitor
				var body = lambdaVisitor.VisitBlock(operation.Body, new VariableItemDictionary(variables));

				// Create the lambda expression
				return Expression.Lambda(body, lambdaParams);
			}
			catch (Exception e)
			{
				return null;
			}
		});

		var optimizeBinaryExpression = new Func<BinaryExpressionSyntax, ITypeSymbol, ITypeSymbol, ITypeSymbol, ExpressionSyntax>((binary, leftType, rightType, type) =>
		{
			if (binary.Left is LiteralExpressionSyntax leftLiteral
			    && binary.Right is LiteralExpressionSyntax rightLiteral
			    && TryGetLiteral(ObjectExtensions.ExecuteBinaryOperation(binary.Kind(), leftLiteral.Token.Value, rightLiteral.Token.Value), out var leftValue))
			{
				return leftValue;
			}

			var expressions = GetBinaryExpressions(node).ToList();

			if (TryOptimizeNode(binary.Kind().ToBinaryOperatorKind(), expressions, type, binary.Left, leftType, binary.Right, rightType, node.Parent, out var optimizedNode)
			    && optimizedNode is ExpressionSyntax optimizedExpr)
			{
				return optimizedExpr;
			}

			return binary;
		});

		var context = new FunctionOptimizerContext(model, loader, targetMethod, node, visitedArguments.OfType<ExpressionSyntax>().ToArray(), originalArguments.OfType<ExpressionSyntax>().ToArray(), x => Visit(x) as ExpressionSyntax, getLambda, optimizeBinaryExpression, additionalMethods, variables);

		var result = _linqOptimizers.Value
			.Where(o => String.Equals(o.Name, targetMethod.Name, StringComparison.Ordinal)
			            && o.ParameterCounts.Contains(targetMethod.Parameters.Length))
			.WhereSelect<BaseLinqFunctionOptimizer, SyntaxNode>((optimizer, out optimized) => optimizer.TryOptimize(context, out optimized))
			.FirstOrDefault();

		return result;
	}

	/// <summary>
	/// Converts arguments to char if there's a char overload available.
	/// </summary>
	private bool ConvertToCharOverloadIfNeeded(IMethodSymbol targetMethod, List<SyntaxNode> arguments, [NotNullWhen(true)] out List<SyntaxNode>? newArguments, [NotNullWhen(true)] out IMethodSymbol? charMethod)
	{
		if (attribute.FloatingPointMode != FloatingPointEvaluationMode.FastMath
		    || !TryGetCharOverload(targetMethod, arguments, out charMethod))
		{
			charMethod = null;
			newArguments = null;
			return false;
		}

		newArguments = arguments
			.Select(s =>
			{
				if (TryGetLiteralValue(s, out var value) && value is string { Length: 1 } charValue)
				{
					return LiteralExpression(SyntaxKind.CharacterLiteralExpression, Literal(charValue[0]));
				}

				return s;
			})
			.ToList();

		return true;
	}

	/// <summary>
	/// Handles static method invocation.
	/// </summary>
	private SyntaxNode? HandleStaticMethodInvocation(InvocationExpressionSyntax node, IMethodSymbol targetMethod, List<SyntaxNode> arguments)
	{
		// Check if method is empty (applies to local functions too)
		if (IsEmptyMethod(targetMethod))
		{
			return null;
		}

		// Check if we're already visiting this method to prevent infinite recursion
		if (visitingMethods?.Contains(targetMethod) is true)
		{
			usings.Add(targetMethod.ContainingType.ContainingNamespace.ToString());

			return node
				.WithArgumentList(node.ArgumentList.WithArguments(SeparatedList(arguments.OfType<ExpressionSyntax>().Select(Argument))))
				.WithMethodSymbolAnnotation(targetMethod);
		}

		var syntax = GetInlinedMethodSyntax(targetMethod);

		if (syntax is not null && !additionalMethods.ContainsKey(syntax))
		{
			additionalMethods.Add(syntax, true);
		}
		else if (syntax is null)
		{
			usings.Add(targetMethod.ContainingType.ContainingNamespace.ToString());
		}

		return node
			.WithArgumentList(node.ArgumentList.WithArguments(SeparatedList(arguments.OfType<ExpressionSyntax>().Select(Argument))))
			.WithMethodSymbolAnnotation(targetMethod);
	}

	/// <summary>
	/// Gets the inlined syntax for a method.
	/// </summary>
	private SyntaxNode? GetInlinedMethodSyntax(IMethodSymbol targetMethod)
	{
		return targetMethod.DeclaringSyntaxReferences
			.Select(s => s.GetSyntax(token))
			.Select<SyntaxNode, SyntaxNode?>(s =>
			{
				var mods = TokenList(Token(SyntaxKind.PrivateKeyword), Token(SyntaxKind.StaticKeyword));

				switch (s)
				{
					case MethodDeclarationSyntax method:
					{
						var parameters = method.ParameterList.Parameters
							.ToDictionary(d => d.Identifier.Text, d => new VariableItem(semanticModel.GetTypeInfo(d.Type).Type ?? semanticModel.Compilation.ObjectType, false, null));

						visitingMethods?.Add(targetMethod);
						var visitor = new ConstExprPartialRewriter(semanticModel, loader, (_, _) => { }, parameters, additionalMethods, usings, attribute, token, visitingMethods);
						var body = visitor.Visit(method.Body) as BlockSyntax;
						visitingMethods?.Remove(targetMethod);

						return method.WithBody(body).WithModifiers(mods);
					}
					case LocalFunctionStatementSyntax localFunc:
					{
						var parameters = localFunc.ParameterList.Parameters
							.ToDictionary(d => d.Identifier.Text, d => new VariableItem(semanticModel.GetTypeInfo(d.Type).Type ?? semanticModel.Compilation.ObjectType, false, null));

						visitingMethods?.Add(targetMethod);
						var visitor = new ConstExprPartialRewriter(semanticModel, loader, (_, _) => { }, parameters, additionalMethods, usings, attribute, token, visitingMethods);
						var body = visitor.Visit(localFunc.Body) as BlockSyntax;
						visitingMethods?.Remove(targetMethod);

						return localFunc.WithBody(body).WithModifiers(mods);
					}
					default:
						return null;
				}
			})
			.FirstOrDefault(f => f is not null);
	}

	/// <summary>
	/// Handles instance method invocation.
	/// </summary>
	private SyntaxNode? HandleInstanceMethodInvocation(InvocationExpressionSyntax node, IMethodSymbol targetMethod, List<SyntaxNode> arguments)
	{
		// try check if method is empty
		if (IsEmptyMethod(targetMethod))
		{
			return null;
		}

		usings.Add(targetMethod.ContainingType.ContainingNamespace.ToString());

		// Mark variable as altered since instance method may mutate it
		if (node.Expression is MemberAccessExpressionSyntax { Expression: IdentifierNameSyntax identifierName }
		    && variables.TryGetValue(identifierName.Identifier.Text, out var variable))
		{
			variable.IsAltered = true;
		}

		var expression = Visit(node.Expression) as ExpressionSyntax ?? node.Expression;

		// Handle collection conversion methods
		if (expression is MemberAccessExpressionSyntax { Expression: CollectionExpressionSyntax collection }
		    && targetMethod.IsMethod(typeof(Enumerable), "ToArray", "ToList"))
		{
			return collection;
		}

		// Try to invoke delegate
		var delegateResult = TryInvokeDelegate(node, expression, arguments);

		if (delegateResult is not null)
		{
			return delegateResult;
		}

		return node
			.WithExpression(expression)
			.WithArgumentList(node.ArgumentList
				.WithArguments(SeparatedList(arguments.OfType<ExpressionSyntax>().Select(Argument))));
	}

	/// <summary>
	/// Tries to invoke a delegate.
	/// </summary>
	private SyntaxNode? TryInvokeDelegate(InvocationExpressionSyntax node, ExpressionSyntax expression, List<SyntaxNode?> arguments)
	{
		if (!TryGetLiteralValue(expression, out var action) || action is not Delegate @delegate)
		{
			return null;
		}

		var constantArguments = arguments
			.WhereSelect<SyntaxNode?, object?>(TryGetLiteralValue)
			.ToList();

		if (constantArguments.Count != arguments.Count)
		{
			return null;
		}

		var args = constantArguments.ToArray();
		var result = @delegate.DynamicInvoke(args);

		if (@delegate.Method.ReturnType == typeof(void))
		{
			return null;
		}

		if (TryGetLiteral(result, out var literal))
		{
			if (node.Expression is IdentifierNameSyntax id
			    && variables.TryGetValue(id.Identifier.Text, out var v))
			{
				v.IsAccessed = false;
			}

			return literal;
		}

		return null;
	}

	/// <summary>
	/// Fallback for invocation expressions when symbol is not found.
	/// </summary>
	private SyntaxNode? VisitInvocationExpressionFallback(InvocationExpressionSyntax node)
	{
		return node
			.WithExpression(Visit(node.Expression) as ExpressionSyntax ?? node.Expression)
			.WithArgumentList(VisitArgumentList(node.ArgumentList) as ArgumentListSyntax ?? node.ArgumentList);
	}

	public override SyntaxNode? VisitElementAccessExpression(ElementAccessExpressionSyntax node)
	{
		var instance = Visit(node.Expression);

		var arguments = node.ArgumentList.Arguments
			.Select(arg => Visit(arg.Expression))
			.ToList();

		var constantArguments = arguments
			.WhereSelect<SyntaxNode, object?>(TryGetLiteralValue)
			.ToArray();

		if (TryGetLiteralValue(node.Expression, out var instanceValue)
		    || TryGetLiteralValue(instance, out instanceValue))
		{
			var result = TryEvaluateElementAccess(node, instanceValue, constantArguments);

			if (result is not null)
			{
				return result;
			}

			if (semanticModel.TryGetSymbol(node, out IPropertySymbol? propertySymbol)
			    && constantArguments.Length == propertySymbol.Parameters.Length)
			{
				if (loader.TryExecuteMethod(propertySymbol.GetMethod, instanceValue, new VariableItemDictionary(variables), constantArguments, out var value)
				    && TryGetLiteral(value, out var literal))
				{
					return literal;
				}

				return node
					.WithExpression(instance as ExpressionSyntax ?? node.Expression)
					.WithArgumentList(node.ArgumentList
						.WithArguments(SeparatedList(arguments.OfType<ExpressionSyntax>().Select(Argument))));
			}
		}

		return base.VisitElementAccessExpression(node);
	}

	/// <summary>
	/// Tries to evaluate element access at compile time.
	/// </summary>
	private SyntaxNode? TryEvaluateElementAccess(ElementAccessExpressionSyntax node, object? instanceValue, object?[] constantArguments)
	{
		if (!TryGetOperation(semanticModel, node, out IOperation? operation))
		{
			return null;
		}

		var type = instanceValue?.GetType();

		return operation switch
		{
			IArrayElementReferenceOperation arrayOp => TryEvaluateArrayAccess(instanceValue as Array, constantArguments, arrayOp.Indices.Length, type),
			IPropertyReferenceOperation { Property.IsIndexer: true } propOp when instanceValue is not null
			                                                                     && constantArguments.Length == propOp.Arguments.Length
			                                                                     && loader.TryExecuteMethod(propOp.Property.GetMethod, instanceValue, new VariableItemDictionary(variables), constantArguments, out var value)
			                                                                     && TryGetLiteral(value, out var literal) => literal,
			_ => null
		};

	}

	/// <summary>
	/// Tries to evaluate array access at compile time.
	/// </summary>
	private SyntaxNode? TryEvaluateArrayAccess(Array? arr, object?[] constantArguments, int indicesLength, Type? type)
	{
		if (arr is null || constantArguments.Length != indicesLength)
		{
			return null;
		}

		try
		{
			if (constantArguments.Length == 1)
			{
				var arg = constantArguments[0];

				// Handle System.Range
				if (arg is not null && (arg.GetType().FullName == "System.Range" || arg.GetType().Name == "Range"))
				{
					return TryEvaluateRangeAccess(arr, arg, type);
				}

				// Handle System.Index
				if (arg is not null && (arg.GetType().FullName == "System.Index" || arg.GetType().Name == "Index"))
				{
					return TryEvaluateIndexAccess(arr, arg);
				}
			}

			// Handle integer indices
			if (constantArguments.All(a => a is int))
			{
				var value = arr.GetValue(constantArguments.OfType<int>().ToArray());

				if (TryGetLiteral(value, out var literal))
				{
					return literal;
				}
			}
			else if (constantArguments.All(a => a is long))
			{
				var value = arr.GetValue(constantArguments.OfType<long>().ToArray());

				if (TryGetLiteral(value, out var literal))
				{
					return literal;
				}
			}
		}
		catch { }

		return null;
	}

	/// <summary>
	/// Tries to evaluate a Range access at compile time.
	/// </summary>
	private SyntaxNode? TryEvaluateRangeAccess(Array arr, object arg, Type? type)
	{
		var getOffsetAndLength = arg.GetType().GetMethod("GetOffsetAndLength", [ typeof(int) ]);
		var tuple = getOffsetAndLength?.Invoke(arg, [ arr.Length ]);

		if (tuple is null)
		{
			return null;
		}

		var tType = tuple.GetType();
		var item1 = tType.GetField("Item1")?.GetValue(tuple);
		var item2 = tType.GetField("Item2")?.GetValue(tuple);

		if (item1 is int offset && item2 is int length)
		{
			var slice = Array.CreateInstance(type?.GetElementType() ?? typeof(object), length);
			Array.Copy(arr, offset, slice, 0, length);

			if (TryGetLiteral(slice, out var result))
			{
				return result;
			}
		}

		return null;
	}

	/// <summary>
	/// Tries to evaluate an Index access at compile time.
	/// </summary>
	private SyntaxNode? TryEvaluateIndexAccess(Array arr, object arg)
	{
		var getOffset = arg.GetType().GetMethod("GetOffset", [ typeof(int) ]);
		var offset = getOffset?.Invoke(arg, [ arr.Length ]);

		if (offset is int idx)
		{
			var value = arr.GetValue(idx);

			if (TryGetLiteral(value, out var literal))
			{
				return literal;
			}
		}

		return null;
	}

	public override SyntaxNode? VisitMemberAccessExpression(MemberAccessExpressionSyntax node)
	{
		semanticModel.TryGetTypeSymbol(node, out var typeSymbol);

		var expression = Visit(node.Expression);
		var hasLiteral = TryGetLiteralValue(node.Expression, typeSymbol, out var instanceValue);

		if (!hasLiteral)
		{
			hasLiteral = TryGetLiteralValue(expression, typeSymbol, out instanceValue);
		}

		if (semanticModel.TryGetSymbol(node, out ISymbol? symbol))
		{
			var result = TryEvaluateMemberAccess(symbol, instanceValue);

			if (result is not null)
			{
				return result;
			}

			// check if symbol is IList.Count
			if (symbol is IPropertySymbol propertySymbol)
			{
				var isListCount = propertySymbol.Name == "Count"
				                  && propertySymbol.ContainingType.AllInterfaces.Any(i => i.OriginalDefinition.SpecialType is SpecialType.System_Collections_Generic_ICollection_T or SpecialType.System_Collections_Generic_IList_T);

				var isArrayLength = propertySymbol is { Name: "Length", ContainingType.SpecialType: SpecialType.System_Array };

				if ((isListCount || isArrayLength)
				    && expression is CollectionExpressionSyntax collectionExpression)
				{
					return CreateLiteral(collectionExpression.Elements.Count);
				}

				if (expression is InvocationExpressionSyntax { Expression: MemberAccessExpressionSyntax { Name: IdentifierNameSyntax { Identifier.Text: { } methodName }, Expression: { } resultExpression } })
				{
					if (isListCount)
					{
						switch (methodName)
						{
							// check if expression is Enumerable.ToList()
							case "ToList" when semanticModel.TryGetTypeSymbol(node.Expression, out var collectionType)
							                   && collectionType is INamedTypeSymbol namedTypeSymbol:
							{
								// return Enumerable.Count() instead
								var newInvocation = InvocationExpression(
										MemberAccessExpression(
											SyntaxKind.SimpleMemberAccessExpression,
											resultExpression,
											IdentifierName("Count")))
									.WithArgumentList(ArgumentList());

								var optimized = TryOptimizeLinqMethod(semanticModel, semanticModel.Compilation
									.GetTypeByMetadataName("System.Linq.Enumerable")!
									.GetMembers("Count")
									.OfType<IMethodSymbol>()
									.Select(s => s.Construct(namedTypeSymbol.TypeArguments[0]))
									.First(m => m.Parameters.Length == 1), newInvocation, [ ], [ ]);

								return optimized ?? newInvocation;
							}
							case "ToHashSet" when semanticModel.TryGetTypeSymbol(node.Expression, out var collectionType)
							                      && collectionType is INamedTypeSymbol namedTypeSymbol:
							{
								// return Enumerable.Distinct().Count() instead
								var distinctInvocation = InvocationExpression(
										MemberAccessExpression(
											SyntaxKind.SimpleMemberAccessExpression,
											resultExpression,
											IdentifierName("Distinct")))
									.WithArgumentList(ArgumentList());

								var optimizedDistinct = TryOptimizeLinqMethod(semanticModel, semanticModel.Compilation
									.GetTypeByMetadataName("System.Linq.Enumerable")!
									.GetMembers("Count")
									.OfType<IMethodSymbol>()
									.Select(s => s.Construct(namedTypeSymbol.TypeArguments[0]))
									.First(m => m.Parameters.Length == 1), distinctInvocation, [ ], [ ]);

								var countInvocation = InvocationExpression(
										MemberAccessExpression(
											SyntaxKind.SimpleMemberAccessExpression,
											optimizedDistinct as ExpressionSyntax ?? distinctInvocation,
											IdentifierName("Count")))
									.WithArgumentList(ArgumentList());

								var optimized = TryOptimizeLinqMethod(semanticModel, semanticModel.Compilation
									.GetTypeByMetadataName("System.Linq.Enumerable")!
									.GetMembers("Count")
									.OfType<IMethodSymbol>()
									.Select(s => s.Construct(namedTypeSymbol.TypeArguments[0]))
									.First(m => m.Parameters.Length == 1), countInvocation, [ ], [ ]);

								return optimized ?? countInvocation;
							}
						}
					}

					if (isArrayLength
					    && methodName == nameof(Enumerable.ToArray)
					    && semanticModel.TryGetTypeSymbol(node.Expression, out typeSymbol)
					    && typeSymbol is IArrayTypeSymbol arrayType)
					{
						// return Enumerable.Count() instead
						var newInvocation = InvocationExpression(
								MemberAccessExpression(
									SyntaxKind.SimpleMemberAccessExpression,
									resultExpression,
									IdentifierName("Count")))
							.WithArgumentList(ArgumentList());

						var optimized = TryOptimizeLinqMethod(semanticModel, semanticModel.Compilation
							.GetTypeByMetadataName("System.Linq.Enumerable")!
							.GetMembers("Count")
							.OfType<IMethodSymbol>()
							.Select(s => s.Construct(arrayType.ElementType))
							.First(m => m.Parameters.Length == 1), newInvocation, [ ], [ ]);

						return optimized ?? newInvocation;
					}
				}
			}
		}

		return node.WithExpression(expression as ExpressionSyntax ?? node.Expression);
	}

	/// <summary>
	/// Tries to evaluate member access at compile time.
	/// </summary>
	private SyntaxNode? TryEvaluateMemberAccess(ISymbol symbol, object? instanceValue)
	{
		switch (symbol)
		{
			case IFieldSymbol fieldSymbol:
				if (fieldSymbol.ContainingType.EnumUnderlyingType is not null)
				{
					return null;
				}

				if (loader.TryGetFieldValue(fieldSymbol, instanceValue, out var value)
				    && TryGetLiteral(value, out var literal))
				{
					return literal;
				}
				break;

			case IPropertySymbol { Parameters.Length: 0 } propertySymbol:
				if (loader.TryExecuteMethod(propertySymbol.GetMethod, instanceValue, new VariableItemDictionary(variables), [ ], out value)
				    && TryGetLiteral(value, out literal))
				{
					return literal;
				}
				break;
		}

		return null;
	}

	public override SyntaxNode? VisitArgument(ArgumentSyntax node)
	{
		var expression = Visit(node.Expression);

		return node.WithExpression(expression as ExpressionSyntax ?? node.Expression);
	}

	public override SyntaxNode? VisitArgumentList(ArgumentListSyntax node)
	{
		return node.WithArguments(VisitList(node.Arguments));
	}

	public override SyntaxNode? VisitQualifiedName(QualifiedNameSyntax node)
	{
		usings.Add(node.Left.ToString());
		return node.Right;
	}
}

using System;
using System.Collections.Generic;
using System.Collections.Immutable;
using System.Linq;
using ConstExpr.SourceGenerator.Comparers;
using ConstExpr.SourceGenerator.Extensions;
using ConstExpr.SourceGenerator.Models;
using ConstExpr.SourceGenerator.Optimizers.ConditionalOptimizers;
using ConstExpr.SourceGenerator.Refactorers;
using ConstExpr.SourceGenerator.Visitors;
using Microsoft.CodeAnalysis;
using Microsoft.CodeAnalysis.CSharp;
using Microsoft.CodeAnalysis.CSharp.Syntax;
using Microsoft.CodeAnalysis.Operations;

namespace ConstExpr.SourceGenerator.Rewriters;

/// <summary>
/// Statement visitor methods for the ConstExprPartialRewriter.
/// Handles if, for, foreach, while, switch, return, block, and local declaration statements.
/// </summary>
public partial class ConstExprPartialRewriter
{
	public override SyntaxNode? VisitIfStatement(IfStatementSyntax node)
	{
		var condition = Visit(node.Condition);

		if (TryGetLiteralValue(condition, out var value))
		{
			if (value is true)
			{
				return Visit(node.Statement);
			}

			return node.Else is not null
				? Visit(node.Else.Statement)
				: null;
		}

		// Save variable state before visiting either branch. The condition is unknown so we
		// cannot tell which branch will execute at runtime. Each branch must be visited with
		// the pre-if state, and afterwards any variable written in either branch must be
		// marked as unknown so downstream code doesn't rely on a specific branch's value.
		var savedState = SaveVariableState();
		var statement = Visit(node.Statement);

		// Restore to pre-if state before visiting the else branch so it doesn't pick up
		// mutations that were made inside the then branch (e.g., h = 0 leaking into else).
		RestoreVariableState(savedState);

		var @else = Visit(node.Else);

		// After both branches: restore original state and invalidate every variable that
		// could have been written in either branch.
		RestoreVariableState(savedState);
		InvalidateAssignedVariables(node.Statement);

		if (node.Else is not null)
		{
			InvalidateAssignedVariables(node.Else.Statement);
		}

		if (@else is null)
		{
			switch (statement)
			{
				case IfStatementSyntax { Else: null } nestedIf:
				{
					condition = Visit(ParenthesizedExpression(LogicalOrExpression(condition as ExpressionSyntax ?? node.Condition, nestedIf.Condition)));
					statement = nestedIf.Statement;

					break;
				}
				case BlockSyntax { Statements: [ IfStatementSyntax { Else: null } nestedBlockIf ] }:
				{
					condition = Visit(ParenthesizedExpression(LogicalOrExpression(condition as ExpressionSyntax ?? node.Condition, nestedBlockIf.Condition)));
					statement = nestedBlockIf.Statement;

					break;
				}
			}
		}

		var result = node
			.WithCondition(condition as ExpressionSyntax ?? node.Condition)
			.WithStatement(statement as StatementSyntax ?? node.Statement)
			.WithElse(@else as ElseClauseSyntax);

		// Try to convert an if-else-if chain to a switch statement / switch expression.
		// Only attempt this when there is at least one else branch (otherwise a single-case
		// switch would be noisier than the original if).
		if (ConvertIfToSwitchCodeRefactoring.TryConvertIfElseChainToSwitch(result, out var switchNode))
		{
			return switchNode;
		}

		switch (statement)
		{
			case ExpressionStatementSyntax { Expression: AssignmentExpressionSyntax assignment }
				when assignment.IsKind(SyntaxKind.SimpleAssignmentExpression)
				     && assignment.Left is IdentifierNameSyntax assignedIdentifier
				     && @else is ElseClauseSyntax { Statement: ExpressionStatementSyntax { Expression: AssignmentExpressionSyntax elseAssignment } }
				     && elseAssignment.IsKind(SyntaxKind.SimpleAssignmentExpression)
				     && elseAssignment.Left is IdentifierNameSyntax elseAssignedIdentifier
				     && assignedIdentifier.Identifier.Text == elseAssignedIdentifier.Identifier.Text:
			{
				return ExpressionStatement(
					VisitIfElseAssignment(condition, node.Condition, assignment, elseAssignment));
			}
			case BlockSyntax { Statements: [ ExpressionStatementSyntax { Expression: AssignmentExpressionSyntax assignment } ] }
				when assignment.IsKind(SyntaxKind.SimpleAssignmentExpression)
				     && assignment.Left is IdentifierNameSyntax assignedIdentifier
				     && @else is ElseClauseSyntax { Statement: BlockSyntax { Statements: [ ExpressionStatementSyntax { Expression: AssignmentExpressionSyntax elseAssignment } ] } }
				     && elseAssignment.IsKind(SyntaxKind.SimpleAssignmentExpression)
				     && elseAssignment.Left is IdentifierNameSyntax elseAssignedIdentifier
				     && assignedIdentifier.Identifier.Text == elseAssignedIdentifier.Identifier.Text:
			{
				return ExpressionStatement(
					VisitIfElseAssignment(condition, node.Condition, assignment, elseAssignment));
			}
			case ReturnStatementSyntax { Expression: { } ifReturn }
				when @else is ElseClauseSyntax { Statement: ReturnStatementSyntax { Expression: { } elseReturn } }:
			{
				return ReturnStatement(
					Visit(ConditionalExpression(
						condition as ExpressionSyntax ?? node.Condition,
						ifReturn,
						elseReturn)) as ExpressionSyntax);
			}
			case BlockSyntax { Statements: [ ReturnStatementSyntax { Expression: { } ifReturn } ] }
				when @else is ElseClauseSyntax { Statement: BlockSyntax { Statements: [ ReturnStatementSyntax { Expression: { } elseReturn } ] } }:
			{
				return ReturnStatement(
					Visit(ConditionalExpression(
						condition as ExpressionSyntax ?? node.Condition,
						ifReturn,
						elseReturn)) as ExpressionSyntax);
			}
		}

		return result;
	}

	/// <summary>
	/// Converts an if-else where both branches perform a simple assignment to the same variable
	/// into a single assignment. When the condition is a comparison and the operands match the
	/// assigned values (e.g. <c>if (a &gt; b) x = a; else x = b;</c>), the optimizer rewrites the
	/// right-hand side to a call like <c>T.MaxNative(a, b)</c> for any numeric type T. Falls back
	/// to an ordinary conditional expression assignment otherwise.
	/// </summary>
	private ExpressionSyntax VisitIfElseAssignment(
		SyntaxNode condition,
		ExpressionSyntax originalCondition,
		AssignmentExpressionSyntax thenAssignment,
		AssignmentExpressionSyntax elseAssignment)
	{
		var condExpr = ConditionalExpression(
			condition as ExpressionSyntax ?? originalCondition,
			thenAssignment.Right,
			elseAssignment.Right);

		// Resolve the element type from the branch operands — the synthetic conditional itself is
		// not present in the semantic model, but the original source identifiers/expressions are.
		if (!semanticModel.TryGetTypeSymbol(thenAssignment.Right, symbolStore, out var assignType))
		{
			semanticModel.TryGetTypeSymbol(elseAssignment.Right, symbolStore, out assignType);
		}

		if (assignType is not null)
		{
			var optimizer = new ConditionalExpressionOptimizer
			{
				Condition = condExpr.Condition,
				WhenTrue = condExpr.WhenTrue,
				WhenFalse = condExpr.WhenFalse,
				Type = assignType
			};

			if (optimizer.TryOptimize(loader, variables, out var optimizedRhs))
			{
				var visitedRhs = Visit(optimizedRhs) as ExpressionSyntax ?? optimizedRhs as ExpressionSyntax ?? condExpr;
				return thenAssignment.WithRight(visitedRhs);
			}
		}

		return Visit(thenAssignment.WithRight(condExpr)) as ExpressionSyntax
		       ?? thenAssignment.WithRight(condExpr);
	}

	public override SyntaxNode? VisitForStatement(ForStatementSyntax node)
	{
		var names = variables.Keys.ToImmutableHashSet();

		Visit(node.Declaration);

		var condition = Visit(node.Condition);

		if (TryGetLiteralValue(condition, out var value))
		{
			switch (value)
			{
				case false:
				{
					return null;
				}
				case true:
				{
					return TryUnrollForLoop(node);
				}
			}
		}

		return VisitForStatementWithoutUnroll(node, names);
	}

	/// <summary>
	/// Tries to unroll a for loop when the condition is always true.
	/// </summary>
	private SyntaxNode? TryUnrollForLoop(ForStatementSyntax node)
	{
		if (attribute.MaxUnrollIterations == 0)
		{
			InvalidateAssignedVariables(node);
			return base.VisitForStatement(node);
		}

		var result = new List<SyntaxNode?>();
		var iteratorCount = 0;

		do
		{
			if (iteratorCount++ >= attribute.MaxUnrollIterations)
			{
				InvalidateAssignedVariables(node);
				return base.VisitForStatement(node);
			}

			var statement = Visit(node.Statement);

			if (statement is not BlockSyntax)
			{
				result.Add(statement);
			}

			if (ShouldStopUnrolling(statement, result))
			{
				break;
			}

			VisitList(node.Incrementors);
		} while (TryGetLiteralValue(Visit(node.Condition), out var value) && value is true);

		return result.Count > 0 ? ToStatementSyntax(result) : null;
	}

	/// <summary>
	/// Visits a for statement without attempting to unroll it.
	/// </summary>
	private SyntaxNode VisitForStatementWithoutUnroll(ForStatementSyntax node, ImmutableHashSet<string> names)
	{
		// Restore variable states after visiting the loop
		foreach (var name in variables.Keys.Except(names).ToList())
		{
			variables.Remove(name);
		}

		var declaration = Visit(node.Declaration);
		InvalidateAssignedVariables(node);

		return node
			.WithInitializers(VisitList(node.Initializers))
			.WithCondition(Visit(node.Condition) as ExpressionSyntax ?? node.Condition)
			.WithDeclaration(declaration as VariableDeclarationSyntax ?? node.Declaration)
			.WithStatement(Visit(node.Statement) as StatementSyntax ?? node.Statement);
	}

	public override SyntaxNode? VisitWhileStatement(WhileStatementSyntax node)
	{
		var condition = Visit(node.Condition);

		if (TryGetLiteralValue(condition, out var value))
		{
			switch (value)
			{
				case false:
				{
					return null;
				}
				case true when attribute.MaxUnrollIterations > 0:
				{
					return TryUnrollWhileLoop(node);
				}
			}
		}

		InvalidateAssignedVariables(node);

		var body = Visit(node.Statement);
		var rewrittenCondition = Visit(node.Condition);

		if (body is BlockSyntax { Statements: [ .., BreakStatementSyntax or ReturnStatementSyntax ] items })
		{
			return IfStatement(
				rewrittenCondition as ExpressionSyntax ?? node.Condition,
				Block(items.Take(items.Count - 1)));
		}

		return node
			.WithCondition(rewrittenCondition as ExpressionSyntax ?? node.Condition)
			.WithStatement(body as StatementSyntax ?? node.Statement);
	}

	public override SyntaxNode? VisitDoStatement(DoStatementSyntax node)
	{
		// Do-while always executes at least once
		var result = new List<SyntaxNode?>();
		var iteratorCount = 0;

		do
		{
			if (iteratorCount++ >= attribute.MaxUnrollIterations)
			{
				InvalidateAssignedVariables(node);
				return base.VisitDoStatement(node);
			}

			var statement = Visit(node.Statement);

			if (statement is not BlockSyntax)
			{
				result.Add(statement);
			}

			if (ShouldStopUnrolling(statement, result))
			{
				break;
			}

			if (statement is BlockSyntax block)
			{
				result.AddRange(block.Statements);
			}
		} while (TryGetLiteralValue(Visit(node.Condition), out var value) && value is true);

		// Check final condition
		var finalCondition = Visit(node.Condition);

		if (TryGetLiteralValue(finalCondition, out var finalValue) && finalValue is false)
		{
			return result.Count > 0 ? ToStatementSyntax(result) : null;
		}

		InvalidateAssignedVariables(node);

		return base.VisitDoStatement(node);
	}

	/// <summary>
	/// Tries to unroll a while loop when the condition is always true.
	/// </summary>
	private SyntaxNode? TryUnrollWhileLoop(WhileStatementSyntax node)
	{
		var result = new List<SyntaxNode?>();
		var iteratorCount = 0;

		do
		{
			if (iteratorCount++ >= attribute.MaxUnrollIterations)
			{
				InvalidateAssignedVariables(node);
				return base.VisitWhileStatement(node);
			}

			var statement = Visit(node.Statement);

			if (statement is not BlockSyntax)
			{
				result.Add(statement);
			}

			if (ShouldStopUnrolling(statement, result))
			{
				break;
			}
		} while (TryGetLiteralValue(Visit(node.Condition), out var value) && value is true);

		return result.Count > 0 ? ToStatementSyntax(result) : null;
	}

	public override SyntaxNode? VisitForEachStatement(ForEachStatementSyntax node)
	{
		var names = variables.Keys.ToImmutableHashSet();
		var collection = Visit(node.Expression);

		var items = GetForEachItems(collection);

		if (items is not null && attribute.MaxUnrollIterations > 0 && items.Count < attribute.MaxUnrollIterations)
		{
			return TryUnrollForEachLoop(node, items);
		}

		InvalidateAssignedVariablesForForEach(node, names);

		return base.VisitForEachStatement(node);
	}

	/// <summary>
	/// Gets the items from a foreach collection expression.
	/// </summary>
	private IReadOnlyList<CSharpSyntaxNode>? GetForEachItems(SyntaxNode? collection)
	{
		return collection switch
		{
			CollectionExpressionSyntax collectionExpression => collectionExpression.Elements,
			LiteralExpressionSyntax { RawKind: (int) SyntaxKind.StringLiteralExpression } stringLiteral =>
				stringLiteral.Token.ValueText
					.Select(s => CreateLiteral(s) as CSharpSyntaxNode)
					.ToList(),
			_ => null
		};
	}

	/// <summary>
	/// Tries to unroll a foreach loop.
	/// </summary>
	private SyntaxNode? TryUnrollForEachLoop(ForEachStatementSyntax node, IReadOnlyList<CSharpSyntaxNode> items)
	{
		var name = node.Identifier.Text;

		if (semanticModel.GetOperation(node) is not IForEachLoopOperation operation)
		{
			return base.VisitForEachStatement(node);
		}

		var variable = new VariableItem(operation.LoopControlVariable.Type, true, null, true);
		variables.Add(name, variable);

		var statements = new List<SyntaxNode>();

		foreach (var item in items)
		{
			if (!TryGetLiteralValue(item, out var val))
			{
				continue;
			}

			variable.Value = val;
			var statement = Visit(node.Statement);

			if (statement is not BlockSyntax)
			{
				statements.Add(statement);
			}

			if (ShouldStopUnrolling(statement, statements))
			{
				break;
			}

			if (statement is BlockSyntax block)
			{
				statements.Add(block);
			}
		}

		var result = ToStatementSyntax(statements);

		// After unrolling, N consecutive equality-check if-statements with identical bodies
		// may be collapsed into a single combined if by CombineConsecutiveIfStatements
		// (e.g. "if (1==x){return true;} … if (5==x){return true;}" → "if (x is 1 or 5){return true;}").
		// Returning a single IfStatementSyntax (instead of a BlockSyntax wrapping N ifs) means
		// the parent VisitBlock will see the if as a direct sibling of the trailing "return false;"
		// and SimplifyIfReturnPatterns can then fold the pair into "return x is 1 or 5;".
		//
		// Guard: only combine when every if-statement's body unconditionally jumps
		// (return / break / continue / throw).  Without this guard, accumulation patterns like
		// "if (5==x) count++; if (5==x) count++;" (from arrays with duplicate values) would be
		// incorrectly merged into a single conditional that increments count only once.
		if (result is BlockSyntax resultBlock
		    && resultBlock.Statements.All(s => s is not IfStatementSyntax ifStmt
		                                       || ContainsJumpStatement(ifStmt.Statement)))
		{
			var combined = CombineConsecutiveIfStatements(resultBlock.Statements, Visit);
			result = combined.Count == 1 ? combined[0] : Block(combined);
		}

		return result;
	}

	/// <summary>
	/// Invalidates assigned variables for a foreach loop.
	/// </summary>
	private void InvalidateAssignedVariablesForForEach(ForEachStatementSyntax node, ImmutableHashSet<string> names)
	{
		var assignedVariables = AssignedVariables(node);

		foreach (var name in names)
		{
			if (variables.TryGetValue(name, out var variable) && assignedVariables.Contains(name))
			{
				variable.HasValue = false;
			}
		}
	}

	/// <summary>
	/// Checks if loop unrolling should stop based on the current statement.
	/// </summary>
	private static bool ShouldStopUnrolling(SyntaxNode? statement, ICollection<SyntaxNode?> result)
	{
		if (statement is BreakStatementSyntax or ReturnStatementSyntax)
		{
			return true;
		}

		if (statement is not BlockSyntax block || !block.Statements.Any(s => s is BreakStatementSyntax or ReturnStatementSyntax))
		{
			return false;
		}

		foreach (var item in block.Statements)
		{
			if (item is BreakStatementSyntax)
			{
				return true;
			}

			result.Add(item);

			if (item is ReturnStatementSyntax)
			{
				return true;
			}
		}

		return false;
	}

	/// <summary>
	/// Invalidates all assigned variables in the given node.
	/// </summary>
	private void InvalidateAssignedVariables(StatementSyntax node)
	{
		foreach (var name in AssignedVariables(node))
		{
			if (variables.TryGetValue(name, out var variable))
			{
				variable.HasValue = false;
			}
		}
	}

	public override SyntaxNode VisitBlock(BlockSyntax node)
	{
		var visited = VisitList(node.Statements);

		var untilThrown = TakeUntilThrownStatements(visited);
		var combined = CombineConsecutiveIfStatements(untilThrown, Visit);
		var mergedIfChain = MergeMixedBoolReturnIfs(combined, Visit);
		var simplified = SimplifyIfReturnPatterns(mergedIfChain);

		return node.WithStatements(simplified);
	}

	/// <summary>
	/// Takes statements until a throw or return statement is encountered (inclusive).
	/// Any code after a throw or return statement is unreachable and can be removed.
	/// </summary>
	private static SyntaxList<StatementSyntax> TakeUntilThrownStatements(SyntaxList<StatementSyntax> statements)
	{
		var result = new List<StatementSyntax>();

		foreach (var statement in statements)
		{
			result.Add(statement);

			// Stop after a throw or return statement since code after it is unreachable
			if (statement is ThrowStatementSyntax
			    or ExpressionStatementSyntax { Expression: ThrowExpressionSyntax }
			    or ReturnStatementSyntax)
			{
				break;
			}
		}

		// Strip a trailing void return (return;) — it is redundant at the end of a void block
		// and produces cleaner output (e.g. empty body {} instead of { return; }).
		if (result.Count > 0 && result[^1] is ReturnStatementSyntax { Expression: null })
		{
			result.RemoveAt(result.Count - 1);
		}

		return List(result);
	}

	/// <summary>
	/// Simplifies patterns like:
	/// - if (cond) { return true; } return false; => return cond;
	/// - if (cond) { return false; } return true; => return !cond;
	/// </summary>
	private SyntaxList<StatementSyntax> SimplifyIfReturnPatterns(SyntaxList<StatementSyntax> statements)
	{
		if (statements.Count < 2)
		{
			return statements;
		}

		var result = new List<StatementSyntax>();

		for (var i = 0; i < statements.Count; i++)
		{
			// Check for pattern: if (cond) { return <bool>; } followed by return <opposite bool>;
			if (i + 1 < statements.Count
			    && statements[i] is IfStatementSyntax { Else: null } ifStatement
			    && statements[i + 1] is ReturnStatementSyntax followingReturn)
			{
				if (TryGetIfReturnBoolPattern(ifStatement, followingReturn, out var simplifiedReturn)
				    || TryGetIfReturnPattern(ifStatement, followingReturn, out simplifiedReturn))
				{
					result.Add(simplifiedReturn!);
					i++; // Skip the following return statement
					continue;
				}
			}

			result.Add(statements[i]);
		}

		var resultList = List(result);

		if (statements.Count != resultList.Count)
		{
			return SimplifyIfReturnPatterns(resultList);
		}

		return resultList;
	}

	/// <summary>
	/// Tries to simplify if-return-bool patterns.
	/// </summary>
	private bool TryGetIfReturnBoolPattern(IfStatementSyntax ifStatement, ReturnStatementSyntax followingReturn, out ReturnStatementSyntax? simplified)
	{
		simplified = null;

		// Get the return statement from the if body
		var ifBody = ifStatement.Statement;

		var ifReturn = ifBody switch
		{
			ReturnStatementSyntax ret => ret,
			BlockSyntax { Statements: [ ReturnStatementSyntax ret ] } => ret,
			_ => null
		};

		if (ifReturn is null)
		{
			return false;
		}

		// Check if both returns are boolean literals
		if (!TryGetBoolLiteral(ifReturn.Expression, out var ifReturnValue))
		{
			return false;
		}

		// Only simplify if they return opposite values
		if (SyntaxNodeComparer.Get().Equals(ifReturn.Expression, followingReturn.Expression))
		{
			return false;
		}

		// if (cond) { return true; } return false; => return cond;
		// if (cond) { return false; } return true; => return !cond;
		var condition = ifStatement.Condition;

		if (ifReturnValue)
		{
			if (followingReturn.Expression is LiteralExpressionSyntax { RawKind: (int) SyntaxKind.FalseLiteralExpression })
			{
				// return cond;
				simplified = ReturnStatement(condition);
			}
			else
			{
				var newCondition = LogicalAndExpression(condition, followingReturn.Expression);
				var booleanType = semanticModel.Compilation.CreateBoolean();

				if (TryOptimizeNode(BinaryOperatorKind.ConditionalAnd, [ ], booleanType, condition, booleanType, followingReturn.Expression, booleanType, null, out var result))
				{
					simplified = ReturnStatement(result as ExpressionSyntax ?? condition);
					return true;
				}

				simplified = ReturnStatement(newCondition);
			}
		}
		else if (InvertLogicalRefactoring.TryInvertLogical(condition as BinaryExpressionSyntax, out var inverted))
		{
			var booleanType = semanticModel.Compilation.CreateBoolean();

			if (TryOptimizeNode(BinaryOperatorKind.ConditionalAnd, [ ], booleanType, inverted, booleanType, followingReturn.Expression, booleanType, null, out var result))
			{
				simplified = ReturnStatement(result as ExpressionSyntax ?? condition);
				return true;
			}

			simplified = ReturnStatement(LogicalAndExpression(inverted, followingReturn.Expression));
		}
		else
		{
			var booleanType = semanticModel.Compilation.CreateBoolean();
			var invertedCondition = NegateExpressionRefactoring.Negate(condition);

			if (TryOptimizeNode(BinaryOperatorKind.ConditionalAnd, [ ], booleanType, invertedCondition, booleanType, followingReturn.Expression, booleanType, null, out var result))
			{
				simplified = ReturnStatement(result as ExpressionSyntax ?? condition);
				return true;
			}

			simplified = ReturnStatement(LogicalAndExpression(invertedCondition, followingReturn.Expression));
		}

		return simplified is not null;
	}

	/// <summary>
	/// Tries to simplify if-return-bool patterns.
	/// </summary>
	private bool TryGetIfReturnPattern(IfStatementSyntax ifStatement, ReturnStatementSyntax followingReturn, out ReturnStatementSyntax? simplified)
	{
		simplified = null;

		// Get the return statement from the if body
		var ifBody = ifStatement.Statement;

		var ifReturn = ifBody switch
		{
			ReturnStatementSyntax ret => ret,
			BlockSyntax { Statements: [ ReturnStatementSyntax ret ] } => ret,
			_ => null
		};

		if (ifReturn is null)
		{
			return false;
		}

		simplified = ReturnStatement(Visit(
			ConditionalExpression(
				ifStatement.Condition,
				ifReturn.Expression,
				followingReturn.Expression)) as ExpressionSyntax ?? ifReturn.Expression);

		return true;
	}

	/// <summary>
	/// Tries to extract a boolean literal value from an expression.
	/// </summary>
	private static bool TryGetBoolLiteral(ExpressionSyntax? expression, out bool value)
	{
		value = false;

		if (expression is LiteralExpressionSyntax literal)
		{
			if (literal.IsKind(SyntaxKind.TrueLiteralExpression))
			{
				value = true;
				return true;
			}

			if (literal.IsKind(SyntaxKind.FalseLiteralExpression))
			{
				value = false;
				return true;
			}
		}

		return false;
	}

	/// <summary>
	/// Merges a consecutive run of if-statements (each returning a boolean literal, no else)
	/// that contains a mix of <c>return true</c> and <c>return false</c> into a single
	/// <c>if (...) return false;</c> statement.
	/// <para>
	/// For each if-statement in the run:
	/// <list type="bullet">
	///   <item>If it returns <c>false</c> → its condition is added to the OR chain as-is.</item>
	///   <item>If it returns <c>true</c>  → its condition is negated and added to the OR chain,
	///     because reaching a subsequent <c>return false</c> requires the <c>return true</c>
	///     guard to have been skipped (i.e., its condition was false).</item>
	/// </list>
	/// </para>
	/// Example:
	/// <code>
	/// if (n &lt;= 1) return false;
	/// if (n &lt;= 3) return true;
	/// if (IsEven(n) || n % 3 == 0) return false;
	/// </code>
	/// becomes:
	/// <code>
	/// if (n &lt;= 1 || n &gt; 3 || IsEven(n) || n % 3 == 0) return false;
	/// </code>
	/// </summary>
	private static SyntaxList<StatementSyntax> MergeMixedBoolReturnIfs(SyntaxList<StatementSyntax> statements, Func<SyntaxNode?, SyntaxNode?> visit)
	{
		if (statements.Count < 2)
		{
			return statements;
		}

		var result = new List<StatementSyntax>();
		var i = 0;

		while (i < statements.Count)
		{
			var runStart = i;
			var run = new List<(ExpressionSyntax Condition, bool ReturnValue)>();

			while (i < statements.Count && TryGetIfBoolReturnBody(statements[i], out var cond, out var retVal))
			{
				run.Add((cond!, retVal));
				i++;
			}

			// Only merge when there are at least 2 ifs with mixed true/false returns
			if (run.Count >= 2 && run.Any(r => r.ReturnValue) && run.Any(r => !r.ReturnValue))
			{
				// Build combined OR condition:
				// - "return false" conditions → keep as-is
				// - "return true" conditions → negate (they act as guards; skipping them means we fall through to the false path)
				ExpressionSyntax? combined = null;

				foreach (var (cond, retVal) in run)
				{
					var part = retVal ? NegateCondition(cond) : cond;

					if (combined is null)
					{
						combined = part;
					}
					else
					{
						combined = LogicalOrExpression(
							NeedsParenthesesInOrContext(combined) ? ParenthesizedExpression(combined) : combined,
							NeedsParenthesesInOrContext(part) ? ParenthesizedExpression(part) : part);
					}
				}

				var visitedCombined = visit(combined) as ExpressionSyntax ?? combined!;

				result.Add(IfStatement(
					visitedCombined,
					ReturnStatement(LiteralExpression(SyntaxKind.FalseLiteralExpression))));
			}
			else if (run.Count > 0)
			{
				// Run is all-same-value — add back unchanged
				for (var k = runStart; k < runStart + run.Count; k++)
				{
					result.Add(statements[k]);
				}
			}
			else
			{
				// Current statement is not a bool-return if — add it as-is and advance
				result.Add(statements[i]);
				i++;
			}
		}

		return List(result);
	}

	/// <summary>
	/// Tries to extract the condition and boolean return value from an if-statement whose body
	/// is a single <c>return true;</c> or <c>return false;</c> (with or without braces) and
	/// that has no else clause.
	/// </summary>
	private static bool TryGetIfBoolReturnBody(
		StatementSyntax statement,
		out ExpressionSyntax? condition,
		out bool returnValue)
	{
		condition = null;
		returnValue = false;

		if (statement is not IfStatementSyntax { Else: null } ifStmt)
		{
			return false;
		}

		var ret = ifStmt.Statement switch
		{
			ReturnStatementSyntax r => r,
			BlockSyntax { Statements: [ ReturnStatementSyntax r ] } => r,
			_ => null
		};

		if (ret?.Expression is not LiteralExpressionSyntax lit)
		{
			return false;
		}

		if (lit.IsKind(SyntaxKind.TrueLiteralExpression))
		{
			condition = ifStmt.Condition;
			returnValue = true;
			return true;
		}

		if (lit.IsKind(SyntaxKind.FalseLiteralExpression))
		{
			condition = ifStmt.Condition;
			returnValue = false;
			return true;
		}

		return false;
	}

	/// <summary>
	/// Negates a condition, preferring a direct inversion (e.g., <c>n &lt;= 3</c> → <c>n &gt; 3</c>)
	/// over wrapping in <c>!(…)</c>.
	/// </summary>
	private static ExpressionSyntax NegateCondition(ExpressionSyntax condition)
	{
		if (InvertLogicalRefactoring.TryInvertLogical(condition as BinaryExpressionSyntax, out var inverted))
		{
			return inverted;
		}

		return NegateExpressionRefactoring.Negate(condition);
	}

	/// <summary>
	/// Combines consecutive if statements that have identical bodies into a single if statement.
	/// Two strategies are applied in order:
	/// 1. Equality pattern: conditions of the form <c>x == literal</c> against the same variable
	///    are combined into <c>if (x is 1 or 5) { … }</c>.
	/// 2. General ||: when the body ends with a jump statement (return / break / continue / throw),
	///    any consecutive if statements with an identical body are combined using <c>||</c>.
	/// Example (strategy 1): if (1 == x) { return true; } if (5 == x) { return true; }
	///                     => if (x is 1 or 5) { return true; }
	/// Example (strategy 2): if (x &gt; 5) { return; } if (y &lt; 3) { return; }
	///                     => if (x &gt; 5 || y &lt; 3) { return; }
	/// </summary>
	internal static SyntaxList<StatementSyntax> CombineConsecutiveIfStatements(SyntaxList<StatementSyntax> statements, Func<SyntaxNode?, SyntaxNode?> visit)
	{
		if (statements.Count < 2)
		{
			return statements;
		}

		var result = new List<StatementSyntax>();
		var i = 0;

		while (i < statements.Count)
		{
			// Only process if statements without an else clause
			if (statements[i] is not IfStatementSyntax { Else: null } currentIf)
			{
				result.Add(statements[i]);
				i++;

				continue;
			}

			// Strategy 1: equality (is or) combination
			if (TryGetEqualityComparisonInfo(currentIf.Condition, out var targetIdentifier, out var firstLiteral))
			{
				var literals = new List<LiteralExpressionSyntax> { firstLiteral! };
				var j = i + 1;

				while (j < statements.Count)
				{
					if (statements[j] is not IfStatementSyntax { Else: null } nextIf)
					{
						break;
					}

					if (!SyntaxNodeComparer.Get<StatementSyntax>().Equals(nextIf.Statement, currentIf.Statement))
					{
						break;
					}

					if (!TryGetEqualityComparisonInfo(nextIf.Condition, out var nextTarget, out var nextLiteral)
					    || nextTarget != targetIdentifier)
					{
						break;
					}

					literals.Add(nextLiteral!);
					j++;
				}

				if (literals.Count > 1)
				{
					// e.g. target is 1 or 5 or 10
					var combinedCondition = visit(CreateIsOrPattern(targetIdentifier!, literals)) as ExpressionSyntax;
					result.Add(currentIf.WithCondition(combinedCondition));
					i = j;
					continue;
				}
			}

			// Strategy 2: general || combination when body ends with a jump statement
			if (ContainsJumpStatement(currentIf.Statement))
			{
				var conditions = new List<ExpressionSyntax> { currentIf.Condition };
				var j = i + 1;

				while (j < statements.Count)
				{
					if (statements[j] is not IfStatementSyntax { Else: null } nextIf)
					{
						break;
					}

					if (!SyntaxNodeComparer.Get<StatementSyntax>().Equals(nextIf.Statement, currentIf.Statement))

					{
						break;
					}

					conditions.Add(nextIf.Condition);
					j++;
				}

				if (conditions.Count > 1)
				{
					var combinedCondition = conditions[0];

					for (var k = 1; k < conditions.Count; k++)
					{
						combinedCondition = LogicalOrExpression(
							NeedsParenthesesInOrContext(combinedCondition)
								? ParenthesizedExpression(combinedCondition)
								: combinedCondition,
							NeedsParenthesesInOrContext(conditions[k])
								? ParenthesizedExpression(conditions[k])
								: conditions[k]);
					}

					result.Add(currentIf.WithCondition(combinedCondition));
					i = j;
					continue;
				}
			}

			result.Add(statements[i]);
			i++;
		}

		return List(result);
	}

	/// <summary>
	/// Returns <see langword="true"/> when a statement unconditionally ends with a jump
	/// (return, break, continue, or throw), making it safe to combine consecutive if
	/// statements with identical bodies using <c>||</c>.
	/// </summary>
	private static bool ContainsJumpStatement(StatementSyntax statement) =>
		statement switch
		{
			ReturnStatementSyntax => true,
			BreakStatementSyntax => true,
			ContinueStatementSyntax => true,
			ThrowStatementSyntax => true,
			BlockSyntax block => block.Statements.Count > 0 && ContainsJumpStatement(block.Statements.Last()),
			_ => false
		};

	/// <summary>
	/// Returns <see langword="true"/> when an expression needs parentheses when used as an
	/// operand of <c>||</c> (i.e., its precedence is lower than logical-or).
	/// </summary>
	private static bool NeedsParenthesesInOrContext(ExpressionSyntax expression) =>
		expression is ConditionalExpressionSyntax or AssignmentExpressionSyntax;

	/// <summary>
	/// Creates an 'is' pattern expression with 'or' for multiple values.
	/// Example: target is 1 or 5 or 10
	/// </summary>
	private static ExpressionSyntax CreateIsOrPattern(string targetIdentifier, List<LiteralExpressionSyntax> literals)
	{
		// Build pattern: 1 or 5 or 10 or ...
		PatternSyntax pattern = ConstantPattern(literals[0]);

		for (var k = 1; k < literals.Count; k++)
		{
			pattern = BinaryPattern(
				SyntaxKind.OrPattern,
				pattern,
				ConstantPattern(literals[k]));
		}

		// Create: target is <pattern>
		return IsPatternExpression(
			IdentifierName(targetIdentifier),
			pattern);
	}

	/// <summary>
	/// Tries to extract the comparison target identifier and literal value from an equality expression.
	/// Handles both 'value == target' and 'target == value' formats.
	/// </summary>
	private static bool TryGetEqualityComparisonInfo(ExpressionSyntax condition, out string? targetIdentifier, out LiteralExpressionSyntax? literal)
	{
		targetIdentifier = null;
		literal = null;

		if (condition is not BinaryExpressionSyntax binary
		    || !binary.IsKind(SyntaxKind.EqualsExpression))
		{
			return false;
		}

		switch (binary)
		{
			// Check if left side is identifier and right side is literal
			case { Left: IdentifierNameSyntax leftId, Right: LiteralExpressionSyntax rightLit }:
			{
				targetIdentifier = leftId.Identifier.Text;
				literal = rightLit;
				return true;
			}
			// Check if right side is identifier and left side is literal
			case { Right: IdentifierNameSyntax rightId, Left: LiteralExpressionSyntax leftLit }:
			{
				targetIdentifier = rightId.Identifier.Text;
				literal = leftLit;
				return true;
			}
			default:
			{
				return false;
			}
		}
	}

	public override SyntaxNode? VisitReturnStatement(ReturnStatementSyntax node)
	{
		var visitedExpression = Visit(node.Expression);

		// If the return expression is parenthesized, unwrap it to avoid returning nested parentheses that can interfere with pattern matching and other optimizations.
		if (visitedExpression is ParenthesizedExpressionSyntax parenthesized)
		{
			visitedExpression = parenthesized.Expression;
		}

		if (visitedExpression is ThrowExpressionSyntax throwExpression)
		{
			return ThrowStatement(throwExpression.Expression);
		}

		return node.WithExpression(visitedExpression as ExpressionSyntax);
	}

	public override SyntaxNode? VisitLocalDeclarationStatement(LocalDeclarationStatementSyntax node)
	{
		var visited = Visit(node.Declaration);

		return visited switch
		{
			null => null,
			BlockSyntax block => block,
			VariableDeclarationSyntax declaration => node.WithDeclaration(declaration),
			ExpressionStatementSyntax expressionStatement => expressionStatement,
			ThrowStatementSyntax throwStatement => throwStatement,
			_ => node
		};
	}
}

using System;
using System.Collections.Generic;
using System.Collections.Immutable;
using System.Linq;
using ConstExpr.SourceGenerator.Comparers;
using ConstExpr.SourceGenerator.Extensions;
using ConstExpr.SourceGenerator.Models;
using ConstExpr.SourceGenerator.Optimizers.ConditionalOptimizers;
using ConstExpr.SourceGenerator.Refactorers;
using ConstExpr.SourceGenerator.Visitors;
using Microsoft.CodeAnalysis;
using Microsoft.CodeAnalysis.CSharp;
using Microsoft.CodeAnalysis.CSharp.Syntax;
using Microsoft.CodeAnalysis.Operations;

namespace ConstExpr.SourceGenerator.Rewriters;

/// <summary>
/// Statement visitor methods for the ConstExprPartialRewriter.
/// Handles if, for, foreach, while, switch, return, block, and local declaration statements.
/// </summary>
public partial class ConstExprPartialRewriter
{
	public override SyntaxNode? VisitIfStatement(IfStatementSyntax node)
	{
		var condition = Visit(node.Condition);

		if (TryGetLiteralValue(condition, out var value))
		{
			if (value is true)
			{
				return Visit(node.Statement);
			}

			return node.Else is not null
				? Visit(node.Else.Statement)
				: null;
		}

		// Save variable state before visiting either branch. The condition is unknown so we
		// cannot tell which branch will execute at runtime. Each branch must be visited with
		// the pre-if state, and afterwards any variable written in either branch must be
		// marked as unknown so downstream code doesn't rely on a specific branch's value.
		var savedState = SaveVariableState();
		var statement = Visit(node.Statement);

		// Restore to pre-if state before visiting the else branch so it doesn't pick up
		// mutations that were made inside the then branch (e.g., h = 0 leaking into else).
		RestoreVariableState(savedState);

		var @else = Visit(node.Else);

		// After both branches: restore original state and invalidate every variable that
		// could have been written in either branch.
		RestoreVariableState(savedState);
		InvalidateAssignedVariables(node.Statement);

		if (node.Else is not null)
		{
			InvalidateAssignedVariables(node.Else.Statement);
		}

		if (@else is null)
		{
			switch (statement)
			{
				case IfStatementSyntax { Else: null } nestedIf:
				{
					condition = Visit(ParenthesizedExpression(LogicalOrExpression(condition as ExpressionSyntax ?? node.Condition, nestedIf.Condition)));
					statement = nestedIf.Statement;

					break;
				}
				case BlockSyntax { Statements: [ IfStatementSyntax { Else: null } nestedBlockIf ] }:
				{
					condition = Visit(ParenthesizedExpression(LogicalOrExpression(condition as ExpressionSyntax ?? node.Condition, nestedBlockIf.Condition)));
					statement = nestedBlockIf.Statement;

					break;
				}
			}
		}

		var result = node
			.WithCondition(condition as ExpressionSyntax ?? node.Condition)
			.WithStatement(statement as StatementSyntax ?? node.Statement)
			.WithElse(@else as ElseClauseSyntax);

		// Try to convert an if-else-if chain to a switch statement / switch expression.
		// Only attempt this when there is at least one else branch (otherwise a single-case
		// switch would be noisier than the original if).
		if (ConvertIfToSwitchCodeRefactoring.TryConvertIfElseChainToSwitch(result, out var switchNode))
		{
			return switchNode;
		}

		switch (statement)
		{
			case ExpressionStatementSyntax { Expression: AssignmentExpressionSyntax assignment }
				when assignment.IsKind(SyntaxKind.SimpleAssignmentExpression)
				     && assignment.Left is IdentifierNameSyntax assignedIdentifier
				     && @else is ElseClauseSyntax { Statement: ExpressionStatementSyntax { Expression: AssignmentExpressionSyntax elseAssignment } }
				     && elseAssignment.IsKind(SyntaxKind.SimpleAssignmentExpression)
				     && elseAssignment.Left is IdentifierNameSyntax elseAssignedIdentifier
				     && assignedIdentifier.Identifier.Text == elseAssignedIdentifier.Identifier.Text:
			{
				return ExpressionStatement(
					VisitIfElseAssignment(condition, node.Condition, assignment, elseAssignment));
			}
			case BlockSyntax { Statements: [ ExpressionStatementSyntax { Expression: AssignmentExpressionSyntax assignment } ] }
				when assignment.IsKind(SyntaxKind.SimpleAssignmentExpression)
				     && assignment.Left is IdentifierNameSyntax assignedIdentifier
				     && @else is ElseClauseSyntax { Statement: BlockSyntax { Statements: [ ExpressionStatementSyntax { Expression: AssignmentExpressionSyntax elseAssignment } ] } }
				     && elseAssignment.IsKind(SyntaxKind.SimpleAssignmentExpression)
				     && elseAssignment.Left is IdentifierNameSyntax elseAssignedIdentifier
				     && assignedIdentifier.Identifier.Text == elseAssignedIdentifier.Identifier.Text:
			{
				return ExpressionStatement(
					VisitIfElseAssignment(condition, node.Condition, assignment, elseAssignment));
			}
			case ReturnStatementSyntax { Expression: { } ifReturn }
				when @else is ElseClauseSyntax { Statement: ReturnStatementSyntax { Expression: { } elseReturn } }:
			{
				return ReturnStatement(
					Visit(ConditionalExpression(
						condition as ExpressionSyntax ?? node.Condition,
						ifReturn,
						elseReturn)) as ExpressionSyntax);
			}
			case BlockSyntax { Statements: [ ReturnStatementSyntax { Expression: { } ifReturn } ] }
				when @else is ElseClauseSyntax { Statement: BlockSyntax { Statements: [ ReturnStatementSyntax { Expression: { } elseReturn } ] } }:
			{
				return ReturnStatement(
					Visit(ConditionalExpression(
						condition as ExpressionSyntax ?? node.Condition,
						ifReturn,
						elseReturn)) as ExpressionSyntax);
			}
		}

		return result;
	}

	/// <summary>
	/// Converts an if-else where both branches perform a simple assignment to the same variable
	/// into a single assignment. When the condition is a comparison and the operands match the
	/// assigned values (e.g. <c>if (a &gt; b) x = a; else x = b;</c>), the optimizer rewrites the
	/// right-hand side to a call like <c>T.MaxNative(a, b)</c> for any numeric type T. Falls back
	/// to an ordinary conditional expression assignment otherwise.
	/// </summary>
	private ExpressionSyntax VisitIfElseAssignment(
		SyntaxNode condition,
		ExpressionSyntax originalCondition,
		AssignmentExpressionSyntax thenAssignment,
		AssignmentExpressionSyntax elseAssignment)
	{
		var condExpr = ConditionalExpression(
			condition as ExpressionSyntax ?? originalCondition,
			thenAssignment.Right,
			elseAssignment.Right);

		// Resolve the element type from the branch operands — the synthetic conditional itself is
		// not present in the semantic model, but the original source identifiers/expressions are.
		if (!semanticModel.TryGetTypeSymbol(thenAssignment.Right, symbolStore, out var assignType))
		{
			semanticModel.TryGetTypeSymbol(elseAssignment.Right, symbolStore, out assignType);
		}

		if (assignType is not null)
		{
			var optimizer = new ConditionalExpressionOptimizer
			{
				Condition = condExpr.Condition,
				WhenTrue = condExpr.WhenTrue,
				WhenFalse = condExpr.WhenFalse,
				Type = assignType
			};

			if (optimizer.TryOptimize(loader, variables, out var optimizedRhs))
			{
				var visitedRhs = Visit(optimizedRhs) as ExpressionSyntax ?? optimizedRhs as ExpressionSyntax ?? condExpr;
				return thenAssignment.WithRight(visitedRhs);
			}
		}

		return Visit(thenAssignment.WithRight(condExpr)) as ExpressionSyntax
		       ?? thenAssignment.WithRight(condExpr);
	}

	public override SyntaxNode? VisitForStatement(ForStatementSyntax node)
	{
		var names = variables.Keys.ToImmutableHashSet();

		Visit(node.Declaration);

		var condition = Visit(node.Condition);

		if (TryGetLiteralValue(condition, out var value))
		{
			switch (value)
			{
				case false:
				{
					return null;
				}
				case true:
				{
					return TryUnrollForLoop(node);
				}
			}
		}

		return VisitForStatementWithoutUnroll(node, names);
	}

	/// <summary>
	/// Tries to unroll a for loop when the condition is always true.
	/// </summary>
	private SyntaxNode? TryUnrollForLoop(ForStatementSyntax node)
	{
		if (attribute.MaxUnrollIterations == 0)
		{
			InvalidateAssignedVariables(node);
			return base.VisitForStatement(node);
		}

		var result = new List<SyntaxNode?>();
		var iteratorCount = 0;

		do
		{
			if (iteratorCount++ >= attribute.MaxUnrollIterations)
			{
				InvalidateAssignedVariables(node);
				return base.VisitForStatement(node);
			}

			var statement = Visit(node.Statement);

			if (statement is not BlockSyntax)
			{
				result.Add(statement);
			}

			if (ShouldStopUnrolling(statement, result))
			{
				break;
			}

			VisitList(node.Incrementors);
		} while (TryGetLiteralValue(Visit(node.Condition), out var value) && value is true);

		return result.Count > 0 ? ToStatementSyntax(result) : null;
	}

	/// <summary>
	/// Visits a for statement without attempting to unroll it.
	/// </summary>
	private SyntaxNode VisitForStatementWithoutUnroll(ForStatementSyntax node, ImmutableHashSet<string> names)
	{
		// Restore variable states after visiting the loop
		foreach (var name in variables.Keys.Except(names).ToList())
		{
			variables.Remove(name);
		}

		var declaration = Visit(node.Declaration);
		InvalidateAssignedVariables(node);

		return node
			.WithInitializers(VisitList(node.Initializers))
			.WithCondition(Visit(node.Condition) as ExpressionSyntax ?? node.Condition)
			.WithDeclaration(declaration as VariableDeclarationSyntax ?? node.Declaration)
			.WithStatement(Visit(node.Statement) as StatementSyntax ?? node.Statement);
	}

	public override SyntaxNode? VisitWhileStatement(WhileStatementSyntax node)
	{
		var condition = Visit(node.Condition);

		if (TryGetLiteralValue(condition, out var value))
		{
			switch (value)
			{
				case false:
				{
					return null;
				}
				case true when attribute.MaxUnrollIterations > 0:
				{
					return TryUnrollWhileLoop(node);
				}
			}
		}

		InvalidateAssignedVariables(node);

		var body = Visit(node.Statement);
		var rewrittenCondition = Visit(node.Condition);

		if (body is BlockSyntax { Statements: [ .., BreakStatementSyntax or ReturnStatementSyntax ] items })
		{
			return IfStatement(
				rewrittenCondition as ExpressionSyntax ?? node.Condition,
				Block(items.Take(items.Count - 1)));
		}

		return node
			.WithCondition(rewrittenCondition as ExpressionSyntax ?? node.Condition)
			.WithStatement(body as StatementSyntax ?? node.Statement);
	}

	public override SyntaxNode? VisitDoStatement(DoStatementSyntax node)
	{
		// Do-while always executes at least once
		var result = new List<SyntaxNode?>();
		var iteratorCount = 0;

		do
		{
			if (iteratorCount++ >= attribute.MaxUnrollIterations)
			{
				InvalidateAssignedVariables(node);
				return base.VisitDoStatement(node);
			}

			var statement = Visit(node.Statement);

			if (statement is not BlockSyntax)
			{
				result.Add(statement);
			}

			if (ShouldStopUnrolling(statement, result))
			{
				break;
			}

			if (statement is BlockSyntax block)
			{
				result.AddRange(block.Statements);
			}
		} while (TryGetLiteralValue(Visit(node.Condition), out var value) && value is true);

		// Check final condition
		var finalCondition = Visit(node.Condition);

		if (TryGetLiteralValue(finalCondition, out var finalValue) && finalValue is false)
		{
			return result.Count > 0 ? ToStatementSyntax(result) : null;
		}

		InvalidateAssignedVariables(node);

		return base.VisitDoStatement(node);
	}

	/// <summary>
	/// Tries to unroll a while loop when the condition is always true.
	/// </summary>
	private SyntaxNode? TryUnrollWhileLoop(WhileStatementSyntax node)
	{
		var result = new List<SyntaxNode?>();
		var iteratorCount = 0;

		do
		{
			if (iteratorCount++ >= attribute.MaxUnrollIterations)
			{
				InvalidateAssignedVariables(node);
				return base.VisitWhileStatement(node);
			}

			var statement = Visit(node.Statement);

			if (statement is not BlockSyntax)
			{
				result.Add(statement);
			}

			if (ShouldStopUnrolling(statement, result))
			{
				break;
			}
		} while (TryGetLiteralValue(Visit(node.Condition), out var value) && value is true);

		return result.Count > 0 ? ToStatementSyntax(result) : null;
	}

	public override SyntaxNode? VisitForEachStatement(ForEachStatementSyntax node)
	{
		var names = variables.Keys.ToImmutableHashSet();
		var collection = Visit(node.Expression);

		var items = GetForEachItems(collection);

		if (items is not null && attribute.MaxUnrollIterations > 0 && items.Count < attribute.MaxUnrollIterations)
		{
			// Save state before attempting unrolling so we can roll back when conditional
			// breaks remain in the unrolled output (i.e., break inside an if whose
			// condition could not be resolved at compile time).
			var savedState = SaveVariableState();
			var unrolled = TryUnrollForEachLoop(node, items);

			// If the unrolled result still contains break statements that are not
			// protected by any inner loop or switch, the breaks are orphaned and
			// would produce invalid C#.  Fall back to a regular foreach, using the
			// constant-folded collection expression so that partial evaluation is
			// still applied where possible.
			if (ContainsOrphanedBreak(unrolled))
			{
				RestoreVariableState(savedState);
				InvalidateAssignedVariablesForForEach(node, names);
				return base.VisitForEachStatement(
					node.WithExpression(collection as ExpressionSyntax ?? node.Expression));
			}

			return unrolled;
		}

		InvalidateAssignedVariablesForForEach(node, names);

		return base.VisitForEachStatement(node);
	}

	/// <summary>
	/// Returns <see langword="true"/> when <paramref name="node"/> contains a
	/// <see cref="BreakStatementSyntax"/> that is not enclosed by any inner loop or
	/// switch statement, making it an orphaned break with no valid jump target.
	/// </summary>
	private static bool ContainsOrphanedBreak(SyntaxNode? node)
	{
		if (node is null)
		{
			return false;
		}

		return node
			.DescendantNodes(n =>
				n is not ForStatementSyntax
				and not ForEachStatementSyntax
				and not WhileStatementSyntax
				and not DoStatementSyntax
				and not SwitchStatementSyntax)
			.OfType<BreakStatementSyntax>()
			.Any();
	}

	/// <summary>
	/// Gets the items from a foreach collection expression.
	/// </summary>
	private IReadOnlyList<CSharpSyntaxNode>? GetForEachItems(SyntaxNode? collection)
	{
		return collection switch
		{
			CollectionExpressionSyntax collectionExpression => collectionExpression.Elements,
			LiteralExpressionSyntax { RawKind: (int) SyntaxKind.StringLiteralExpression } stringLiteral =>
				stringLiteral.Token.ValueText
					.Select(s => CreateLiteral(s) as CSharpSyntaxNode)
					.ToList(),
			_ => null
		};
	}

	/// <summary>
	/// Tries to unroll a foreach loop.
	/// </summary>
	private SyntaxNode? TryUnrollForEachLoop(ForEachStatementSyntax node, IReadOnlyList<CSharpSyntaxNode> items)
	{
		var name = node.Identifier.Text;

		if (semanticModel.GetOperation(node) is not IForEachLoopOperation operation)
		{
			return base.VisitForEachStatement(node);
		}

		var variable = new VariableItem(operation.LoopControlVariable.Type, true, null, true);
		variables.Add(name, variable);

		var statements = new List<SyntaxNode>();

		foreach (var item in items)
		{
			if (!TryGetLiteralValue(item, out var val))
			{
				continue;
			}

			variable.Value = val;
			var statement = Visit(node.Statement);

			if (statement is not BlockSyntax)
			{
				statements.Add(statement);
			}

			if (ShouldStopUnrolling(statement, statements))
			{
				break;
			}

			if (statement is BlockSyntax block)
			{
				statements.Add(block);
			}
		}

		var result = ToStatementSyntax(statements);

		// After unrolling, N consecutive equality-check if-statements with identical bodies
		// may be collapsed into a single combined if by CombineConsecutiveIfStatements
		// (e.g. "if (1==x){return true;} … if (5==x){return true;}" → "if (x is 1 or 5){return true;}").
		// Returning a single IfStatementSyntax (instead of a BlockSyntax wrapping N ifs) means
		// the parent VisitBlock will see the if as a direct sibling of the trailing "return false;"
		// and SimplifyIfReturnPatterns can then fold the pair into "return x is 1 or 5;".
		//
		// Guard: only combine when every if-statement's body unconditionally jumps
		// (return / break / continue / throw).  Without this guard, accumulation patterns like
		// "if (5==x) count++; if (5==x) count++;" (from arrays with duplicate values) would be
		// incorrectly merged into a single conditional that increments count only once.
		if (result is BlockSyntax resultBlock
		    && resultBlock.Statements.All(s => s is not IfStatementSyntax ifStmt
		                                       || ContainsJumpStatement(ifStmt.Statement)))
		{
			var combined = CombineConsecutiveIfStatements(resultBlock.Statements, Visit);
			result = combined.Count == 1 ? combined[0] : Block(combined);
		}

		return result;
	}

	/// <summary>
	/// Invalidates assigned variables for a foreach loop.
	/// </summary>
	private void InvalidateAssignedVariablesForForEach(ForEachStatementSyntax node, ImmutableHashSet<string> names)
	{
		var assignedVariables = AssignedVariables(node);

		foreach (var name in names)
		{
			if (variables.TryGetValue(name, out var variable) && assignedVariables.Contains(name))
			{
				variable.HasValue = false;
			}
		}
	}

	/// <summary>
	/// Checks if loop unrolling should stop based on the current statement.
	/// </summary>
	private static bool ShouldStopUnrolling(SyntaxNode? statement, ICollection<SyntaxNode?> result)
	{
		if (statement is BreakStatementSyntax or ReturnStatementSyntax)
		{
			return true;
		}

		if (statement is not BlockSyntax block || !block.Statements.Any(s => s is BreakStatementSyntax or ReturnStatementSyntax))
		{
			return false;
		}

		foreach (var item in block.Statements)
		{
			if (item is BreakStatementSyntax)
			{
				return true;
			}

			result.Add(item);

			if (item is ReturnStatementSyntax)
			{
				return true;
			}
		}

		return false;
	}

	/// <summary>
	/// Invalidates all assigned variables in the given node.
	/// </summary>
	private void InvalidateAssignedVariables(StatementSyntax node)
	{
		foreach (var name in AssignedVariables(node))
		{
			if (variables.TryGetValue(name, out var variable))
			{
				variable.HasValue = false;
			}
		}
	}

	public override SyntaxNode VisitBlock(BlockSyntax node)
	{
		var visited = VisitList(node.Statements);

		var untilThrown = TakeUntilThrownStatements(visited);
		var combined = CombineConsecutiveIfStatements(untilThrown, Visit);
		var mergedIfChain = MergeMixedBoolReturnIfs(combined, Visit);
		var simplified = SimplifyIfReturnPatterns(mergedIfChain);

		return node.WithStatements(simplified);
	}

	/// <summary>
	/// Takes statements until a throw or return statement is encountered (inclusive).
	/// Any code after a throw or return statement is unreachable and can be removed.
	/// </summary>
	private static SyntaxList<StatementSyntax> TakeUntilThrownStatements(SyntaxList<StatementSyntax> statements)
	{
		var result = new List<StatementSyntax>();

		foreach (var statement in statements)
		{
			result.Add(statement);

			// Stop after a throw or return statement since code after it is unreachable
			if (statement is ThrowStatementSyntax
			    or ExpressionStatementSyntax { Expression: ThrowExpressionSyntax }
			    or ReturnStatementSyntax)
			{
				break;
			}
		}

		// Strip a trailing void return (return;) — it is redundant at the end of a void block
		// and produces cleaner output (e.g. empty body {} instead of { return; }).
		if (result.Count > 0 && result[^1] is ReturnStatementSyntax { Expression: null })
		{
			result.RemoveAt(result.Count - 1);
		}

		return List(result);
	}

	/// <summary>
	/// Simplifies patterns like:
	/// - if (cond) { return true; } return false; => return cond;
	/// - if (cond) { return false; } return true; => return !cond;
	/// </summary>
	private SyntaxList<StatementSyntax> SimplifyIfReturnPatterns(SyntaxList<StatementSyntax> statements)
	{
		if (statements.Count < 2)
		{
			return statements;
		}

		var result = new List<StatementSyntax>();

		for (var i = 0; i < statements.Count; i++)
		{
			// Check for pattern: if (cond) { return <bool>; } followed by return <opposite bool>;
			if (i + 1 < statements.Count
			    && statements[i] is IfStatementSyntax { Else: null } ifStatement
			    && statements[i + 1] is ReturnStatementSyntax followingReturn)
			{
				if (TryGetIfReturnBoolPattern(ifStatement, followingReturn, out var simplifiedReturn)
				    || TryGetIfReturnPattern(ifStatement, followingReturn, out simplifiedReturn))
				{
					result.Add(simplifiedReturn!);
					i++; // Skip the following return statement
					continue;
				}
			}

			result.Add(statements[i]);
		}

		var resultList = List(result);

		if (statements.Count != resultList.Count)
		{
			return SimplifyIfReturnPatterns(resultList);
		}

		return resultList;
	}

	/// <summary>
	/// Tries to simplify if-return-bool patterns.
	/// </summary>
	private bool TryGetIfReturnBoolPattern(IfStatementSyntax ifStatement, ReturnStatementSyntax followingReturn, out ReturnStatementSyntax? simplified)
	{
		simplified = null;

		// Get the return statement from the if body
		var ifBody = ifStatement.Statement;

		var ifReturn = ifBody switch
		{
			ReturnStatementSyntax ret => ret,
			BlockSyntax { Statements: [ ReturnStatementSyntax ret ] } => ret,
			_ => null
		};

		if (ifReturn is null)
		{
			return false;
		}

		// Check if both returns are boolean literals
		if (!TryGetBoolLiteral(ifReturn.Expression, out var ifReturnValue))
		{
			return false;
		}

		// Only simplify if they return opposite values
		if (SyntaxNodeComparer.Get().Equals(ifReturn.Expression, followingReturn.Expression))
		{
			return false;
		}

		// if (cond) { return true; } return false; => return cond;
		// if (cond) { return false; } return true; => return !cond;
		var condition = ifStatement.Condition;

		if (ifReturnValue)
		{
			if (followingReturn.Expression is LiteralExpressionSyntax { RawKind: (int) SyntaxKind.FalseLiteralExpression })
			{
				// return cond;
				simplified = ReturnStatement(condition);
			}
			else
			{
				var newCondition = LogicalAndExpression(condition, followingReturn.Expression);
				var booleanType = semanticModel.Compilation.CreateBoolean();

				if (TryOptimizeNode(BinaryOperatorKind.ConditionalAnd, [ ], booleanType, condition, booleanType, followingReturn.Expression, booleanType, null, out var result))
				{
					simplified = ReturnStatement(result as ExpressionSyntax ?? condition);
					return true;
				}

				simplified = ReturnStatement(newCondition);
			}
		}
		else if (InvertLogicalRefactoring.TryInvertLogical(condition as BinaryExpressionSyntax, out var inverted))
		{
			var booleanType = semanticModel.Compilation.CreateBoolean();

			if (TryOptimizeNode(BinaryOperatorKind.ConditionalAnd, [ ], booleanType, inverted, booleanType, followingReturn.Expression, booleanType, null, out var result))
			{
				simplified = ReturnStatement(result as ExpressionSyntax ?? condition);
				return true;
			}

			simplified = ReturnStatement(LogicalAndExpression(inverted, followingReturn.Expression));
		}
		else
		{
			var booleanType = semanticModel.Compilation.CreateBoolean();
			var invertedCondition = NegateExpressionRefactoring.Negate(condition);

			if (TryOptimizeNode(BinaryOperatorKind.ConditionalAnd, [ ], booleanType, invertedCondition, booleanType, followingReturn.Expression, booleanType, null, out var result))
			{
				simplified = ReturnStatement(result as ExpressionSyntax ?? condition);
				return true;
			}

			simplified = ReturnStatement(LogicalAndExpression(invertedCondition, followingReturn.Expression));
		}

		return simplified is not null;
	}

	/// <summary>
	/// Tries to simplify if-return-bool patterns.
	/// </summary>
	private bool TryGetIfReturnPattern(IfStatementSyntax ifStatement, ReturnStatementSyntax followingReturn, out ReturnStatementSyntax? simplified)
	{
		simplified = null;

		// Get the return statement from the if body
		var ifBody = ifStatement.Statement;

		var ifReturn = ifBody switch
		{
			ReturnStatementSyntax ret => ret,
			BlockSyntax { Statements: [ ReturnStatementSyntax ret ] } => ret,
			_ => null
		};

		if (ifReturn is null)
		{
			return false;
		}

		simplified = ReturnStatement(Visit(
			ConditionalExpression(
				ifStatement.Condition,
				ifReturn.Expression,
				followingReturn.Expression)) as ExpressionSyntax ?? ifReturn.Expression);

		return true;
	}

	/// <summary>
	/// Tries to extract a boolean literal value from an expression.
	/// </summary>
	private static bool TryGetBoolLiteral(ExpressionSyntax? expression, out bool value)
	{
		value = false;

		if (expression is LiteralExpressionSyntax literal)
		{
			if (literal.IsKind(SyntaxKind.TrueLiteralExpression))
			{
				value = true;
				return true;
			}

			if (literal.IsKind(SyntaxKind.FalseLiteralExpression))
			{
				value = false;
				return true;
			}
		}

		return false;
	}

	/// <summary>
	/// Merges a consecutive run of if-statements (each returning a boolean literal, no else)
	/// that contains a mix of <c>return true</c> and <c>return false</c> into a single
	/// <c>if (...) return false;</c> statement.
	/// <para>
	/// For each if-statement in the run:
	/// <list type="bullet">
	///   <item>If it returns <c>false</c> → its condition is added to the OR chain as-is.</item>
	///   <item>If it returns <c>true</c>  → its condition is negated and added to the OR chain,
	///     because reaching a subsequent <c>return false</c> requires the <c>return true</c>
	///     guard to have been skipped (i.e., its condition was false).</item>
	/// </list>
	/// </para>
	/// Example:
	/// <code>
	/// if (n &lt;= 1) return false;
	/// if (n &lt;= 3) return true;
	/// if (IsEven(n) || n % 3 == 0) return false;
	/// </code>
	/// becomes:
	/// <code>
	/// if (n &lt;= 1 || n &gt; 3 || IsEven(n) || n % 3 == 0) return false;
	/// </code>
	/// </summary>
	private static SyntaxList<StatementSyntax> MergeMixedBoolReturnIfs(SyntaxList<StatementSyntax> statements, Func<SyntaxNode?, SyntaxNode?> visit)
	{
		if (statements.Count < 2)
		{
			return statements;
		}

		var result = new List<StatementSyntax>();
		var i = 0;

		while (i < statements.Count)
		{
			var runStart = i;
			var run = new List<(ExpressionSyntax Condition, bool ReturnValue)>();

			while (i < statements.Count && TryGetIfBoolReturnBody(statements[i], out var cond, out var retVal))
			{
				run.Add((cond!, retVal));
				i++;
			}

			// Only merge when there are at least 2 ifs with mixed true/false returns
			if (run.Count >= 2 && run.Any(r => r.ReturnValue) && run.Any(r => !r.ReturnValue))
			{
				// Build combined OR condition:
				// - "return false" conditions → keep as-is
				// - "return true" conditions → negate (they act as guards; skipping them means we fall through to the false path)
				ExpressionSyntax? combined = null;

				foreach (var (cond, retVal) in run)
				{
					var part = retVal ? NegateCondition(cond) : cond;

					if (combined is null)
					{
						combined = part;
					}
					else
					{
						combined = LogicalOrExpression(
							NeedsParenthesesInOrContext(combined) ? ParenthesizedExpression(combined) : combined,
							NeedsParenthesesInOrContext(part) ? ParenthesizedExpression(part) : part);
					}
				}

				var visitedCombined = visit(combined) as ExpressionSyntax ?? combined!;

				result.Add(IfStatement(
					visitedCombined,
					ReturnStatement(LiteralExpression(SyntaxKind.FalseLiteralExpression))));
			}
			else if (run.Count > 0)
			{
				// Run is all-same-value — add back unchanged
				for (var k = runStart; k < runStart + run.Count; k++)
				{
					result.Add(statements[k]);
				}
			}
			else
			{
				// Current statement is not a bool-return if — add it as-is and advance
				result.Add(statements[i]);
				i++;
			}
		}

		return List(result);
	}

	/// <summary>
	/// Tries to extract the condition and boolean return value from an if-statement whose body
	/// is a single <c>return true;</c> or <c>return false;</c> (with or without braces) and
	/// that has no else clause.
	/// </summary>
	private static bool TryGetIfBoolReturnBody(
		StatementSyntax statement,
		out ExpressionSyntax? condition,
		out bool returnValue)
	{
		condition = null;
		returnValue = false;

		if (statement is not IfStatementSyntax { Else: null } ifStmt)
		{
			return false;
		}

		var ret = ifStmt.Statement switch
		{
			ReturnStatementSyntax r => r,
			BlockSyntax { Statements: [ ReturnStatementSyntax r ] } => r,
			_ => null
		};

		if (ret?.Expression is not LiteralExpressionSyntax lit)
		{
			return false;
		}

		if (lit.IsKind(SyntaxKind.TrueLiteralExpression))
		{
			condition = ifStmt.Condition;
			returnValue = true;
			return true;
		}

		if (lit.IsKind(SyntaxKind.FalseLiteralExpression))
		{
			condition = ifStmt.Condition;
			returnValue = false;
			return true;
		}

		return false;
	}

	/// <summary>
	/// Negates a condition, preferring a direct inversion (e.g., <c>n &lt;= 3</c> → <c>n &gt; 3</c>)
	/// over wrapping in <c>!(…)</c>.
	/// </summary>
	private static ExpressionSyntax NegateCondition(ExpressionSyntax condition)
	{
		if (InvertLogicalRefactoring.TryInvertLogical(condition as BinaryExpressionSyntax, out var inverted))
		{
			return inverted;
		}

		return NegateExpressionRefactoring.Negate(condition);
	}

	/// <summary>
	/// Combines consecutive if statements that have identical bodies into a single if statement.
	/// Two strategies are applied in order:
	/// 1. Equality pattern: conditions of the form <c>x == literal</c> against the same variable
	///    are combined into <c>if (x is 1 or 5) { … }</c>.
	/// 2. General ||: when the body ends with a jump statement (return / break / continue / throw),
	///    any consecutive if statements with an identical body are combined using <c>||</c>.
	/// Example (strategy 1): if (1 == x) { return true; } if (5 == x) { return true; }
	///                     => if (x is 1 or 5) { return true; }
	/// Example (strategy 2): if (x &gt; 5) { return; } if (y &lt; 3) { return; }
	///                     => if (x &gt; 5 || y &lt; 3) { return; }
	/// </summary>
	internal static SyntaxList<StatementSyntax> CombineConsecutiveIfStatements(SyntaxList<StatementSyntax> statements, Func<SyntaxNode?, SyntaxNode?> visit)
	{
		if (statements.Count < 2)
		{
			return statements;
		}

		var result = new List<StatementSyntax>();
		var i = 0;

		while (i < statements.Count)
		{
			// Only process if statements without an else clause
			if (statements[i] is not IfStatementSyntax { Else: null } currentIf)
			{
				result.Add(statements[i]);
				i++;

				continue;
			}

			// Strategy 1: equality (is or) combination
			if (TryGetEqualityComparisonInfo(currentIf.Condition, out var targetIdentifier, out var firstLiteral))
			{
				var literals = new List<LiteralExpressionSyntax> { firstLiteral! };
				var j = i + 1;

				while (j < statements.Count)
				{
					if (statements[j] is not IfStatementSyntax { Else: null } nextIf)
					{
						break;
					}

					if (!SyntaxNodeComparer.Get<StatementSyntax>().Equals(nextIf.Statement, currentIf.Statement))
					{
						break;
					}

					if (!TryGetEqualityComparisonInfo(nextIf.Condition, out var nextTarget, out var nextLiteral)
					    || nextTarget != targetIdentifier)
					{
						break;
					}

					literals.Add(nextLiteral!);
					j++;
				}

				if (literals.Count > 1)
				{
					// e.g. target is 1 or 5 or 10
					var combinedCondition = visit(CreateIsOrPattern(targetIdentifier!, literals)) as ExpressionSyntax;
					result.Add(currentIf.WithCondition(combinedCondition));
					i = j;
					continue;
				}
			}

			// Strategy 2: general || combination when body ends with a jump statement
			if (ContainsJumpStatement(currentIf.Statement))
			{
				var conditions = new List<ExpressionSyntax> { currentIf.Condition };
				var j = i + 1;

				while (j < statements.Count)
				{
					if (statements[j] is not IfStatementSyntax { Else: null } nextIf)
					{
						break;
					}

					if (!SyntaxNodeComparer.Get<StatementSyntax>().Equals(nextIf.Statement, currentIf.Statement))

					{
						break;
					}

					conditions.Add(nextIf.Condition);
					j++;
				}

				if (conditions.Count > 1)
				{
					var combinedCondition = conditions[0];

					for (var k = 1; k < conditions.Count; k++)
					{
						combinedCondition = LogicalOrExpression(
							NeedsParenthesesInOrContext(combinedCondition)
								? ParenthesizedExpression(combinedCondition)
								: combinedCondition,
							NeedsParenthesesInOrContext(conditions[k])
								? ParenthesizedExpression(conditions[k])
								: conditions[k]);
					}

					result.Add(currentIf.WithCondition(combinedCondition));
					i = j;
					continue;
				}
			}

			result.Add(statements[i]);
			i++;
		}

		return List(result);
	}

	/// <summary>
	/// Returns <see langword="true"/> when a statement unconditionally ends with a jump
	/// (return, break, continue, or throw), making it safe to combine consecutive if
	/// statements with identical bodies using <c>||</c>.
	/// </summary>
	private static bool ContainsJumpStatement(StatementSyntax statement) =>
		statement switch
		{
			ReturnStatementSyntax => true,
			BreakStatementSyntax => true,
			ContinueStatementSyntax => true,
			ThrowStatementSyntax => true,
			BlockSyntax block => block.Statements.Count > 0 && ContainsJumpStatement(block.Statements.Last()),
			_ => false
		};

	/// <summary>
	/// Returns <see langword="true"/> when an expression needs parentheses when used as an
	/// operand of <c>||</c> (i.e., its precedence is lower than logical-or).
	/// </summary>
	private static bool NeedsParenthesesInOrContext(ExpressionSyntax expression) =>
		expression is ConditionalExpressionSyntax or AssignmentExpressionSyntax;

	/// <summary>
	/// Creates an 'is' pattern expression with 'or' for multiple values.
	/// Example: target is 1 or 5 or 10
	/// </summary>
	private static ExpressionSyntax CreateIsOrPattern(string targetIdentifier, List<LiteralExpressionSyntax> literals)
	{
		// Build pattern: 1 or 5 or 10 or ...
		PatternSyntax pattern = ConstantPattern(literals[0]);

		for (var k = 1; k < literals.Count; k++)
		{
			pattern = BinaryPattern(
				SyntaxKind.OrPattern,
				pattern,
				ConstantPattern(literals[k]));
		}

		// Create: target is <pattern>
		return IsPatternExpression(
			IdentifierName(targetIdentifier),
			pattern);
	}

	/// <summary>
	/// Tries to extract the comparison target identifier and literal value from an equality expression.
	/// Handles both 'value == target' and 'target == value' formats.
	/// </summary>
	private static bool TryGetEqualityComparisonInfo(ExpressionSyntax condition, out string? targetIdentifier, out LiteralExpressionSyntax? literal)
	{
		targetIdentifier = null;
		literal = null;

		if (condition is not BinaryExpressionSyntax binary
		    || !binary.IsKind(SyntaxKind.EqualsExpression))
		{
			return false;
		}

		switch (binary)
		{
			// Check if left side is identifier and right side is literal
			case { Left: IdentifierNameSyntax leftId, Right: LiteralExpressionSyntax rightLit }:
			{
				targetIdentifier = leftId.Identifier.Text;
				literal = rightLit;
				return true;
			}
			// Check if right side is identifier and left side is literal
			case { Right: IdentifierNameSyntax rightId, Left: LiteralExpressionSyntax leftLit }:
			{
				targetIdentifier = rightId.Identifier.Text;
				literal = leftLit;
				return true;
			}
			default:
			{
				return false;
			}
		}
	}

	public override SyntaxNode? VisitReturnStatement(ReturnStatementSyntax node)
	{
		var visitedExpression = Visit(node.Expression);

		// If the return expression is parenthesized, unwrap it to avoid returning nested parentheses that can interfere with pattern matching and other optimizations.
		if (visitedExpression is ParenthesizedExpressionSyntax parenthesized)
		{
			visitedExpression = parenthesized.Expression;
		}

		if (visitedExpression is ThrowExpressionSyntax throwExpression)
		{
			return ThrowStatement(throwExpression.Expression);
		}

		return node.WithExpression(visitedExpression as ExpressionSyntax);
	}

	public override SyntaxNode? VisitLocalDeclarationStatement(LocalDeclarationStatementSyntax node)
	{
		var visited = Visit(node.Declaration);

		return visited switch
		{
			null => null,
			BlockSyntax block => block,
			VariableDeclarationSyntax declaration => node.WithDeclaration(declaration),
			ExpressionStatementSyntax expressionStatement => expressionStatement,
			ThrowStatementSyntax throwStatement => throwStatement,
			_ => node
		};
	}
}

using BenchmarkDotNet.Attributes;

namespace FastPowBench;

[MemoryDiagnoser]
public class FastPowBenchmark
{
    private float[] _floatBaseData = null!;
    private float[] _floatExpData = null!;
    private double[] _doubleBaseData = null!;
    private double[] _doubleExpData = null!;
    private const int N = 1000;

    [GlobalSetup]
    public void Setup()
    {
        var random = new Random(42);
        _floatBaseData = new float[N];
        _floatExpData = new float[N];
        _doubleBaseData = new double[N];
        _doubleExpData = new double[N];

        for (var i = 0; i < N; i++)
        {
            var baseValue = random.NextDouble() * 10 + 0.1; // Range [0.1, 10.1]
            var expValue = random.NextDouble() * 6 - 3; // Range [-3, 3]

            _floatBaseData[i] = (float)baseValue;
            _floatExpData[i] = (float)expValue;
            _doubleBaseData[i] = baseValue;
            _doubleExpData[i] = expValue;
        }
    }

    // Float benchmarks
    [Benchmark(Baseline = true)]
    public float MathPow_Float()
    {
        var sum = 0f;
        for (var i = 0; i < N; i++)
        {
            sum += MathF.Pow(_floatBaseData[i], _floatExpData[i]);
        }
        return sum;
    }

    [Benchmark]
    public float FastPow_Float()
    {
        var sum = 0f;
        for (var i = 0; i < N; i++)
        {
            sum += FastPow(_floatBaseData[i], _floatExpData[i]);
        }
        return sum;
    }

    // Double benchmarks
    [Benchmark]
    public double MathPow_Double()
    {
        var sum = 0.0;
        for (var i = 0; i < N; i++)
        {
            sum += Math.Pow(_doubleBaseData[i], _doubleExpData[i]);
        }
        return sum;
    }

    [Benchmark]
    public double FastPow_Double()
    {
        var sum = 0.0;
        for (var i = 0; i < N; i++)
        {
            sum += FastPow(_doubleBaseData[i], _doubleExpData[i]);
        }
        return sum;
    }

    // FastPow implementation for float
    private static float FastPow(float x, float y)
    {
        // Handle special cases (keep minimal and predictable)
        if (y == 0.0f || x == 1.0f) return 1.0f;
        if (x <= 0.0f) return Single.NaN; // consistent with fast-math approximation path

        // Range reduction: x = m * 2^e with m in [1,2)
        var ibits = BitConverter.SingleToInt32Bits(x);
        var iexp = ((ibits >> 23) & 0xFF) - 127; // unbiased exponent
        var imant = ibits & 0x7FFFFF;
        var m = 1.0f + (imant * (1.0f / 8388608.0f)); // 2^23

        // log2(m) via ln(m) ≈ 2*(z + z^3/3 + z^5/5 + z^7/7), z = (m-1)/(m+1) ∈ [0, 1/3]
        const float INV_LN2 = 1.4426950408889634f; // 1/ln(2)
        var z = (m - 1.0f) / (m + 1.0f);
        var t2 = z * z; // z^2
        // Horner: z * (1 + t2/3 + t2^2/5 + t2^3/7)
        var sInner = Single.FusedMultiplyAdd(1f / 7f, t2, 1f / 5f);
        sInner = Single.FusedMultiplyAdd(sInner, t2, 1f / 3f);
        sInner = Single.FusedMultiplyAdd(sInner, t2, 1f);
        var ln_m = 2.0f * (z * sInner);
        var log2m = ln_m * INV_LN2;
        var log2x = iexp + log2m;

        var t = y * log2x;

        // exp2(t): split into k + f with f in [-0.5, 0.5) for better poly accuracy
        var kf = Single.Floor(t + 0.5f);
        var k = (int)kf;
        var f = t - kf;

        // 2^f ≈ e^(ln2*f), 7th order Taylor around 0
        const float LN2 = 0.6931471805599453f;
        var u = LN2 * f;
        // Horner with FMA: ((((((1/5040)u + 1/720)u + 1/120)u + 1/24)u + 1/6)u + 1/2)u + 1; then add final +u term fused
        var p = 1f / 5040f;
        p = Single.FusedMultiplyAdd(p, u, 1f / 720f);
        p = Single.FusedMultiplyAdd(p, u, 1f / 120f);
        p = Single.FusedMultiplyAdd(p, u, 1f / 24f);
        p = Single.FusedMultiplyAdd(p, u, 1f / 6f);
        p = Single.FusedMultiplyAdd(p, u, 0.5f);
        p = Single.FusedMultiplyAdd(p, u, 1f);
        var exp2f = Single.FusedMultiplyAdd(p, u, 1f);

        // Scale by 2^k via exponent bits (mantissa = 1.0)
        var expBits = (k + 127) << 23;
        var scale = BitConverter.Int32BitsToSingle(expBits);
        return exp2f * scale;
    }

    // FastPow implementation for double
    private static double FastPow(double x, double y)
    {
        // Handle special cases (keep minimal and predictable)
        if (y == 0.0 || x == 1.0) return 1.0;
        if (x <= 0.0) return Double.NaN;

        // Range reduction: x = m * 2^e with m in [1,2)
        var bits = BitConverter.DoubleToInt64Bits(x);
        var iexp = (int)((bits >> 52) & 0x7FF) - 1023; // unbiased exponent
        var imant = bits & 0x000F_FFFF_FFFF_FFFFL; // 52-bit mantissa
        var m = 1.0 + (imant * (1.0 / 4503599627370496.0)); // 2^52

        // log2(m) via ln(m) ≈ 2*(z + z^3/3 + z^5/5 + z^7/7)
        const double INV_LN2 = 1.4426950408889634073599; // 1/ln(2)
        var z = (m - 1.0) / (m + 1.0);
        var t2 = z * z;
        // Horner: z * (1 + t2/3 + t2^2/5 + t2^3/7)
        var sInner = Double.FusedMultiplyAdd(1.0 / 7.0, t2, 1.0 / 5.0);
        sInner = Double.FusedMultiplyAdd(sInner, t2, 1.0 / 3.0);
        sInner = Double.FusedMultiplyAdd(sInner, t2, 1.0);
        var ln_m = 2.0 * (z * sInner);
        var log2m = ln_m * INV_LN2;
        var log2x = iexp + log2m;

        var t = y * log2x;

        // exp2(t): k + f with f in [-0.5, 0.5)
        var kf = Double.Floor(t + 0.5);
        var k = (int)kf;
        var f = t - kf;

        // 2^f ≈ e^(ln2*f), 7th order Taylor
        const double LN2 = 0.6931471805599453094172;
        var u = LN2 * f;
        var p = 1.0 / 5040.0;
        p = Double.FusedMultiplyAdd(p, u, 1.0 / 720.0);
        p = Double.FusedMultiplyAdd(p, u, 1.0 / 120.0);
        p = Double.FusedMultiplyAdd(p, u, 1.0 / 24.0);
        p = Double.FusedMultiplyAdd(p, u, 1.0 / 6.0);
        p = Double.FusedMultiplyAdd(p, u, 0.5);
        p = Double.FusedMultiplyAdd(p, u, 1.0);
        var exp2f = Double.FusedMultiplyAdd(p, u, 1.0);

        // Scale by 2^k using exponent bits
        var expBits = ((long)(k + 1023) & 0x7FFL) << 52;
        var scale = BitConverter.Int64BitsToDouble(expBits);
        return exp2f * scale;
    }
}

using TUnit.Core;

namespace ConstExpr.Tests;

internal class Program
{
	public static async Task Main(string[] args)
	{
		await TUnitTestRunner.RunAsync(args);
	}
}

namespace ConstExpr.Tests.Tests;

public class DivisionParenthesisTest : BaseTest<double>
{
	public override IEnumerable<double> Result => [25.0];

	public override string SourceCode => """
		using System.Collections.Generic;
		using ConstExpr.Core.Attributes;

		namespace Testing;

		public static class Classes
		{
			public static void Test()
			{
				Run();
			}

			[ConstExpr]
			public static IEnumerable<double> Run()
			{
				var verticalVelocity = 10.0;
				var gravity = 2.0;
				// This should remain: verticalVelocity * verticalVelocity / (2 * gravity)
				// = 100 / (2 * 2) = 100 / 4 = 25
				// NOT become: verticalVelocity * verticalVelocity / 2 * gravity
				// = 100 / 2 * 2 = 50 * 2 = 100 (WRONG!)
				yield return (verticalVelocity * verticalVelocity) / (2 * gravity);
			}
		}
		""";
}

using System;
using ConstExpr.Core;

namespace TestForLoopFix
{
    public class ForLoopTest
    {
        // Test for loop with i++
        [ConstExpr]
        public static int SumWithPostfixIncrement(int n)
        {
            var sum = 0;
            for (var i = 0; i < n; i++)
            {
                sum += i;
            }
            return sum;
        }

        // Test for loop with ++i
        [ConstExpr]
        public static int SumWithPrefixIncrement(int n)
        {
            var sum = 0;
            for (var i = 0; i < n; ++i)
            {
                sum += i;
            }
            return sum;
        }

        // Test for loop with i--
        [ConstExpr]
        public static int CountdownSum(int n)
        {
            var sum = 0;
            for (var i = n; i > 0; i--)
            {
                sum += i;
            }
            return sum;
        }

        // Test for loop with multiple incrementors
        [ConstExpr]
        public static int MultipleIncrementors()
        {
            var sum = 0;
            for (var i = 0, j = 10; i < 5; i++, j--)
            {
                sum += i + j;
            }
            return sum;
        }

        public static void Main()
        {
            Console.WriteLine("=== FOR LOOP INCREMENT/DECREMENT TESTS ===\n");

            Console.WriteLine($"SumWithPostfixIncrement(5) = {SumWithPostfixIncrement(5)}");
            Console.WriteLine($"Expected: {0 + 1 + 2 + 3 + 4} (sum of 0..4)\n");

            Console.WriteLine($"SumWithPrefixIncrement(5) = {SumWithPrefixIncrement(5)}");
            Console.WriteLine($"Expected: {0 + 1 + 2 + 3 + 4} (sum of 0..4)\n");

            Console.WriteLine($"CountdownSum(5) = {CountdownSum(5)}");
            Console.WriteLine($"Expected: {5 + 4 + 3 + 2 + 1} (sum of 5..1)\n");

            Console.WriteLine($"MultipleIncrementors() = {MultipleIncrementors()}");
            Console.WriteLine($"Expected: {(0+10) + (1+9) + (2+8) + (3+7) + (4+6)}\n");
        }
    }
}

using System;
using ConstExpr.Core;

namespace TestLoopVariableRestore
{
    public class LoopVariableRestoreTest
    {
        // Test that variables modified in while loop are properly handled
        [ConstExpr]
        public static int WhileLoopVariableTest()
        {
            var counter = 0;
            var sum = 0;

            while (counter < 5)
            {
                sum += counter;
                counter++;
            }

            // After the loop, counter and sum should not be treated as constants
            // since we don't know how many iterations happened
            return sum + counter; // Should be 10 + 5 = 15
        }

        // Test that variables modified in for loop are properly handled
        [ConstExpr]
        public static int ForLoopVariableTest()
        {
            var sum = 0;

            for (var i = 0; i < 5; i++)
            {
                sum += i;
            }

            // After the loop, sum should not be treated as constant
            return sum; // Should be 0 + 1 + 2 + 3 + 4 = 10
        }

        // Test that variables modified in foreach loop are properly handled
        [ConstExpr]
        public static int ForEachLoopVariableTest()
        {
            var sum = 0;
            var numbers = new[] { 1, 2, 3, 4, 5 };

            foreach (var num in numbers)
            {
                sum += num;
            }

            // After the loop, sum should not be treated as constant
            return sum; // Should be 1 + 2 + 3 + 4 + 5 = 15
        }

        // Test nested loops
        [ConstExpr]
        public static int NestedLoopsTest()
        {
            var sum = 0;

            for (var i = 0; i < 3; i++)
            {
                for (var j = 0; j < 3; j++)
                {
                    sum += i * j;
                }
            }

            return sum; // Should be 0*0 + 0*1 + 0*2 + 1*0 + 1*1 + 1*2 + 2*0 + 2*1 + 2*2 = 9
        }

        public static void Main()
        {
            Console.WriteLine("=== LOOP VARIABLE RESTORE TESTS ===\n");

            var result1 = WhileLoopVariableTest();
            Console.WriteLine($"WhileLoopVariableTest() = {result1}");
            Console.WriteLine($"Expected: 15\n");

            var result2 = ForLoopVariableTest();
            Console.WriteLine($"ForLoopVariableTest() = {result2}");
            Console.WriteLine($"Expected: 10\n");

            var result3 = ForEachLoopVariableTest();
            Console.WriteLine($"ForEachLoopVariableTest() = {result3}");
            Console.WriteLine($"Expected: 15\n");

            var result4 = NestedLoopsTest();
            Console.WriteLine($"NestedLoopsTest() = {result4}");
            Console.WriteLine($"Expected: 9\n");

            // Verify all tests passed
            if (result1 == 15 && result2 == 10 && result3 == 15 && result4 == 9)
            {
                Console.WriteLine("✅ All tests passed!");
            }
            else
            {
                Console.WriteLine("❌ Some tests failed!");
            }
        }
    }
}

using System;
using System.Collections.Generic;
using System.Collections.Immutable;
using System.Linq;
using System.Threading;
using ConstExpr.SourceGenerator.Enums;
using ConstExpr.SourceGenerator.Models;
using Microsoft.CodeAnalysis;
using Microsoft.CodeAnalysis.CSharp;
using Microsoft.CodeAnalysis.CSharp.Syntax;

namespace ConstExpr.SourceGenerator.Visitors;

/// <summary>
/// Analyzes a syntax node (method body, block, or loop) to determine whether
/// it is eligible for auto-vectorization using SIMD intrinsics.
///
/// A node is considered vectorizable when it contains at least one loop that:
/// <list type="bullet">
///   <item>Iterates over a numeric array or <c>Span&lt;T&gt;</c> / <c>ReadOnlySpan&lt;T&gt;</c></item>
///   <item>Works with element types that map to a SIMD vector lane (byte, short, int, long, float, double, …)</item>
///   <item>Uses only element-wise arithmetic, bitwise, or comparison operations</item>
///   <item>Has no loop-carried data dependences (no <c>arr[i-1]</c>-style cross-iteration reads)</item>
///   <item>Contains no unsupported control flow inside the hot loop (no <c>goto</c>, no <c>yield</c>)</item>
///   <item>Does not call non-vectorizable methods in the loop body</item>
/// </list>
/// </summary>
public sealed class VectorizationEligibilityVisitor : CSharpSyntaxWalker
{
    // -------------------------------------------------------------------------
    // Supported element SpecialTypes — these are the types that map directly
    // to SIMD vector lanes on all major platforms.
    // -------------------------------------------------------------------------
    private static readonly ImmutableHashSet<SpecialType> VectorizableElementTypes =
        ImmutableHashSet.Create(
            SpecialType.System_Byte,
            SpecialType.System_SByte,
            SpecialType.System_Int16,
            SpecialType.System_UInt16,
            SpecialType.System_Int32,
            SpecialType.System_UInt32,
            SpecialType.System_Int64,
            SpecialType.System_UInt64,
            SpecialType.System_Single,
            SpecialType.System_Double
        );

    // Element-type metadata names for Span / ReadOnlySpan detection
    private static readonly ImmutableHashSet<string> SpanTypeNames =
        ImmutableHashSet.Create(
            StringComparer.Ordinal,
            "System.Span`1",
            "System.ReadOnlySpan`1",
            "System.Memory`1",
            "System.ReadOnlyMemory`1"
        );

    // Intrinsic / pure math methods that have direct SIMD equivalents and
    // are therefore safe to use inside a vectorizable loop body.
    private static readonly ImmutableHashSet<string> VectorizableMathMethods =
        ImmutableHashSet.Create(
            StringComparer.Ordinal,
            "System.Math.Abs",
            "System.Math.Min",
            "System.Math.Max",
            "System.Math.Sqrt",
            "System.Math.Floor",
            "System.Math.Ceiling",
            "System.Math.Round",
            "System.MathF.Abs",
            "System.MathF.Min",
            "System.MathF.Max",
            "System.MathF.Sqrt",
            "System.MathF.Floor",
            "System.MathF.Ceiling",
            "System.MathF.Round"
        );

    // -------------------------------------------------------------------------
    // State
    // -------------------------------------------------------------------------

    private readonly SemanticModel _model;
    private readonly CancellationToken _ct;
    private readonly List<string> _reasons = [];

    // The set of loop variable names that act as a simple counter (for int i = 0; i < n; i++)
    private HashSet<string> _loopCounterNames = [];

    // Tracks whether we are currently inside a supported loop
    private bool _insideVectorizableLoop;

    // Tracks whether any vectorizable loop was found
    private bool _foundVectorizableLoop;

    // The element type found in the innermost loop, used to select a vector width
    private SpecialType _elementType = SpecialType.None;

    // -------------------------------------------------------------------------
    // Public API
    // -------------------------------------------------------------------------

    private VectorizationEligibilityVisitor(SemanticModel model, CancellationToken ct)
        : base(SyntaxWalkerDepth.Node)
    {
        _model = model;
        _ct = ct;
    }

    /// <summary>
    /// Analyzes the given <paramref name="node"/> and returns a
    /// <see cref="VectorizationResult"/> describing whether vectorization is applicable.
    /// </summary>
    public static VectorizationResult Analyze(SyntaxNode node, SemanticModel model, CancellationToken ct = default)
    {
        var visitor = new VectorizationEligibilityVisitor(model, ct);
        visitor.Visit(node);
        return visitor.BuildResult();
    }

    // -------------------------------------------------------------------------
    // Loop detection
    // -------------------------------------------------------------------------

    public override void VisitForStatement(ForStatementSyntax node)
    {
        if (_ct.IsCancellationRequested)
        {
            return;
        }

        // Detect canonical counting pattern: for (var i = 0; i < n; i++) or (int i = 0; i < n; i++)
        if (!TryExtractCounterVariable(node, out var counterName))
        {
            // Not a simple counted loop — record reason and continue walking children
            // so we can still detect an inner loop that might be vectorizable.
            _reasons.Add($"Loop at line {node.GetLocation().GetLineSpan().StartLinePosition.Line + 1} does not follow a simple counter pattern (int i = 0; i < n; i++).");
            base.VisitForStatement(node);
            return;
        }

        _loopCounterNames.Add(counterName);
        var wasInside = _insideVectorizableLoop;
        _insideVectorizableLoop = true;

        // Analyze the body
        var bodyAnalyzer = new LoopBodyAnalyzer(_model, _loopCounterNames, VectorizableMathMethods, _ct);
        bodyAnalyzer.Visit(node.Statement);

        if (bodyAnalyzer.IsVectorizable)
        {
            _foundVectorizableLoop = true;

            if (bodyAnalyzer.ElementType != SpecialType.None)
            {
                _elementType = bodyAnalyzer.ElementType;
            }
        }
        else
        {
            foreach (var reason in bodyAnalyzer.Reasons)
            {
                _reasons.Add(reason);
            }
        }

        _loopCounterNames.Remove(counterName);
        _insideVectorizableLoop = wasInside;
    }

    public override void VisitForEachStatement(ForEachStatementSyntax node)
    {
        if (_ct.IsCancellationRequested)
        {
            return;
        }

        // A foreach loop can be vectorized only when the source collection type
        // is a numeric array or Span<T> with a vectorizable element type.
        // We walk the body with a conservative analyzer that disallows index arithmetic.
        var collectionType = _model.GetTypeInfo(node.Expression, _ct).Type;
        var elementType = GetCollectionElementType(collectionType);

        if (elementType == SpecialType.None)
        {
            _reasons.Add($"foreach loop at line {node.GetLocation().GetLineSpan().StartLinePosition.Line + 1}: collection element type is not a supported numeric type.");
            base.VisitForEachStatement(node);
            return;
        }

        var bodyAnalyzer = new LoopBodyAnalyzer(_model, _loopCounterNames, VectorizableMathMethods, _ct, foreachElementName: node.Identifier.Text);
        bodyAnalyzer.Visit(node.Statement);

        if (bodyAnalyzer.IsVectorizable)
        {
            _foundVectorizableLoop = true;
            _elementType = elementType;
        }
        else
        {
            foreach (var reason in bodyAnalyzer.Reasons)
            {
                _reasons.Add(reason);
            }
        }
    }

    public override void VisitWhileStatement(WhileStatementSyntax node)
    {
        // While loops are generally not auto-vectorizable without further analysis
        // of the induction variable, so we report it and keep walking.
        _reasons.Add($"while loop at line {node.GetLocation().GetLineSpan().StartLinePosition.Line + 1} cannot be auto-vectorized (no canonical induction variable).");
        base.VisitWhileStatement(node);
    }

    // -------------------------------------------------------------------------
    // Result construction
    // -------------------------------------------------------------------------

    private VectorizationResult BuildResult()
    {
        if (!_foundVectorizableLoop)
        {
            if (_reasons.Count == 0)
            {
                _reasons.Add("No vectorizable loop pattern was found in the analyzed code.");
            }

            return new VectorizationResult(false, VectorTypes.None, _reasons);
        }

        var vectorType = SelectVectorType(_elementType);
        return new VectorizationResult(true, vectorType, _reasons);
    }

    // -------------------------------------------------------------------------
    // Helpers
    // -------------------------------------------------------------------------

    /// <summary>
    /// Attempts to extract the name of the induction variable from a simple
    /// <c>for (int/var i = 0; i &lt; n; i++)</c> statement.
    /// </summary>
    private static bool TryExtractCounterVariable(ForStatementSyntax node, out string counterName)
    {
        counterName = string.Empty;

        // Declaration must be a single variable initialised to 0
        if (node.Declaration is not { Variables: { Count: 1 } variables })
        {
            return false;
        }

        var declarator = variables[0];

        if (declarator.Initializer?.Value is not LiteralExpressionSyntax { Token.Value: 0 })
        {
            return false;
        }

        // Condition must be a binary < or <= comparison involving the counter variable
        if (node.Condition is not BinaryExpressionSyntax condition ||
            condition.Kind() is not (SyntaxKind.LessThanExpression or SyntaxKind.LessThanOrEqualExpression))
        {
            return false;
        }

        if (condition.Left is not IdentifierNameSyntax leftId ||
            leftId.Identifier.Text != declarator.Identifier.Text)
        {
            return false;
        }

        // Incrementor must be i++ or ++i
        if (node.Incrementors.Count != 1)
        {
            return false;
        }

        var incrementor = node.Incrementors[0];

        var isSimpleIncrement = incrementor switch
        {
            PostfixUnaryExpressionSyntax postfix => postfix.IsKind(SyntaxKind.PostIncrementExpression)
                                                    && postfix.Operand is IdentifierNameSyntax pi
                                                    && pi.Identifier.Text == declarator.Identifier.Text,
            PrefixUnaryExpressionSyntax prefix => prefix.IsKind(SyntaxKind.PreIncrementExpression)
                                                  && prefix.Operand is IdentifierNameSyntax pri
                                                  && pri.Identifier.Text == declarator.Identifier.Text,
            _ => false
        };

        if (!isSimpleIncrement)
        {
            return false;
        }

        counterName = declarator.Identifier.Text;
        return true;
    }

    /// <summary>
    /// Returns the <see cref="SpecialType"/> of the element stored in a numeric
    /// array or Span-like collection, or <see cref="SpecialType.None"/> when the
    /// type is not supported.
    /// </summary>
    private static SpecialType GetCollectionElementType(ITypeSymbol? collectionType)
    {
        if (collectionType is null)
        {
            return SpecialType.None;
        }

        // T[]
        if (collectionType is IArrayTypeSymbol arrayType)
        {
            return VectorizableElementTypes.Contains(arrayType.ElementType.SpecialType)
                ? arrayType.ElementType.SpecialType
                : SpecialType.None;
        }

        // Span<T> / ReadOnlySpan<T> / Memory<T> / ReadOnlyMemory<T>
        if (collectionType is INamedTypeSymbol namedType && namedType.IsGenericType)
        {
            var metadataName = $"{namedType.ContainingNamespace}.{namedType.MetadataName}";

            if (SpanTypeNames.Contains(metadataName) && namedType.TypeArguments.Length == 1)
            {
                var elementSpecial = namedType.TypeArguments[0].SpecialType;
                return VectorizableElementTypes.Contains(elementSpecial) ? elementSpecial : SpecialType.None;
            }
        }

        return SpecialType.None;
    }

    /// <summary>
    /// Selects the widest applicable <see cref="VectorTypes"/> for the given
    /// element type.  Uses <c>Vector256</c> as the default target (widely
    /// supported on modern x64 via AVX2), stepping down when lane count would
    /// exceed 64 bytes.
    /// </summary>
    private static VectorTypes SelectVectorType(SpecialType elementType)
    {
        var byteSize = elementType switch
        {
            SpecialType.System_Byte or SpecialType.System_SByte => 1,
            SpecialType.System_Int16 or SpecialType.System_UInt16 => 2,
            SpecialType.System_Int32 or SpecialType.System_UInt32 or SpecialType.System_Single => 4,
            SpecialType.System_Int64 or SpecialType.System_UInt64 or SpecialType.System_Double => 8,
            _ => 4
        };

        // Pick 256-bit vectors (32 bytes / byteSize lanes) as a sensible default;
        // for 8-byte elements that gives 4 lanes which is still useful.
        // 512-bit (AVX-512) is suggested only for 1- or 2-byte elements where
        // the lane count is very high.
        return byteSize switch
        {
            1 => VectorTypes.Vector512, // 64 byte / 1 = 64 lanes
            2 => VectorTypes.Vector256, // 32 byte / 2 = 16 lanes
            4 => VectorTypes.Vector256, // 32 byte / 4 = 8 lanes (AVX2 sweet-spot)
            8 => VectorTypes.Vector256, // 32 byte / 8 = 4 lanes
            _ => VectorTypes.Vector128
        };
    }

    // =========================================================================
    // Inner class: LoopBodyAnalyzer
    // Walks a single loop body and checks all vectorization preconditions.
    // =========================================================================

    /// <summary>
    /// Walks the body of a single loop and records whether every operation
    /// inside is compatible with auto-vectorization.
    /// </summary>
    private sealed class LoopBodyAnalyzer : CSharpSyntaxWalker
    {
        private readonly SemanticModel _model;
        private readonly ImmutableHashSet<string> _counterNames;
        private readonly ImmutableHashSet<string> _vectorizableMathMethods;
        private readonly CancellationToken _ct;

        // For foreach loops the element variable has a well-known name
        private readonly string? _foreachElementName;

        // The element type we detect from the first array/span access
        private SpecialType _detectedElementType = SpecialType.None;
        private bool _hasArrayOrSpanAccess;
        private bool _hadViolation;

        private readonly List<string> _reasons = [];

        public bool IsVectorizable => _hasArrayOrSpanAccess && !_hadViolation;
        public IReadOnlyList<string> Reasons => _reasons;
        public SpecialType ElementType => _detectedElementType;

        public LoopBodyAnalyzer(
            SemanticModel model,
            ImmutableHashSet<string> counterNames,
            ImmutableHashSet<string> vectorizableMathMethods,
            CancellationToken ct,
            string? foreachElementName = null)
            : base(SyntaxWalkerDepth.Node)
        {
            _model = model;
            _counterNames = counterNames;
            _vectorizableMathMethods = vectorizableMathMethods;
            _ct = ct;
            _foreachElementName = foreachElementName;
        }

        public override void Visit(SyntaxNode? node)
        {
            if (_ct.IsCancellationRequested || _hadViolation)
            {
                return;
            }

            base.Visit(node);
        }

        // ── Element access: arr[i] ────────────────────────────────────────────

        public override void VisitElementAccessExpression(ElementAccessExpressionSyntax node)
        {
            var type = _model.GetTypeInfo(node.Expression, _ct).Type;
            var elementType = GetElementType(type);

            if (elementType == SpecialType.None)
            {
                _reasons.Add($"Element access at line {node.GetLocation().GetLineSpan().StartLinePosition.Line + 1} is on a non-numeric or unsupported collection type.");
                _hadViolation = true;
                return;
            }

            // Validate that the index expression is a simple counter variable or
            // a counter ± a compile-time constant (stride-1 access is fine for
            // gathers, but true dependency checks require the same index for
            // both reads and writes — for now we accept counter ± literal).
            foreach (var arg in node.ArgumentList.Arguments)
            {
                if (!IsSimpleIndexExpression(arg.Expression))
                {
                    _reasons.Add($"Non-trivial index expression '{arg.Expression}' at line {node.GetLocation().GetLineSpan().StartLinePosition.Line + 1}. Only simple counter accesses (i, i+k, i-k) are supported.");
                    _hadViolation = true;
                    return;
                }
            }

            _hasArrayOrSpanAccess = true;

            if (_detectedElementType == SpecialType.None)
            {
                _detectedElementType = elementType;
            }
            else if (_detectedElementType != elementType)
            {
                // Mixed element types — still vectorizable if widening is possible,
                // but we keep it conservative and report.
                _reasons.Add($"Mixed element types detected ({_detectedElementType} vs {elementType}). Mixed-type vectorization is not supported.");
                _hadViolation = true;
                return;
            }

            base.VisitElementAccessExpression(node);
        }

        // ── foreach element variable: treat it like an array element ─────────

        public override void VisitIdentifierName(IdentifierNameSyntax node)
        {
            if (_foreachElementName is null || node.Identifier.Text != _foreachElementName)
            {
                base.VisitIdentifierName(node);
                return;
            }

            // The foreach element itself — the type is the element type of the
            // collection, which was already validated by the outer visitor.
            _hasArrayOrSpanAccess = true;
            base.VisitIdentifierName(node);
        }

        // ── Supported binary operators ────────────────────────────────────────

        public override void VisitBinaryExpression(BinaryExpressionSyntax node)
        {
            if (!IsSupportedBinaryOperator(node.Kind()))
            {
                _reasons.Add($"Unsupported binary operator '{node.OperatorToken}' at line {node.GetLocation().GetLineSpan().StartLinePosition.Line + 1}.");
                _hadViolation = true;
                return;
            }

            base.VisitBinaryExpression(node);
        }

        // ── Method calls inside the loop ─────────────────────────────────────

        public override void VisitInvocationExpression(InvocationExpressionSyntax node)
        {
            var symbol = _model.GetSymbolInfo(node, _ct).Symbol as IMethodSymbol;

            if (symbol is null)
            {
                _reasons.Add($"Unresolved method call at line {node.GetLocation().GetLineSpan().StartLinePosition.Line + 1}.");
                _hadViolation = true;
                return;
            }

            var fullName = $"{symbol.ContainingType?.ToDisplayString()}.{symbol.Name}";

            if (!_vectorizableMathMethods.Contains(fullName))
            {
                _reasons.Add($"Method call '{fullName}' at line {node.GetLocation().GetLineSpan().StartLinePosition.Line + 1} does not have a known SIMD equivalent.");
                _hadViolation = true;
                return;
            }

            base.VisitInvocationExpression(node);
        }

        // ── Control flow that breaks vectorization ────────────────────────────

        public override void VisitGotoStatement(GotoStatementSyntax node)
        {
            _reasons.Add($"goto statement at line {node.GetLocation().GetLineSpan().StartLinePosition.Line + 1} prevents vectorization.");
            _hadViolation = true;
        }

        public override void VisitYieldStatement(YieldStatementSyntax node)
        {
            _reasons.Add($"yield statement at line {node.GetLocation().GetLineSpan().StartLinePosition.Line + 1} prevents vectorization.");
            _hadViolation = true;
        }

        public override void VisitAwaitExpression(AwaitExpressionSyntax node)
        {
            _reasons.Add($"await expression at line {node.GetLocation().GetLineSpan().StartLinePosition.Line + 1} prevents vectorization.");
            _hadViolation = true;
        }

        public override void VisitUnsafeStatement(UnsafeStatementSyntax node)
        {
            _reasons.Add($"unsafe block at line {node.GetLocation().GetLineSpan().StartLinePosition.Line + 1} prevents vectorization.");
            _hadViolation = true;
        }

        public override void VisitLockStatement(LockStatementSyntax node)
        {
            _reasons.Add($"lock statement at line {node.GetLocation().GetLineSpan().StartLinePosition.Line + 1} prevents vectorization.");
            _hadViolation = true;
        }

        // ── Helpers ───────────────────────────────────────────────────────────

        /// <summary>
        /// Returns the element <see cref="SpecialType"/> for arrays and Span-like types,
        /// or <see cref="SpecialType.None"/> for unsupported types.
        /// </summary>
        private SpecialType GetElementType(ITypeSymbol? type)
        {
            if (type is IArrayTypeSymbol arrayType)
            {
                return VectorizableElementTypes.Contains(arrayType.ElementType.SpecialType)
                    ? arrayType.ElementType.SpecialType
                    : SpecialType.None;
            }

            if (type is INamedTypeSymbol { IsGenericType: true } namedType)
            {
                var metadataName = $"{namedType.ContainingNamespace}.{namedType.MetadataName}";

                if (SpanTypeNames.Contains(metadataName) && namedType.TypeArguments.Length == 1)
                {
                    var elementSpecial = namedType.TypeArguments[0].SpecialType;
                    return VectorizableElementTypes.Contains(elementSpecial) ? elementSpecial : SpecialType.None;
                }
            }

            return SpecialType.None;
        }

        /// <summary>
        /// Returns <see langword="true"/> when the index expression is:
        /// <list type="bullet">
        ///   <item>A counter variable (<c>i</c>)</item>
        ///   <item>A counter ± an integer literal (<c>i + 1</c>, <c>i - 2</c>)</item>
        ///   <item>An integer literal (constant access)</item>
        /// </list>
        /// </summary>
        private bool IsSimpleIndexExpression(ExpressionSyntax expression)
        {
            return expression switch
            {
                // i
                IdentifierNameSyntax id => _counterNames.Contains(id.Identifier.Text),

                // 42
                LiteralExpressionSyntax lit => lit.IsKind(SyntaxKind.NumericLiteralExpression),

                // i +/- k  or  k +/- i
                BinaryExpressionSyntax bin when
                    bin.IsKind(SyntaxKind.AddExpression) || bin.IsKind(SyntaxKind.SubtractExpression) =>
                    (IsSimpleIndexExpression(bin.Left) && bin.Right is LiteralExpressionSyntax)
                    || (bin.Left is LiteralExpressionSyntax && IsSimpleIndexExpression(bin.Right)),

                _ => false
            };
        }

        /// <summary>
        /// Returns <see langword="true"/> when the binary operator has a direct
        /// SIMD equivalent and does not introduce cross-lane dependencies.
        /// </summary>
        private static bool IsSupportedBinaryOperator(SyntaxKind kind)
        {
            return kind switch
            {
                SyntaxKind.AddExpression => true,
                SyntaxKind.SubtractExpression => true,
                SyntaxKind.MultiplyExpression => true,
                SyntaxKind.DivideExpression => true,
                SyntaxKind.ModuloExpression => true,
                SyntaxKind.BitwiseAndExpression => true,
                SyntaxKind.BitwiseOrExpression => true,
                SyntaxKind.ExclusiveOrExpression => true,
                SyntaxKind.LeftShiftExpression => true,
                SyntaxKind.RightShiftExpression => true,
                SyntaxKind.UnsignedRightShiftExpression => true,
                SyntaxKind.LessThanExpression => true,
                SyntaxKind.LessThanOrEqualExpression => true,
                SyntaxKind.GreaterThanExpression => true,
                SyntaxKind.GreaterThanOrEqualExpression => true,
                SyntaxKind.EqualsExpression => true,
                SyntaxKind.NotEqualsExpression => true,
                _ => false
            };
        }
    }
}

using System;
using System.Collections.Generic;
using System.Collections.Immutable;
using System.Linq;
using System.Threading;
using ConstExpr.SourceGenerator.Enums;
using ConstExpr.SourceGenerator.Models;
using Microsoft.CodeAnalysis;
using Microsoft.CodeAnalysis.CSharp;
using Microsoft.CodeAnalysis.CSharp.Syntax;

namespace ConstExpr.SourceGenerator.Visitors;

/// <summary>
/// Analyzes a syntax node (method body, block, or loop) to determine whether
/// it is eligible for auto-vectorization using SIMD intrinsics.
///
/// A node is considered vectorizable when it contains at least one loop that:
/// <list type="bullet">
///   <item>Iterates over a numeric array or <c>Span&lt;T&gt;</c> / <c>ReadOnlySpan&lt;T&gt;</c></item>
///   <item>Works with element types that map to a SIMD vector lane (byte, short, int, long, float, double, …)</item>
///   <item>Uses only element-wise arithmetic, bitwise, or comparison operations</item>
///   <item>Has no loop-carried data dependences (no <c>arr[i-1]</c>-style cross-iteration reads)</item>
///   <item>Contains no unsupported control flow inside the hot loop (no <c>goto</c>, no <c>yield</c>)</item>
///   <item>Does not call non-vectorizable methods in the loop body</item>
/// </list>
/// </summary>
public sealed class VectorizationEligibilityVisitor : CSharpSyntaxWalker
{
    // -------------------------------------------------------------------------
    // Supported element SpecialTypes — these are the types that map directly
    // to SIMD vector lanes on all major platforms.
    // -------------------------------------------------------------------------
    private static readonly ImmutableHashSet<SpecialType> VectorizableElementTypes =
        ImmutableHashSet.Create(
            SpecialType.System_Byte,
            SpecialType.System_SByte,
            SpecialType.System_Int16,
            SpecialType.System_UInt16,
            SpecialType.System_Int32,
            SpecialType.System_UInt32,
            SpecialType.System_Int64,
            SpecialType.System_UInt64,
            SpecialType.System_Single,
            SpecialType.System_Double
        );

    // Element-type metadata names for Span / ReadOnlySpan detection
    private static readonly ImmutableHashSet<string> SpanTypeNames =
        ImmutableHashSet.Create(
            StringComparer.Ordinal,
            "System.Span`1",
            "System.ReadOnlySpan`1",
            "System.Memory`1",
            "System.ReadOnlyMemory`1"
        );

    // Intrinsic / pure math methods that have direct SIMD equivalents and
    // are therefore safe to use inside a vectorizable loop body.
    private static readonly ImmutableHashSet<string> VectorizableMathMethods =
        ImmutableHashSet.Create(
            StringComparer.Ordinal,
            "System.Math.Abs",
            "System.Math.Min",
            "System.Math.Max",
            "System.Math.Sqrt",
            "System.Math.Floor",
            "System.Math.Ceiling",
            "System.Math.Round",
            "System.MathF.Abs",
            "System.MathF.Min",
            "System.MathF.Max",
            "System.MathF.Sqrt",
            "System.MathF.Floor",
            "System.MathF.Ceiling",
            "System.MathF.Round"
        );

    // -------------------------------------------------------------------------
    // State
    // -------------------------------------------------------------------------

    private readonly SemanticModel _model;
    private readonly CancellationToken _ct;
    private readonly List<string> _reasons = [];

    // The set of loop variable names that act as a simple counter (for int i = 0; i < n; i++)
    private HashSet<string> _loopCounterNames = [];

    // Tracks whether we are currently inside a supported loop
    private bool _insideVectorizableLoop;

    // Tracks whether any vectorizable loop was found
    private bool _foundVectorizableLoop;

    // The element type found in the innermost loop, used to select a vector width
    private SpecialType _elementType = SpecialType.None;

    // -------------------------------------------------------------------------
    // Public API
    // -------------------------------------------------------------------------

    private VectorizationEligibilityVisitor(SemanticModel model, CancellationToken ct)
        : base(SyntaxWalkerDepth.Node)
    {
        _model = model;
        _ct = ct;
    }

    /// <summary>
    /// Analyzes the given <paramref name="node"/> and returns a
    /// <see cref="VectorizationResult"/> describing whether vectorization is applicable.
    /// </summary>
    public static VectorizationResult Analyze(SyntaxNode node, SemanticModel model, CancellationToken ct = default)
    {
        var visitor = new VectorizationEligibilityVisitor(model, ct);
        visitor.Visit(node);
        return visitor.BuildResult();
    }

    // -------------------------------------------------------------------------
    // Loop detection
    // -------------------------------------------------------------------------

    public override void VisitForStatement(ForStatementSyntax node)
    {
        if (_ct.IsCancellationRequested)
        {
            return;
        }

        // Detect canonical counting pattern: for (var i = 0; i < n; i++) or (int i = 0; i < n; i++)
        if (!TryExtractCounterVariable(node, out var counterName))
        {
            // Not a simple counted loop — record reason and continue walking children
            // so we can still detect an inner loop that might be vectorizable.
            _reasons.Add($"Loop at line {node.GetLocation().GetLineSpan().StartLinePosition.Line + 1} does not follow a simple counter pattern (int i = 0; i < n; i++).");
            base.VisitForStatement(node);
            return;
        }

        _loopCounterNames.Add(counterName);
        var wasInside = _insideVectorizableLoop;
        _insideVectorizableLoop = true;

        // Analyze the body
        var bodyAnalyzer = new LoopBodyAnalyzer(_model, _loopCounterNames.ToImmutableHashSet(), VectorizableMathMethods, _ct);
        bodyAnalyzer.Visit(node.Statement);

        if (bodyAnalyzer.IsVectorizable)
        {
            _foundVectorizableLoop = true;

            if (bodyAnalyzer.ElementType != SpecialType.None)
            {
                _elementType = bodyAnalyzer.ElementType;
            }
        }
        else
        {
            foreach (var reason in bodyAnalyzer.Reasons)
            {
                _reasons.Add(reason);
            }
        }

        _loopCounterNames.Remove(counterName);
        _insideVectorizableLoop = wasInside;
    }

    public override void VisitForEachStatement(ForEachStatementSyntax node)
    {
        if (_ct.IsCancellationRequested)
        {
            return;
        }

        // A foreach loop can be vectorized only when the source collection type
        // is a numeric array or Span<T> with a vectorizable element type.
        // We walk the body with a conservative analyzer that disallows index arithmetic.
        var collectionType = _model.GetTypeInfo(node.Expression, _ct).Type;
        var elementType = GetCollectionElementType(collectionType);

        if (elementType == SpecialType.None)
        {
            _reasons.Add($"foreach loop at line {node.GetLocation().GetLineSpan().StartLinePosition.Line + 1}: collection element type is not a supported numeric type.");
            base.VisitForEachStatement(node);
            return;
        }

        var bodyAnalyzer = new LoopBodyAnalyzer(_model, _loopCounterNames, VectorizableMathMethods, _ct, foreachElementName: node.Identifier.Text);
        bodyAnalyzer.Visit(node.Statement);

        if (bodyAnalyzer.IsVectorizable)
        {
            _foundVectorizableLoop = true;
            _elementType = elementType;
        }
        else
        {
            foreach (var reason in bodyAnalyzer.Reasons)
            {
                _reasons.Add(reason);
            }
        }
    }

    public override void VisitWhileStatement(WhileStatementSyntax node)
    {
        // While loops are generally not auto-vectorizable without further analysis
        // of the induction variable, so we report it and keep walking.
        _reasons.Add($"while loop at line {node.GetLocation().GetLineSpan().StartLinePosition.Line + 1} cannot be auto-vectorized (no canonical induction variable).");
        base.VisitWhileStatement(node);
    }

    // -------------------------------------------------------------------------
    // Result construction
    // -------------------------------------------------------------------------

    private VectorizationResult BuildResult()
    {
        if (!_foundVectorizableLoop)
        {
            if (_reasons.Count == 0)
            {
                _reasons.Add("No vectorizable loop pattern was found in the analyzed code.");
            }

            return new VectorizationResult(false, VectorTypes.None, _reasons);
        }

        var vectorType = SelectVectorType(_elementType);
        return new VectorizationResult(true, vectorType, _reasons);
    }

    // -------------------------------------------------------------------------
    // Helpers
    // -------------------------------------------------------------------------

    /// <summary>
    /// Attempts to extract the name of the induction variable from a simple
    /// <c>for (int/var i = 0; i &lt; n; i++)</c> statement.
    /// </summary>
    private static bool TryExtractCounterVariable(ForStatementSyntax node, out string counterName)
    {
        counterName = string.Empty;

        // Declaration must be a single variable initialised to 0
        if (node.Declaration is not { Variables: { Count: 1 } variables })
        {
            return false;
        }

        var declarator = variables[0];

        if (declarator.Initializer?.Value is not LiteralExpressionSyntax { Token.Value: 0 })
        {
            return false;
        }

        // Condition must be a binary < or <= comparison involving the counter variable
        if (node.Condition is not BinaryExpressionSyntax condition ||
            condition.Kind() is not (SyntaxKind.LessThanExpression or SyntaxKind.LessThanOrEqualExpression))
        {
            return false;
        }

        if (condition.Left is not IdentifierNameSyntax leftId ||
            leftId.Identifier.Text != declarator.Identifier.Text)
        {
            return false;
        }

        // Incrementor must be i++ or ++i
        if (node.Incrementors.Count != 1)
        {
            return false;
        }

        var incrementor = node.Incrementors[0];

        var isSimpleIncrement = incrementor switch
        {
            PostfixUnaryExpressionSyntax postfix => postfix.IsKind(SyntaxKind.PostIncrementExpression)
                                                    && postfix.Operand is IdentifierNameSyntax pi
                                                    && pi.Identifier.Text == declarator.Identifier.Text,
            PrefixUnaryExpressionSyntax prefix => prefix.IsKind(SyntaxKind.PreIncrementExpression)
                                                  && prefix.Operand is IdentifierNameSyntax pri
                                                  && pri.Identifier.Text == declarator.Identifier.Text,
            _ => false
        };

        if (!isSimpleIncrement)
        {
            return false;
        }

        counterName = declarator.Identifier.Text;
        return true;
    }

    /// <summary>
    /// Returns the <see cref="SpecialType"/> of the element stored in a numeric
    /// array or Span-like collection, or <see cref="SpecialType.None"/> when the
    /// type is not supported.
    /// </summary>
    private static SpecialType GetCollectionElementType(ITypeSymbol? collectionType)
    {
        if (collectionType is null)
        {
            return SpecialType.None;
        }

        // T[]
        if (collectionType is IArrayTypeSymbol arrayType)
        {
            return VectorizableElementTypes.Contains(arrayType.ElementType.SpecialType)
                ? arrayType.ElementType.SpecialType
                : SpecialType.None;
        }

        // Span<T> / ReadOnlySpan<T> / Memory<T> / ReadOnlyMemory<T>
        if (collectionType is INamedTypeSymbol namedType && namedType.IsGenericType)
        {
            var metadataName = $"{namedType.ContainingNamespace}.{namedType.MetadataName}";

            if (SpanTypeNames.Contains(metadataName) && namedType.TypeArguments.Length == 1)
            {
                var elementSpecial = namedType.TypeArguments[0].SpecialType;
                return VectorizableElementTypes.Contains(elementSpecial) ? elementSpecial : SpecialType.None;
            }
        }

        return SpecialType.None;
    }

    /// <summary>
    /// Selects the widest applicable <see cref="VectorTypes"/> for the given
    /// element type.  Uses <c>Vector256</c> as the default target (widely
    /// supported on modern x64 via AVX2), stepping down when lane count would
    /// exceed 64 bytes.
    /// </summary>
    private static VectorTypes SelectVectorType(SpecialType elementType)
    {
        var byteSize = elementType switch
        {
            SpecialType.System_Byte or SpecialType.System_SByte => 1,
            SpecialType.System_Int16 or SpecialType.System_UInt16 => 2,
            SpecialType.System_Int32 or SpecialType.System_UInt32 or SpecialType.System_Single => 4,
            SpecialType.System_Int64 or SpecialType.System_UInt64 or SpecialType.System_Double => 8,
            _ => 4
        };

        // Pick 256-bit vectors (32 bytes / byteSize lanes) as a sensible default;
        // for 8-byte elements that gives 4 lanes which is still useful.
        // 512-bit (AVX-512) is suggested only for 1- or 2-byte elements where
        // the lane count is very high.
        return byteSize switch
        {
            1 => VectorTypes.Vector512, // 64 byte / 1 = 64 lanes
            2 => VectorTypes.Vector256, // 32 byte / 2 = 16 lanes
            4 => VectorTypes.Vector256, // 32 byte / 4 = 8 lanes (AVX2 sweet-spot)
            8 => VectorTypes.Vector256, // 32 byte / 8 = 4 lanes
            _ => VectorTypes.Vector128
        };
    }

    // =========================================================================
    // Inner class: LoopBodyAnalyzer
    // Walks a single loop body and checks all vectorization preconditions.
    // =========================================================================

    /// <summary>
    /// Walks the body of a single loop and records whether every operation
    /// inside is compatible with auto-vectorization.
    /// </summary>
    private sealed class LoopBodyAnalyzer : CSharpSyntaxWalker
    {
        private readonly SemanticModel _model;
        private readonly ImmutableHashSet<string> _counterNames;
        private readonly ImmutableHashSet<string> _vectorizableMathMethods;
        private readonly CancellationToken _ct;

        // For foreach loops the element variable has a well-known name
        private readonly string? _foreachElementName;

        // The element type we detect from the first array/span access
        private SpecialType _detectedElementType = SpecialType.None;
        private bool _hasArrayOrSpanAccess;
        private bool _hadViolation;

        private readonly List<string> _reasons = [];

        public bool IsVectorizable => _hasArrayOrSpanAccess && !_hadViolation;
        public IReadOnlyList<string> Reasons => _reasons;
        public SpecialType ElementType => _detectedElementType;

        public LoopBodyAnalyzer(
            SemanticModel model,
            ImmutableHashSet<string> counterNames,
            ImmutableHashSet<string> vectorizableMathMethods,
            CancellationToken ct,
            string? foreachElementName = null)
            : base(SyntaxWalkerDepth.Node)
        {
            _model = model;
            _counterNames = counterNames;
            _vectorizableMathMethods = vectorizableMathMethods;
            _ct = ct;
            _foreachElementName = foreachElementName;
        }

        public override void Visit(SyntaxNode? node)
        {
            if (_ct.IsCancellationRequested || _hadViolation)
            {
                return;
            }

            base.Visit(node);
        }

        // ── Element access: arr[i] ────────────────────────────────────────────

        public override void VisitElementAccessExpression(ElementAccessExpressionSyntax node)
        {
            var type = _model.GetTypeInfo(node.Expression, _ct).Type;
            var elementType = GetElementType(type);

            if (elementType == SpecialType.None)
            {
                _reasons.Add($"Element access at line {node.GetLocation().GetLineSpan().StartLinePosition.Line + 1} is on a non-numeric or unsupported collection type.");
                _hadViolation = true;
                return;
            }

            // Validate that the index expression is a simple counter variable or
            // a counter ± a compile-time constant (stride-1 access is fine for
            // gathers, but true dependency checks require the same index for
            // both reads and writes — for now we accept counter ± literal).
            foreach (var arg in node.ArgumentList.Arguments)
            {
                if (!IsSimpleIndexExpression(arg.Expression))
                {
                    _reasons.Add($"Non-trivial index expression '{arg.Expression}' at line {node.GetLocation().GetLineSpan().StartLinePosition.Line + 1}. Only simple counter accesses (i, i+k, i-k) are supported.");
                    _hadViolation = true;
                    return;
                }
            }

            _hasArrayOrSpanAccess = true;

            if (_detectedElementType == SpecialType.None)
            {
                _detectedElementType = elementType;
            }
            else if (_detectedElementType != elementType)
            {
                // Mixed element types — still vectorizable if widening is possible,
                // but we keep it conservative and report.
                _reasons.Add($"Mixed element types detected ({_detectedElementType} vs {elementType}). Mixed-type vectorization is not supported.");
                _hadViolation = true;
                return;
            }

            base.VisitElementAccessExpression(node);
        }

        // ── foreach element variable: treat it like an array element ─────────

        public override void VisitIdentifierName(IdentifierNameSyntax node)
        {
            if (_foreachElementName is null || node.Identifier.Text != _foreachElementName)
            {
                base.VisitIdentifierName(node);
                return;
            }

            // The foreach element itself — the type is the element type of the
            // collection, which was already validated by the outer visitor.
            _hasArrayOrSpanAccess = true;
            base.VisitIdentifierName(node);
        }

        // ── Supported binary operators ────────────────────────────────────────

        public override void VisitBinaryExpression(BinaryExpressionSyntax node)
        {
            if (!IsSupportedBinaryOperator(node.Kind()))
            {
                _reasons.Add($"Unsupported binary operator '{node.OperatorToken}' at line {node.GetLocation().GetLineSpan().StartLinePosition.Line + 1}.");
                _hadViolation = true;
                return;
            }

            base.VisitBinaryExpression(node);
        }

        // ── Method calls inside the loop ─────────────────────────────────────

        public override void VisitInvocationExpression(InvocationExpressionSyntax node)
        {
            var symbol = _model.GetSymbolInfo(node, _ct).Symbol as IMethodSymbol;

            if (symbol is null)
            {
                _reasons.Add($"Unresolved method call at line {node.GetLocation().GetLineSpan().StartLinePosition.Line + 1}.");
                _hadViolation = true;
                return;
            }

            var fullName = $"{symbol.ContainingType?.ToDisplayString()}.{symbol.Name}";

            if (!_vectorizableMathMethods.Contains(fullName))
            {
                _reasons.Add($"Method call '{fullName}' at line {node.GetLocation().GetLineSpan().StartLinePosition.Line + 1} does not have a known SIMD equivalent.");
                _hadViolation = true;
                return;
            }

            base.VisitInvocationExpression(node);
        }

        // ── Control flow that breaks vectorization ────────────────────────────

        public override void VisitGotoStatement(GotoStatementSyntax node)
        {
            _reasons.Add($"goto statement at line {node.GetLocation().GetLineSpan().StartLinePosition.Line + 1} prevents vectorization.");
            _hadViolation = true;
        }

        public override void VisitYieldStatement(YieldStatementSyntax node)
        {
            _reasons.Add($"yield statement at line {node.GetLocation().GetLineSpan().StartLinePosition.Line + 1} prevents vectorization.");
            _hadViolation = true;
        }

        public override void VisitAwaitExpression(AwaitExpressionSyntax node)
        {
            _reasons.Add($"await expression at line {node.GetLocation().GetLineSpan().StartLinePosition.Line + 1} prevents vectorization.");
            _hadViolation = true;
        }

        public override void VisitUnsafeStatement(UnsafeStatementSyntax node)
        {
            _reasons.Add($"unsafe block at line {node.GetLocation().GetLineSpan().StartLinePosition.Line + 1} prevents vectorization.");
            _hadViolation = true;
        }

        public override void VisitLockStatement(LockStatementSyntax node)
        {
            _reasons.Add($"lock statement at line {node.GetLocation().GetLineSpan().StartLinePosition.Line + 1} prevents vectorization.");
            _hadViolation = true;
        }

        // ── Helpers ───────────────────────────────────────────────────────────

        /// <summary>
        /// Returns the element <see cref="SpecialType"/> for arrays and Span-like types,
        /// or <see cref="SpecialType.None"/> for unsupported types.
        /// </summary>
        private SpecialType GetElementType(ITypeSymbol? type)
        {
            if (type is IArrayTypeSymbol arrayType)
            {
                return VectorizableElementTypes.Contains(arrayType.ElementType.SpecialType)
                    ? arrayType.ElementType.SpecialType
                    : SpecialType.None;
            }

            if (type is INamedTypeSymbol { IsGenericType: true } namedType)
            {
                var metadataName = $"{namedType.ContainingNamespace}.{namedType.MetadataName}";

                if (SpanTypeNames.Contains(metadataName) && namedType.TypeArguments.Length == 1)
                {
                    var elementSpecial = namedType.TypeArguments[0].SpecialType;
                    return VectorizableElementTypes.Contains(elementSpecial) ? elementSpecial : SpecialType.None;
                }
            }

            return SpecialType.None;
        }

        /// <summary>
        /// Returns <see langword="true"/> when the index expression is:
        /// <list type="bullet">
        ///   <item>A counter variable (<c>i</c>)</item>
        ///   <item>A counter ± an integer literal (<c>i + 1</c>, <c>i - 2</c>)</item>
        ///   <item>An integer literal (constant access)</item>
        /// </list>
        /// </summary>
        private bool IsSimpleIndexExpression(ExpressionSyntax expression)
        {
            return expression switch
            {
                // i
                IdentifierNameSyntax id => _counterNames.Contains(id.Identifier.Text),

                // 42
                LiteralExpressionSyntax lit => lit.IsKind(SyntaxKind.NumericLiteralExpression),

                // i +/- k  or  k +/- i
                BinaryExpressionSyntax bin when
                    bin.IsKind(SyntaxKind.AddExpression) || bin.IsKind(SyntaxKind.SubtractExpression) =>
                    (IsSimpleIndexExpression(bin.Left) && bin.Right is LiteralExpressionSyntax)
                    || (bin.Left is LiteralExpressionSyntax && IsSimpleIndexExpression(bin.Right)),

                _ => false
            };
        }

        /// <summary>
        /// Returns <see langword="true"/> when the binary operator has a direct
        /// SIMD equivalent and does not introduce cross-lane dependencies.
        /// </summary>
        private static bool IsSupportedBinaryOperator(SyntaxKind kind)
        {
            return kind switch
            {
                SyntaxKind.AddExpression => true,
                SyntaxKind.SubtractExpression => true,
                SyntaxKind.MultiplyExpression => true,
                SyntaxKind.DivideExpression => true,
                SyntaxKind.ModuloExpression => true,
                SyntaxKind.BitwiseAndExpression => true,
                SyntaxKind.BitwiseOrExpression => true,
                SyntaxKind.ExclusiveOrExpression => true,
                SyntaxKind.LeftShiftExpression => true,
                SyntaxKind.RightShiftExpression => true,
                SyntaxKind.UnsignedRightShiftExpression => true,
                SyntaxKind.LessThanExpression => true,
                SyntaxKind.LessThanOrEqualExpression => true,
                SyntaxKind.GreaterThanExpression => true,
                SyntaxKind.GreaterThanOrEqualExpression => true,
                SyntaxKind.EqualsExpression => true,
                SyntaxKind.NotEqualsExpression => true,
                _ => false
            };
        }
    }
}
